INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('romeo_and_juliet_act1_scene1',1,0,'SAMPSON','Gregory, o’ my word, we’ll not carry coals.'),
('romeo_and_juliet_act1_scene1',2,1,'GREGORY','No, for then we should be colliers.'),
('romeo_and_juliet_act1_scene1',3,2,'SAMPSON','I mean, an we be in choler, we’ll draw.'),
('romeo_and_juliet_act1_scene1',4,3,'GREGORY','Ay, while you live, draw your neck out o’ the collar.'),
('romeo_and_juliet_act1_scene1',5,4,'SAMPSON','I strike quickly, being moved.'),
('romeo_and_juliet_act1_scene1',6,5,'GREGORY','But thou art not quickly moved to strike.'),
('romeo_and_juliet_act1_scene1',7,6,'SAMPSON','A dog of the house of Montague moves me.'),
('romeo_and_juliet_act1_scene1',8,7,'GREGORY','To move is to stir; and to be valiant is to stand:'),
('romeo_and_juliet_act1_scene1',9,8,'GREGORY','therefore, if thou art moved, thou runn’st away.'),
('romeo_and_juliet_act1_scene1',10,9,'SAMPSON','A dog of that house shall move me to stand: I will'),
('romeo_and_juliet_act1_scene1',11,10,'SAMPSON','take the wall of any man or maid of Montague’s.'),
('romeo_and_juliet_act1_scene1',12,11,'GREGORY','That shows thee a weak slave; for the weakest goes to the wall.'),
('romeo_and_juliet_act1_scene1',13,12,'SAMPSON','True; and therefore women, being the weaker vessels, are ever thrust to'),
('romeo_and_juliet_act1_scene1',14,13,'SAMPSON','the wall: therefore I will push Montague’s men from the wall, and'),
('romeo_and_juliet_act1_scene1',15,14,'SAMPSON','thrust his maids to the wall.'),
('romeo_and_juliet_act1_scene1',16,15,'GREGORY','The quarrel is between our masters and us their men.'),
('romeo_and_juliet_act1_scene1',17,16,'SAMPSON','’Tis all one, I will show myself a tyrant: when I have'),
('romeo_and_juliet_act1_scene1',18,17,'SAMPSON','fought with the men, I will be cruel with the maids, and'),
('romeo_and_juliet_act1_scene1',19,18,'SAMPSON','cut off their heads.'),
('romeo_and_juliet_act1_scene1',19,19,'GREGORY','The heads of the maids?'),
('romeo_and_juliet_act1_scene1',20,20,'SAMPSON','Ay, the heads of the maids, or their maidenheads; take it in'),
('romeo_and_juliet_act1_scene1',21,21,'SAMPSON','what sense thou wilt.'),
('romeo_and_juliet_act1_scene1',22,22,'GREGORY','They must take it in sense that feel it.'),
('romeo_and_juliet_act1_scene1',23,23,'SAMPSON','Me they shall feel while I am able to stand: and ’tis'),
('romeo_and_juliet_act1_scene1',24,24,'SAMPSON','known I am a pretty piece of flesh.'),
('romeo_and_juliet_act1_scene1',25,25,'GREGORY','’Tis well thou art not fish; if thou hadst, thou hadst been'),
('romeo_and_juliet_act1_scene1',26,26,'GREGORY','poor John. Draw thy tool; here comes two of the house of'),
('romeo_and_juliet_act1_scene1',27,27,'GREGORY','the Montagues.'),
('romeo_and_juliet_act1_scene1',28,28,'SAMPSON','My naked weapon is out: quarrel, I will back thee.'),
('romeo_and_juliet_act1_scene1',29,29,'GREGORY','How! turn thy back and run?'),
('romeo_and_juliet_act1_scene1',29,30,'SAMPSON','Fear me not.'),
('romeo_and_juliet_act1_scene1',30,31,'GREGORY','No, marry; I fear thee!'),
('romeo_and_juliet_act1_scene1',31,32,'SAMPSON','Let us take the law of our sides; let them begin.'),
('romeo_and_juliet_act1_scene1',32,33,'GREGORY','I will frown as I pass by, and let them take it as they list.'),
('romeo_and_juliet_act1_scene1',33,34,'SAMPSON','Nay, as they dare. I will bite my thumb at them; which'),
('romeo_and_juliet_act1_scene1',34,35,'SAMPSON','is a disgrace to them, if they bear it.'),
('romeo_and_juliet_act1_scene1',35,36,'ABRAHAM','Do you bite your thumb at us, sir?'),
('romeo_and_juliet_act1_scene1',36,37,'SAMPSON','I do bite my thumb, sir.'),
('romeo_and_juliet_act1_scene1',37,38,'ABRAHAM','Do you bite your thumb at us, sir?'),
('romeo_and_juliet_act1_scene1',38,39,'SAMPSON','Is the law of our side, if I say ay?'),
('romeo_and_juliet_act1_scene1',39,40,'GREGORY','No.'),
('romeo_and_juliet_act1_scene1',40,41,'SAMPSON','No, sir, I do not bite my thumb at you, sir, but'),
('romeo_and_juliet_act1_scene1',41,42,'SAMPSON','I bite my thumb, sir.'),
('romeo_and_juliet_act1_scene1',41,43,'GREGORY','Do you quarrel, sir?'),
('romeo_and_juliet_act1_scene1',42,44,'ABRAHAM','Quarrel, sir! no, sir.'),
('romeo_and_juliet_act1_scene1',43,45,'SAMPSON','If you do, sir, I am for you: I serve as good'),
('romeo_and_juliet_act1_scene1',44,46,'SAMPSON','a man as you.'),
('romeo_and_juliet_act1_scene1',44,47,'ABRAHAM','No better.'),
('romeo_and_juliet_act1_scene1',45,48,'SAMPSON','Well, sir.'),
('romeo_and_juliet_act1_scene1',46,49,'GREGORY','Say “better:” here comes one of my master’s kinsmen.'),
('romeo_and_juliet_act1_scene1',47,50,'SAMPSON','Yes, better, sir.'),
('romeo_and_juliet_act1_scene1',47,51,'ABRAHAM','You lie.'),
('romeo_and_juliet_act1_scene1',48,52,'SAMPSON','Draw, if you be men. Gregory, remember thy swashing blow. They fight.'),
('romeo_and_juliet_act1_scene1',49,53,'BENVOLIO','Part, fools!'),
('romeo_and_juliet_act1_scene1',50,54,'BENVOLIO','Put up your swords; you know not what you do. Beats down their swords.'),
('romeo_and_juliet_act1_scene1',51,55,'TYBALT','What, art thou drawn among these heartless hinds?'),
('romeo_and_juliet_act1_scene1',52,56,'TYBALT','Turn thee, Benvolio, look upon thy death.'),
('romeo_and_juliet_act1_scene1',53,57,'BENVOLIO','I do but keep the peace: put up thy sword,'),
('romeo_and_juliet_act1_scene1',54,58,'BENVOLIO','Or manage it to part these men with me.'),
('romeo_and_juliet_act1_scene1',55,59,'TYBALT','What, drawn, and talk of peace! I hate the word,'),
('romeo_and_juliet_act1_scene1',56,60,'TYBALT','As I hate hell, all Montagues, and thee:'),
('romeo_and_juliet_act1_scene1',57,61,'TYBALT','Have at thee, coward! They fight.'),
('romeo_and_juliet_act1_scene1',58,62,'FIRST CITIZEN','Clubs, bills, and partisans! strike! beat them down!'),
('romeo_and_juliet_act1_scene1',59,63,'FIRST CITIZEN','Down with the Capulets! down with the Montagues!'),
('romeo_and_juliet_act1_scene1',60,64,'CAPULET','What noise is this? Give me my long sword, ho!'),
('romeo_and_juliet_act1_scene1',61,65,'LADY CAPULET','A crutch, a crutch! why call you for a sword?'),
('romeo_and_juliet_act1_scene1',62,66,'CAPULET','My sword, I say! Old Montague is come,'),
('romeo_and_juliet_act1_scene1',63,67,'CAPULET','And flourishes his blade in spite of me.'),
('romeo_and_juliet_act1_scene1',64,68,'MONTAGUE','Thou villain Capulet—Hold me not, let me go.'),
('romeo_and_juliet_act1_scene1',65,69,'LADY MONTAGUE','Thou shalt not stir a foot to seek a foe.'),
('romeo_and_juliet_act1_scene1',66,70,'PRINCE','Rebellious subjects, enemies to peace,'),
('romeo_and_juliet_act1_scene1',67,71,'PRINCE','Profaners of this neighbour-stained steel—'),
('romeo_and_juliet_act1_scene1',68,72,'PRINCE','Will they not hear? What, ho! you men, you beasts,'),
('romeo_and_juliet_act1_scene1',69,73,'PRINCE','That quench the fire of your pernicious rage'),
('romeo_and_juliet_act1_scene1',70,74,'PRINCE','With purple fountains issuing from your veins,'),
('romeo_and_juliet_act1_scene1',71,75,'PRINCE','On pain of torture, from those bloody hands'),
('romeo_and_juliet_act1_scene1',72,76,'PRINCE','Throw your mistemper’d weapons to the ground,'),
('romeo_and_juliet_act1_scene1',73,77,'PRINCE','And hear the sentence of your moved prince.'),
('romeo_and_juliet_act1_scene1',74,78,'PRINCE','Three civil brawls, bred of an airy word,'),
('romeo_and_juliet_act1_scene1',75,79,'PRINCE','By thee, old Capulet, and Montague,'),
('romeo_and_juliet_act1_scene1',76,80,'PRINCE','Have thrice disturb’d the quiet of our streets,'),
('romeo_and_juliet_act1_scene1',77,81,'PRINCE','And made Verona’s ancient citizens'),
('romeo_and_juliet_act1_scene1',78,82,'PRINCE','Cast by their grave beseeming ornaments,'),
('romeo_and_juliet_act1_scene1',79,83,'PRINCE','To wield old partisans, in hands as old,'),
('romeo_and_juliet_act1_scene1',80,84,'PRINCE','Canker’d with peace, to part your canker’d hate:'),
('romeo_and_juliet_act1_scene1',81,85,'PRINCE','If ever you disturb our streets again,'),
('romeo_and_juliet_act1_scene1',82,86,'PRINCE','Your lives shall pay the forfeit of the peace.'),
('romeo_and_juliet_act1_scene1',83,87,'PRINCE','For this time, all the rest depart away:'),
('romeo_and_juliet_act1_scene1',84,88,'PRINCE','You, Capulet, shall go along with me:'),
('romeo_and_juliet_act1_scene1',85,89,'PRINCE','And, Montague, come you this afternoon,'),
('romeo_and_juliet_act1_scene1',86,90,'PRINCE','To know our further pleasure in this case,'),
('romeo_and_juliet_act1_scene1',87,91,'PRINCE','To old Free-town, our common judgment-place.'),
('romeo_and_juliet_act1_scene1',88,92,'PRINCE','Once more, on pain of death, all men depart.'),
('romeo_and_juliet_act1_scene1',89,93,'MONTAGUE','Who set this ancient quarrel new abroach?'),
('romeo_and_juliet_act1_scene1',90,94,'MONTAGUE','Speak, nephew, were you by when it began?'),
('romeo_and_juliet_act1_scene1',91,95,'BENVOLIO','Here were the servants of your adversary,'),
('romeo_and_juliet_act1_scene1',92,96,'BENVOLIO','And yours, close fighting ere I did approach:'),
('romeo_and_juliet_act1_scene1',93,97,'BENVOLIO','I drew to part them: in the instant came'),
('romeo_and_juliet_act1_scene1',94,98,'BENVOLIO','The fiery Tybalt, with his sword prepared,'),
('romeo_and_juliet_act1_scene1',95,99,'BENVOLIO','Which, as he breathed defiance to my ears,'),
('romeo_and_juliet_act1_scene1',96,100,'BENVOLIO','He swung about his head and cut the winds,'),
('romeo_and_juliet_act1_scene1',97,101,'BENVOLIO','Who nothing hurt withal hiss’d him in scorn:'),
('romeo_and_juliet_act1_scene1',98,102,'BENVOLIO','While we were interchanging thrusts and blows,'),
('romeo_and_juliet_act1_scene1',99,103,'BENVOLIO','Came more and more and fought on part and part.'),
('romeo_and_juliet_act1_scene1',100,104,'BENVOLIO','Till the prince came, who parted either part.'),
('romeo_and_juliet_act1_scene1',101,105,'LADY MONTAGUE','O, where is Romeo? saw you him to-day?'),
('romeo_and_juliet_act1_scene1',102,106,'LADY MONTAGUE','Right glad I am he was not at this fray.'),
('romeo_and_juliet_act1_scene1',103,107,'BENVOLIO','Madam, an hour before the worshipp’d sun'),
('romeo_and_juliet_act1_scene1',104,108,'BENVOLIO','Peer’d forth the golden window of the east,'),
('romeo_and_juliet_act1_scene1',105,109,'BENVOLIO','A troubled mind drave me to walk abroad;'),
('romeo_and_juliet_act1_scene1',106,110,'BENVOLIO','Where, underneath the grove of sycamore'),
('romeo_and_juliet_act1_scene1',107,111,'BENVOLIO','That westward rooteth from the city’s side,'),
('romeo_and_juliet_act1_scene1',108,112,'BENVOLIO','So early walking did I see your son:'),
('romeo_and_juliet_act1_scene1',109,113,'BENVOLIO','Towards him I made, but he was ware of me'),
('romeo_and_juliet_act1_scene1',110,114,'BENVOLIO','And stole into the covert of the wood:'),
('romeo_and_juliet_act1_scene1',111,115,'BENVOLIO','I, measuring his affections by my own,'),
('romeo_and_juliet_act1_scene1',112,116,'BENVOLIO','That most are busied when they’re most alone,'),
('romeo_and_juliet_act1_scene1',113,117,'BENVOLIO','Pursued my humour not pursuing his,'),
('romeo_and_juliet_act1_scene1',114,118,'BENVOLIO','And gladly shunn’d who gladly fled from me.'),
('romeo_and_juliet_act1_scene1',115,119,'MONTAGUE','Many a morning hath he there been seen,'),
('romeo_and_juliet_act1_scene1',116,120,'MONTAGUE','With tears augmenting the fresh morning’s dew,'),
('romeo_and_juliet_act1_scene1',117,121,'MONTAGUE','Adding to clouds more clouds with his deep sighs;'),
('romeo_and_juliet_act1_scene1',118,122,'MONTAGUE','But all so soon as the all-cheering sun'),
('romeo_and_juliet_act1_scene1',119,123,'MONTAGUE','Should in the furthest east begin to draw'),
('romeo_and_juliet_act1_scene1',120,124,'MONTAGUE','The shady curtains from Aurora’s bed,'),
('romeo_and_juliet_act1_scene1',121,125,'MONTAGUE','Away from light steals home my heavy son,'),
('romeo_and_juliet_act1_scene1',122,126,'MONTAGUE','And private in his chamber pens himself,'),
('romeo_and_juliet_act1_scene1',123,127,'MONTAGUE','Shuts up his windows, locks fair daylight out'),
('romeo_and_juliet_act1_scene1',124,128,'MONTAGUE','And makes himself an artificial night:'),
('romeo_and_juliet_act1_scene1',125,129,'MONTAGUE','Black and portentous must this humour prove,'),
('romeo_and_juliet_act1_scene1',126,130,'MONTAGUE','Unless good counsel may the cause remove.'),
('romeo_and_juliet_act1_scene1',127,131,'BENVOLIO','My noble uncle, do you know the cause?'),
('romeo_and_juliet_act1_scene1',128,132,'MONTAGUE','I neither know it nor can learn of him.'),
('romeo_and_juliet_act1_scene1',129,133,'BENVOLIO','Have you importuned him by any means?'),
('romeo_and_juliet_act1_scene1',130,134,'MONTAGUE','Both by myself and many other friends:'),
('romeo_and_juliet_act1_scene1',131,135,'MONTAGUE','But he, his own affections’ counsellor,'),
('romeo_and_juliet_act1_scene1',132,136,'MONTAGUE','Is to himself—I will not say how true—'),
('romeo_and_juliet_act1_scene1',133,137,'MONTAGUE','But to himself so secret and so close,'),
('romeo_and_juliet_act1_scene1',134,138,'MONTAGUE','So far from sounding and discovery,'),
('romeo_and_juliet_act1_scene1',135,139,'MONTAGUE','As is the bird bit with an envious worm,'),
('romeo_and_juliet_act1_scene1',136,140,'MONTAGUE','Ere he can spread his sweet leaves to the air,'),
('romeo_and_juliet_act1_scene1',137,141,'MONTAGUE','Or dedicate his beauty to the sun.'),
('romeo_and_juliet_act1_scene1',138,142,'MONTAGUE','Could we but learn from whence his sorrows grow,'),
('romeo_and_juliet_act1_scene1',139,143,'MONTAGUE','We would as willingly give cure as know.'),
('romeo_and_juliet_act1_scene1',140,144,'BENVOLIO','See, where he comes: so please you, step aside;'),
('romeo_and_juliet_act1_scene1',141,145,'BENVOLIO','I’ll know his grievance, or be much denied.'),
('romeo_and_juliet_act1_scene1',142,146,'MONTAGUE','I would thou wert so happy by thy stay,'),
('romeo_and_juliet_act1_scene1',143,147,'MONTAGUE','To hear true shrift. Come, madam, let’s away.'),
('romeo_and_juliet_act1_scene1',144,148,'BENVOLIO','Good morrow, cousin.'),
('romeo_and_juliet_act1_scene1',144,149,'ROMEO','Is the day so young?'),
('romeo_and_juliet_act1_scene1',145,150,'BENVOLIO','But new struck nine.'),
('romeo_and_juliet_act1_scene1',145,151,'ROMEO','Ay me! sad hours seem long.'),
('romeo_and_juliet_act1_scene1',146,152,'ROMEO','Was that my father that went hence so fast?'),
('romeo_and_juliet_act1_scene1',147,153,'BENVOLIO','It was. What sadness lengthens Romeo’s hours?'),
('romeo_and_juliet_act1_scene1',148,154,'ROMEO','Not having that, which, having, makes them short.'),
('romeo_and_juliet_act1_scene1',149,155,'BENVOLIO','In love?'),
('romeo_and_juliet_act1_scene1',149,156,'ROMEO','Out—'),
('romeo_and_juliet_act1_scene1',150,157,'BENVOLIO','Of love?'),
('romeo_and_juliet_act1_scene1',151,158,'ROMEO','Out of her favour, where I am in love.'),
('romeo_and_juliet_act1_scene1',152,159,'BENVOLIO','Alas, that love, so gentle in his view,'),
('romeo_and_juliet_act1_scene1',153,160,'BENVOLIO','Should be so tyrannous and rough in proof!'),
('romeo_and_juliet_act1_scene1',154,161,'ROMEO','Alas, that love, whose view is muffled still,'),
('romeo_and_juliet_act1_scene1',155,162,'ROMEO','Should, without eyes, see pathways to his will!'),
('romeo_and_juliet_act1_scene1',156,163,'ROMEO','Where shall we dine? O me! What fray was here?'),
('romeo_and_juliet_act1_scene1',157,164,'ROMEO','Yet tell me not, for I have heard it all.'),
('romeo_and_juliet_act1_scene1',158,165,'ROMEO','Here’s much to do with hate, but more with love.'),
('romeo_and_juliet_act1_scene1',159,166,'ROMEO','Why, then, O brawling love! O loving hate!'),
('romeo_and_juliet_act1_scene1',160,167,'ROMEO','O anything, of nothing first create!'),
('romeo_and_juliet_act1_scene1',161,168,'ROMEO','O heavy lightness! serious vanity!'),
('romeo_and_juliet_act1_scene1',162,169,'ROMEO','Mis-shapen chaos of well-seeming forms!'),
('romeo_and_juliet_act1_scene1',163,170,'ROMEO','Feather of lead, bright smoke, cold fire, sick health!'),
('romeo_and_juliet_act1_scene1',164,171,'ROMEO','Still-waking sleep, that is not what it is!'),
('romeo_and_juliet_act1_scene1',165,172,'ROMEO','This love feel I, that feel no love in this.'),
('romeo_and_juliet_act1_scene1',166,173,'ROMEO','Dost thou not laugh?'),
('romeo_and_juliet_act1_scene1',166,174,'BENVOLIO','No, coz, I rather weep.'),
('romeo_and_juliet_act1_scene1',167,175,'ROMEO','Good heart, at what?'),
('romeo_and_juliet_act1_scene1',167,176,'BENVOLIO','At thy good heart’s oppression.'),
('romeo_and_juliet_act1_scene1',168,177,'ROMEO','Why, such is love’s transgression.'),
('romeo_and_juliet_act1_scene1',169,178,'ROMEO','Griefs of mine own lie heavy in my breast,'),
('romeo_and_juliet_act1_scene1',170,179,'ROMEO','Which thou wilt propagate, to have it prest'),
('romeo_and_juliet_act1_scene1',171,180,'ROMEO','With more of thine: this love that thou hast shown'),
('romeo_and_juliet_act1_scene1',172,181,'ROMEO','Doth add more grief to too much of mine own.'),
('romeo_and_juliet_act1_scene1',173,182,'ROMEO','Love is a smoke raised with the fume of sighs;'),
('romeo_and_juliet_act1_scene1',174,183,'ROMEO','Being purged, a fire sparkling in lovers’ eyes;'),
('romeo_and_juliet_act1_scene1',175,184,'ROMEO','Being vex’d, a sea nourish’d with lovers’ tears:'),
('romeo_and_juliet_act1_scene1',176,185,'ROMEO','What is it else? a madness most discreet,'),
('romeo_and_juliet_act1_scene1',177,186,'ROMEO','A choking gall and a preserving sweet.'),
('romeo_and_juliet_act1_scene1',178,187,'ROMEO','Farewell, my coz.'),
('romeo_and_juliet_act1_scene1',178,188,'BENVOLIO','Soft! I will go along;'),
('romeo_and_juliet_act1_scene1',179,189,'BENVOLIO','An if you leave me so, you do me wrong.'),
('romeo_and_juliet_act1_scene1',180,190,'ROMEO','Tut, I have lost myself; I am not here;'),
('romeo_and_juliet_act1_scene1',181,191,'ROMEO','This is not Romeo, he’s some other where.'),
('romeo_and_juliet_act1_scene1',182,192,'BENVOLIO','Tell me in sadness, who is that you love.'),
('romeo_and_juliet_act1_scene1',183,193,'ROMEO','What, shall I groan and tell thee?'),
('romeo_and_juliet_act1_scene1',184,194,'BENVOLIO','Groan! why, no;'),
('romeo_and_juliet_act1_scene1',185,195,'BENVOLIO','But sadly tell me who.'),
('romeo_and_juliet_act1_scene1',186,196,'ROMEO','Bid a sick man in sadness make his will:'),
('romeo_and_juliet_act1_scene1',187,197,'ROMEO','Ah, word ill urged to one that is so ill!'),
('romeo_and_juliet_act1_scene1',188,198,'ROMEO','In sadness, cousin, I do love a woman.'),
('romeo_and_juliet_act1_scene1',189,199,'BENVOLIO','I aim’d so near, when I supposed you loved.'),
('romeo_and_juliet_act1_scene1',190,200,'ROMEO','A right good mark-man! And she’s fair I love.'),
('romeo_and_juliet_act1_scene1',191,201,'BENVOLIO','A right fair mark, fair coz, is soonest hit.'),
('romeo_and_juliet_act1_scene1',192,202,'ROMEO','Well, in that hit you miss: she’ll not be hit'),
('romeo_and_juliet_act1_scene1',193,203,'ROMEO','With Cupid’s arrow; she hath Dian’s wit;'),
('romeo_and_juliet_act1_scene1',194,204,'ROMEO','And, in strong proof of chastity well arm’d,'),
('romeo_and_juliet_act1_scene1',195,205,'ROMEO','From love’s weak childish bow she lives unharm’d.'),
('romeo_and_juliet_act1_scene1',196,206,'ROMEO','She will not stay the siege of loving terms,'),
('romeo_and_juliet_act1_scene1',197,207,'ROMEO','Nor bide the encounter of assailing eyes,'),
('romeo_and_juliet_act1_scene1',198,208,'ROMEO','Nor ope her lap to saint-seducing gold:'),
('romeo_and_juliet_act1_scene1',199,209,'ROMEO','O, she is rich in beauty, only poor,'),
('romeo_and_juliet_act1_scene1',200,210,'ROMEO','That when she dies with beauty dies her store.'),
('romeo_and_juliet_act1_scene1',201,211,'BENVOLIO','Then she hath sworn that she will still live chaste?'),
('romeo_and_juliet_act1_scene1',202,212,'ROMEO','She hath, and in that sparing makes huge waste,'),
('romeo_and_juliet_act1_scene1',203,213,'ROMEO','For beauty starved with her severity'),
('romeo_and_juliet_act1_scene1',204,214,'ROMEO','Cuts beauty off from all posterity.'),
('romeo_and_juliet_act1_scene1',205,215,'ROMEO','She is too fair, too wise, wisely too fair,'),
('romeo_and_juliet_act1_scene1',206,216,'ROMEO','To merit bliss by making me despair:'),
('romeo_and_juliet_act1_scene1',207,217,'ROMEO','She hath forsworn to love, and in that vow'),
('romeo_and_juliet_act1_scene1',208,218,'ROMEO','Do I live dead that live to tell it now.'),
('romeo_and_juliet_act1_scene1',209,219,'BENVOLIO','Be ruled by me, forget to think of her.'),
('romeo_and_juliet_act1_scene1',210,220,'ROMEO','O, teach me how I should forget to think.'),
('romeo_and_juliet_act1_scene1',211,221,'BENVOLIO','By giving liberty unto thine eyes;'),
('romeo_and_juliet_act1_scene1',212,222,'BENVOLIO','Examine other beauties.'),
('romeo_and_juliet_act1_scene1',212,223,'ROMEO','’Tis the way'),
('romeo_and_juliet_act1_scene1',213,224,'ROMEO','To call hers exquisite, in question more:'),
('romeo_and_juliet_act1_scene1',214,225,'ROMEO','These happy masks that kiss fair ladies’ brows'),
('romeo_and_juliet_act1_scene1',215,226,'ROMEO','Being black put us in mind they hide the fair;'),
('romeo_and_juliet_act1_scene1',216,227,'ROMEO','He that is strucken blind cannot forget'),
('romeo_and_juliet_act1_scene1',217,228,'ROMEO','The precious treasure of his eyesight lost:'),
('romeo_and_juliet_act1_scene1',218,229,'ROMEO','Show me a mistress that is passing fair,'),
('romeo_and_juliet_act1_scene1',219,230,'ROMEO','What doth her beauty serve, but as a note'),
('romeo_and_juliet_act1_scene1',220,231,'ROMEO','Where I may read who pass’d that passing fair?'),
('romeo_and_juliet_act1_scene1',221,232,'ROMEO','Farewell: thou canst not teach me to forget.'),
('romeo_and_juliet_act1_scene1',222,233,'BENVOLIO','I’ll pay that doctrine, or else die in debt.'),
('romeo_and_juliet_act1_scene2',1,0,'CAPULET','But Montague is bound as well as I,'),
('romeo_and_juliet_act1_scene2',2,1,'CAPULET','In penalty alike; and ’tis not hard, I think,'),
('romeo_and_juliet_act1_scene2',3,2,'CAPULET','For men so old as we to keep the peace.'),
('romeo_and_juliet_act1_scene2',4,3,'PARIS','Of honourable reckoning are you both;'),
('romeo_and_juliet_act1_scene2',5,4,'PARIS','And pity ’tis you lived at odds so long.'),
('romeo_and_juliet_act1_scene2',6,5,'PARIS','But now, my lord, what say you to my suit?'),
('romeo_and_juliet_act1_scene2',7,6,'CAPULET','But saying o’er what I have said before:'),
('romeo_and_juliet_act1_scene2',8,7,'CAPULET','My child is yet a stranger in the world;'),
('romeo_and_juliet_act1_scene2',9,8,'CAPULET','She hath not seen the change of fourteen years;'),
('romeo_and_juliet_act1_scene2',10,9,'CAPULET','Let two more summers wither in their pride,'),
('romeo_and_juliet_act1_scene2',11,10,'CAPULET','Ere we may think her ripe to be a bride.'),
('romeo_and_juliet_act1_scene2',12,11,'PARIS','Younger than she are happy mothers made.'),
('romeo_and_juliet_act1_scene2',13,12,'CAPULET','And too soon marr’d are those so early made.'),
('romeo_and_juliet_act1_scene2',14,13,'CAPULET','The earth hath swallow’d all my hopes but she,'),
('romeo_and_juliet_act1_scene2',15,14,'CAPULET','She is the hopeful lady of my earth:'),
('romeo_and_juliet_act1_scene2',16,15,'CAPULET','But woo her, gentle Paris, get her heart,'),
('romeo_and_juliet_act1_scene2',17,16,'CAPULET','My will to her consent is but a part;'),
('romeo_and_juliet_act1_scene2',18,17,'CAPULET','An she agree, within her scope of choice'),
('romeo_and_juliet_act1_scene2',19,18,'CAPULET','Lies my consent and fair according voice.'),
('romeo_and_juliet_act1_scene2',20,19,'CAPULET','This night I hold an old accustom’d feast,'),
('romeo_and_juliet_act1_scene2',21,20,'CAPULET','Whereto I have invited many a guest,'),
('romeo_and_juliet_act1_scene2',22,21,'CAPULET','Such as I love; and you, among the store,'),
('romeo_and_juliet_act1_scene2',23,22,'CAPULET','One more, most welcome, makes my number more.'),
('romeo_and_juliet_act1_scene2',24,23,'CAPULET','At my poor house look to behold this night'),
('romeo_and_juliet_act1_scene2',25,24,'CAPULET','Earth-treading stars that make dark heaven light:'),
('romeo_and_juliet_act1_scene2',26,25,'CAPULET','Such comfort as do lusty young men feel'),
('romeo_and_juliet_act1_scene2',27,26,'CAPULET','When well-apparell’d April on the heel'),
('romeo_and_juliet_act1_scene2',28,27,'CAPULET','Of limping winter treads, even such delight'),
('romeo_and_juliet_act1_scene2',29,28,'CAPULET','Among fresh female buds shall you this night'),
('romeo_and_juliet_act1_scene2',30,29,'CAPULET','Inherit at my house; hear all, all see,'),
('romeo_and_juliet_act1_scene2',31,30,'CAPULET','And like her most whose merit most shall be:'),
('romeo_and_juliet_act1_scene2',32,31,'CAPULET','Which on more view, of many mine being one'),
('romeo_and_juliet_act1_scene2',33,32,'CAPULET','May stand in number, though in reckoning none.'),
('romeo_and_juliet_act1_scene2',34,33,'CAPULET','Come, go with me. To Servant, giving a paper. Go, sirrah, trudge about'),
('romeo_and_juliet_act1_scene2',35,34,'CAPULET','Through fair Verona; find those persons out'),
('romeo_and_juliet_act1_scene2',36,35,'CAPULET','Whose names are written there, and to them say,'),
('romeo_and_juliet_act1_scene2',37,36,'CAPULET','My house and welcome on their pleasure stay.'),
('romeo_and_juliet_act1_scene2',38,37,'SERVANT','Find them out whose names are written here! It is written, that'),
('romeo_and_juliet_act1_scene2',39,38,'SERVANT','the shoemaker should meddle with his yard, and the tailor with his'),
('romeo_and_juliet_act1_scene2',40,39,'SERVANT','last, the fisher with his pencil, and the painter with his nets;'),
('romeo_and_juliet_act1_scene2',41,40,'SERVANT','but I am sent to find those persons whose names are here'),
('romeo_and_juliet_act1_scene2',42,41,'SERVANT','writ, and can never find what names the writing person hath here'),
('romeo_and_juliet_act1_scene2',43,42,'SERVANT','writ. I must to the learned.—In good time.'),
('romeo_and_juliet_act1_scene2',44,43,'BENVOLIO','Tut, man, one fire burns out another’s burning,'),
('romeo_and_juliet_act1_scene2',45,44,'BENVOLIO','One pain is lessen’d by another’s anguish;'),
('romeo_and_juliet_act1_scene2',46,45,'BENVOLIO','Turn giddy, and be holp by backward turning;'),
('romeo_and_juliet_act1_scene2',47,46,'BENVOLIO','One desperate grief cures with another’s languish:'),
('romeo_and_juliet_act1_scene2',48,47,'BENVOLIO','Take thou some new infection to thy eye,'),
('romeo_and_juliet_act1_scene2',49,48,'BENVOLIO','And the rank poison of the old will die.'),
('romeo_and_juliet_act1_scene2',50,49,'ROMEO','Your plantain-leaf is excellent for that.'),
('romeo_and_juliet_act1_scene2',50,50,'BENVOLIO','For what, I pray thee?'),
('romeo_and_juliet_act1_scene2',51,51,'ROMEO','For your broken shin.'),
('romeo_and_juliet_act1_scene2',51,52,'BENVOLIO','Why, Romeo, art thou mad?'),
('romeo_and_juliet_act1_scene2',52,53,'ROMEO','Not mad, but bound more than a madman is;'),
('romeo_and_juliet_act1_scene2',53,54,'ROMEO','Shut up in prison, kept without my food,'),
('romeo_and_juliet_act1_scene2',54,55,'ROMEO','Whipp’d and tormented and—God-den, good fellow.'),
('romeo_and_juliet_act1_scene2',55,56,'SERVANT','God gi’ god-den. I pray, sir, can you read?'),
('romeo_and_juliet_act1_scene2',56,57,'ROMEO','Ay, mine own fortune in my misery.'),
('romeo_and_juliet_act1_scene2',57,58,'SERVANT','Perhaps you have learned it without book: but, I pray, can you'),
('romeo_and_juliet_act1_scene2',58,59,'SERVANT','read anything you see?'),
('romeo_and_juliet_act1_scene2',59,60,'ROMEO','Ay, if I know the letters and the language.'),
('romeo_and_juliet_act1_scene2',60,61,'SERVANT','Ye say honestly: rest you merry!'),
('romeo_and_juliet_act1_scene2',61,62,'ROMEO','Stay, fellow; I can read. “Signior Martino and his wife and daughters;'),
('romeo_and_juliet_act1_scene2',62,63,'ROMEO','County Anselme and his beauteous sisters; the lady widow of Vitruvio; Signior'),
('romeo_and_juliet_act1_scene2',63,64,'ROMEO','Placentio and his lovely nieces; Mercutio and his brother Valentine; mine uncle'),
('romeo_and_juliet_act1_scene2',64,65,'ROMEO','Capulet, his wife, and daughters; my fair niece Rosaline; Livia; Signior Valentio'),
('romeo_and_juliet_act1_scene2',65,66,'ROMEO','and his cousin Tybalt; Lucio and the lively Helena.” A fair assembly:'),
('romeo_and_juliet_act1_scene2',66,67,'ROMEO','whither should they come?'),
('romeo_and_juliet_act1_scene2',66,68,'SERVANT','Up.'),
('romeo_and_juliet_act1_scene2',67,69,'ROMEO','Whither?'),
('romeo_and_juliet_act1_scene2',67,70,'SERVANT','To supper; to our house.'),
('romeo_and_juliet_act1_scene2',68,71,'ROMEO','Whose house?'),
('romeo_and_juliet_act1_scene2',68,72,'SERVANT','My master’s.'),
('romeo_and_juliet_act1_scene2',69,73,'ROMEO','Indeed, I should have ask’d you that before.'),
('romeo_and_juliet_act1_scene2',70,74,'SERVANT','Now I’ll tell you without asking: my master is the great rich'),
('romeo_and_juliet_act1_scene2',71,75,'SERVANT','Capulet; and if you be not of the house of Montagues, I'),
('romeo_and_juliet_act1_scene2',72,76,'SERVANT','pray, come and crush a cup of wine. Rest you merry!'),
('romeo_and_juliet_act1_scene2',73,77,'BENVOLIO','At this same ancient feast of Capulet’s'),
('romeo_and_juliet_act1_scene2',74,78,'BENVOLIO','Sups the fair Rosaline whom thou so lovest,'),
('romeo_and_juliet_act1_scene2',75,79,'BENVOLIO','With all the admired beauties of Verona:'),
('romeo_and_juliet_act1_scene2',76,80,'BENVOLIO','Go thither; and, with unattainted eye,'),
('romeo_and_juliet_act1_scene2',77,81,'BENVOLIO','Compare her face with some that I shall show,'),
('romeo_and_juliet_act1_scene2',78,82,'BENVOLIO','And I will make thee think thy swan a crow.'),
('romeo_and_juliet_act1_scene2',79,83,'ROMEO','When the devout religion of mine eye'),
('romeo_and_juliet_act1_scene2',80,84,'ROMEO','Maintains such falsehood, then turn tears to fires;'),
('romeo_and_juliet_act1_scene2',81,85,'ROMEO','And these, who often drown’d could never die,'),
('romeo_and_juliet_act1_scene2',82,86,'ROMEO','Transparent heretics, be burnt for liars!'),
('romeo_and_juliet_act1_scene2',83,87,'ROMEO','One fairer than my love! the all-seeing sun'),
('romeo_and_juliet_act1_scene2',84,88,'ROMEO','Ne’er saw her match since first the world begun.'),
('romeo_and_juliet_act1_scene2',85,89,'BENVOLIO','Tut, you saw her fair, none else being by,'),
('romeo_and_juliet_act1_scene2',86,90,'BENVOLIO','Herself poised with herself in either eye:'),
('romeo_and_juliet_act1_scene2',87,91,'BENVOLIO','But in that crystal scales let there be weigh’d'),
('romeo_and_juliet_act1_scene2',88,92,'BENVOLIO','Your lady’s love against some other maid'),
('romeo_and_juliet_act1_scene2',89,93,'BENVOLIO','That I will show you shining at this feast,'),
('romeo_and_juliet_act1_scene2',90,94,'BENVOLIO','And she shall scant show well that now shows best.'),
('romeo_and_juliet_act1_scene2',91,95,'ROMEO','I’ll go along, no such sight to be shown,'),
('romeo_and_juliet_act1_scene2',92,96,'ROMEO','But to rejoice in splendour of mine own.'),
('romeo_and_juliet_act1_scene3',1,0,'LADY CAPULET','Nurse, where’s my daughter? call her forth to me.'),
('romeo_and_juliet_act1_scene3',2,1,'NURSE','Now, by my maidenhead, at twelve year old,'),
('romeo_and_juliet_act1_scene3',3,2,'NURSE','I bade her come. What, lamb! what, lady-bird!'),
('romeo_and_juliet_act1_scene3',4,3,'NURSE','God forbid! Where’s this girl? What, Juliet!'),
('romeo_and_juliet_act1_scene3',5,4,'JULIET','How now! who calls?'),
('romeo_and_juliet_act1_scene3',5,5,'NURSE','Your mother.'),
('romeo_and_juliet_act1_scene3',6,6,'JULIET','Madam, I am here.'),
('romeo_and_juliet_act1_scene3',7,7,'JULIET','What is your will?'),
('romeo_and_juliet_act1_scene3',8,8,'LADY CAPULET','This is the matter:—Nurse, give leave awhile,'),
('romeo_and_juliet_act1_scene3',9,9,'LADY CAPULET','We must talk in secret:—nurse, come back again;'),
('romeo_and_juliet_act1_scene3',10,10,'LADY CAPULET','I have remember’d me, thou’s hear our counsel.'),
('romeo_and_juliet_act1_scene3',11,11,'LADY CAPULET','Thou know’st my daughter’s of a pretty age.'),
('romeo_and_juliet_act1_scene3',12,12,'NURSE','Faith, I can tell her age unto an hour.'),
('romeo_and_juliet_act1_scene3',13,13,'LADY CAPULET','She’s not fourteen.'),
('romeo_and_juliet_act1_scene3',13,14,'NURSE','I’ll lay fourteen of my teeth—'),
('romeo_and_juliet_act1_scene3',14,15,'NURSE','And yet, to my teen be it spoken, I have but four—'),
('romeo_and_juliet_act1_scene3',15,16,'NURSE','She is not fourteen. How long is it now'),
('romeo_and_juliet_act1_scene3',16,17,'NURSE','To Lammas-tide?'),
('romeo_and_juliet_act1_scene3',16,18,'LADY CAPULET','A fortnight and odd days.'),
('romeo_and_juliet_act1_scene3',17,19,'NURSE','Even or odd, of all days in the year,'),
('romeo_and_juliet_act1_scene3',18,20,'NURSE','Come Lammas-eve at night shall she be fourteen.'),
('romeo_and_juliet_act1_scene3',19,21,'NURSE','Susan and she—God rest all Christian souls!—'),
('romeo_and_juliet_act1_scene3',20,22,'NURSE','Were of an age: well, Susan is with God;'),
('romeo_and_juliet_act1_scene3',21,23,'NURSE','She was too good for me: but, as I said,'),
('romeo_and_juliet_act1_scene3',22,24,'NURSE','On Lammas-eve at night shall she be fourteen;'),
('romeo_and_juliet_act1_scene3',23,25,'NURSE','That shall she, marry; I remember it well.'),
('romeo_and_juliet_act1_scene3',24,26,'NURSE','’Tis since the earthquake now eleven years;'),
('romeo_and_juliet_act1_scene3',25,27,'NURSE','And she was wean’d—I never shall forget it—'),
('romeo_and_juliet_act1_scene3',26,28,'NURSE','Of all the days of the year, upon that day:'),
('romeo_and_juliet_act1_scene3',27,29,'NURSE','For I had then laid wormwood to my dug,'),
('romeo_and_juliet_act1_scene3',28,30,'NURSE','Sitting in the sun under the dove-house wall;'),
('romeo_and_juliet_act1_scene3',29,31,'NURSE','My lord and you were then at Mantua:—'),
('romeo_and_juliet_act1_scene3',30,32,'NURSE','Nay, I do bear a brain:—but, as I said,'),
('romeo_and_juliet_act1_scene3',31,33,'NURSE','When it did taste the wormwood on the nipple'),
('romeo_and_juliet_act1_scene3',32,34,'NURSE','Of my dug and felt it bitter, pretty fool,'),
('romeo_and_juliet_act1_scene3',33,35,'NURSE','To see it tetchy and fall out with the dug!'),
('romeo_and_juliet_act1_scene3',34,36,'NURSE','“Shake” quoth the dove-house: ’twas no need, I trow,'),
('romeo_and_juliet_act1_scene3',35,37,'NURSE','To bid me trudge:'),
('romeo_and_juliet_act1_scene3',36,38,'NURSE','And since that time it is eleven years;'),
('romeo_and_juliet_act1_scene3',37,39,'NURSE','For then she could stand alone; nay, by the rood,'),
('romeo_and_juliet_act1_scene3',38,40,'NURSE','She could have run and waddled all about;'),
('romeo_and_juliet_act1_scene3',39,41,'NURSE','For even the day before, she broke her brow:'),
('romeo_and_juliet_act1_scene3',40,42,'NURSE','And then my husband—God be with his soul!'),
('romeo_and_juliet_act1_scene3',41,43,'NURSE','A’ was a merry man—took up the child:'),
('romeo_and_juliet_act1_scene3',42,44,'NURSE','“Yea,” quoth he, “dost thou fall upon thy face?'),
('romeo_and_juliet_act1_scene3',43,45,'NURSE','Thou wilt fall backward when thou hast more wit;'),
('romeo_and_juliet_act1_scene3',44,46,'NURSE','Wilt thou not, Jule?” and, by my holidame,'),
('romeo_and_juliet_act1_scene3',45,47,'NURSE','The pretty wretch left crying and said “Ay.”'),
('romeo_and_juliet_act1_scene3',46,48,'NURSE','To see, now, how a jest shall come about!'),
('romeo_and_juliet_act1_scene3',47,49,'NURSE','I warrant, an I should live a thousand years,'),
('romeo_and_juliet_act1_scene3',48,50,'NURSE','I never should forget it: “Wilt thou not, Jule?” quoth he;'),
('romeo_and_juliet_act1_scene3',49,51,'NURSE','And, pretty fool, it stinted and said “Ay.”'),
('romeo_and_juliet_act1_scene3',50,52,'LADY CAPULET','Enough of this; I pray thee, hold thy peace.'),
('romeo_and_juliet_act1_scene3',51,53,'NURSE','Yes, madam: yet I cannot choose but laugh,'),
('romeo_and_juliet_act1_scene3',52,54,'NURSE','To think it should leave crying and say “Ay.”'),
('romeo_and_juliet_act1_scene3',53,55,'NURSE','And yet, I warrant, it had upon its brow'),
('romeo_and_juliet_act1_scene3',54,56,'NURSE','A bump as big as a young cockerel’s stone;'),
('romeo_and_juliet_act1_scene3',55,57,'NURSE','A parlous knock; and it cried bitterly:'),
('romeo_and_juliet_act1_scene3',56,58,'NURSE','“Yea,” quoth my husband, “fall’st upon thy face?'),
('romeo_and_juliet_act1_scene3',57,59,'NURSE','Thou wilt fall backward when thou comest to age;'),
('romeo_and_juliet_act1_scene3',58,60,'NURSE','Wilt thou not, Jule?” it stinted and said “Ay.”'),
('romeo_and_juliet_act1_scene3',59,61,'JULIET','And stint thou too, I pray thee, nurse, say I.'),
('romeo_and_juliet_act1_scene3',60,62,'NURSE','Peace, I have done. God mark thee to his grace!'),
('romeo_and_juliet_act1_scene3',61,63,'NURSE','Thou wast the prettiest babe that e’er I nursed:'),
('romeo_and_juliet_act1_scene3',62,64,'NURSE','An I might live to see thee married once,'),
('romeo_and_juliet_act1_scene3',63,65,'NURSE','I have my wish.'),
('romeo_and_juliet_act1_scene3',64,66,'LADY CAPULET','Marry, that “marry” is the very theme'),
('romeo_and_juliet_act1_scene3',65,67,'LADY CAPULET','I came to talk of. Tell me, daughter Juliet,'),
('romeo_and_juliet_act1_scene3',66,68,'LADY CAPULET','How stands your disposition to be married?'),
('romeo_and_juliet_act1_scene3',67,69,'JULIET','It is an honour that I dream not of.'),
('romeo_and_juliet_act1_scene3',68,70,'NURSE','An honour! were not I thine only nurse,'),
('romeo_and_juliet_act1_scene3',69,71,'NURSE','I would say thou hadst suck’d wisdom from thy teat.'),
('romeo_and_juliet_act1_scene3',70,72,'LADY CAPULET','Well, think of marriage now; younger than you,'),
('romeo_and_juliet_act1_scene3',71,73,'LADY CAPULET','Here in Verona, ladies of esteem,'),
('romeo_and_juliet_act1_scene3',72,74,'LADY CAPULET','Are made already mothers: by my count,'),
('romeo_and_juliet_act1_scene3',73,75,'LADY CAPULET','I was your mother much upon these years'),
('romeo_and_juliet_act1_scene3',74,76,'LADY CAPULET','That you are now a maid. Thus then in brief:'),
('romeo_and_juliet_act1_scene3',75,77,'LADY CAPULET','The valiant Paris seeks you for his love.'),
('romeo_and_juliet_act1_scene3',76,78,'NURSE','A man, young lady! lady, such a man'),
('romeo_and_juliet_act1_scene3',77,79,'NURSE','As all the world—why, he’s a man of wax.'),
('romeo_and_juliet_act1_scene3',78,80,'LADY CAPULET','Verona’s summer hath not such a flower.'),
('romeo_and_juliet_act1_scene3',79,81,'NURSE','Nay, he’s a flower; in faith, a very flower.'),
('romeo_and_juliet_act1_scene3',80,82,'LADY CAPULET','What say you? can you love the gentleman?'),
('romeo_and_juliet_act1_scene3',81,83,'LADY CAPULET','This night you shall behold him at our feast;'),
('romeo_and_juliet_act1_scene3',82,84,'LADY CAPULET','Read o’er the volume of young Paris’ face,'),
('romeo_and_juliet_act1_scene3',83,85,'LADY CAPULET','And find delight writ there with beauty’s pen;'),
('romeo_and_juliet_act1_scene3',84,86,'LADY CAPULET','Examine every married lineament,'),
('romeo_and_juliet_act1_scene3',85,87,'LADY CAPULET','And see how one another lends content,'),
('romeo_and_juliet_act1_scene3',86,88,'LADY CAPULET','And what obscured in this fair volume lies'),
('romeo_and_juliet_act1_scene3',87,89,'LADY CAPULET','Find written in the margent of his eyes.'),
('romeo_and_juliet_act1_scene3',88,90,'LADY CAPULET','This precious book of love, this unbound lover,'),
('romeo_and_juliet_act1_scene3',89,91,'LADY CAPULET','To beautify him, only lacks a cover:'),
('romeo_and_juliet_act1_scene3',90,92,'LADY CAPULET','The fish lives in the sea, and ’tis much pride'),
('romeo_and_juliet_act1_scene3',91,93,'LADY CAPULET','For fair without the fair within to hide:'),
('romeo_and_juliet_act1_scene3',92,94,'LADY CAPULET','That book in many’s eyes doth share the glory,'),
('romeo_and_juliet_act1_scene3',93,95,'LADY CAPULET','That in gold clasps locks in the golden story;'),
('romeo_and_juliet_act1_scene3',94,96,'LADY CAPULET','So shall you share all that he doth possess,'),
('romeo_and_juliet_act1_scene3',95,97,'LADY CAPULET','By having him, making yourself no less.'),
('romeo_and_juliet_act1_scene3',96,98,'NURSE','No less! nay, bigger; women grow by men.'),
('romeo_and_juliet_act1_scene3',97,99,'LADY CAPULET','Speak briefly, can you like of Paris’ love?'),
('romeo_and_juliet_act1_scene3',98,100,'JULIET','I’ll look to like, if looking liking move:'),
('romeo_and_juliet_act1_scene3',99,101,'JULIET','But no more deep will I endart mine eye'),
('romeo_and_juliet_act1_scene3',100,102,'JULIET','Than your consent gives strength to make it fly.'),
('romeo_and_juliet_act1_scene3',101,103,'SERVANT','Madam, the guests are come, supper served up, you called, my young'),
('romeo_and_juliet_act1_scene3',102,104,'SERVANT','lady asked for, the nurse cursed in the pantry, and everything in'),
('romeo_and_juliet_act1_scene3',103,105,'SERVANT','extremity. I must hence to wait; I beseech you, follow straight.'),
('romeo_and_juliet_act1_scene3',104,106,'LADY CAPULET','We follow thee. Juliet, the county stays.'),
('romeo_and_juliet_act1_scene3',105,107,'NURSE','Go, girl, seek happy nights to happy days.'),
('romeo_and_juliet_act1_scene4',1,0,'ROMEO','What, shall this speech be spoke for our excuse?'),
('romeo_and_juliet_act1_scene4',2,1,'ROMEO','Or shall we on without apology?'),
('romeo_and_juliet_act1_scene4',3,2,'BENVOLIO','The date is out of such prolixity:'),
('romeo_and_juliet_act1_scene4',4,3,'BENVOLIO','We’ll have no Cupid hoodwink’d with a scarf,'),
('romeo_and_juliet_act1_scene4',5,4,'BENVOLIO','Bearing a Tartar’s painted bow of lath,'),
('romeo_and_juliet_act1_scene4',6,5,'BENVOLIO','Scaring the ladies like a crow-keeper;'),
('romeo_and_juliet_act1_scene4',7,6,'BENVOLIO','Nor no without-book prologue, faintly spoke'),
('romeo_and_juliet_act1_scene4',8,7,'BENVOLIO','After the prompter, for our entrance:'),
('romeo_and_juliet_act1_scene4',9,8,'BENVOLIO','But let them measure us by what they will;'),
('romeo_and_juliet_act1_scene4',10,9,'BENVOLIO','We’ll measure them a measure, and be gone.'),
('romeo_and_juliet_act1_scene4',11,10,'ROMEO','Give me a torch: I am not for this ambling;'),
('romeo_and_juliet_act1_scene4',12,11,'ROMEO','Being but heavy, I will bear the light.'),
('romeo_and_juliet_act1_scene4',13,12,'MERCUTIO','Nay, gentle Romeo, we must have you dance.'),
('romeo_and_juliet_act1_scene4',14,13,'ROMEO','Not I, believe me: you have dancing shoes'),
('romeo_and_juliet_act1_scene4',15,14,'ROMEO','With nimble soles: I have a soul of lead'),
('romeo_and_juliet_act1_scene4',16,15,'ROMEO','So stakes me to the ground I cannot move.'),
('romeo_and_juliet_act1_scene4',17,16,'MERCUTIO','You are a lover; borrow Cupid’s wings,'),
('romeo_and_juliet_act1_scene4',18,17,'MERCUTIO','And soar with them above a common bound.'),
('romeo_and_juliet_act1_scene4',19,18,'ROMEO','I am too sore enpierced with his shaft'),
('romeo_and_juliet_act1_scene4',20,19,'ROMEO','To soar with his light feathers, and so bound,'),
('romeo_and_juliet_act1_scene4',21,20,'ROMEO','I cannot bound a pitch above dull woe:'),
('romeo_and_juliet_act1_scene4',22,21,'ROMEO','Under love’s heavy burden do I sink.'),
('romeo_and_juliet_act1_scene4',23,22,'MERCUTIO','And, to sink in it, should you burden love;'),
('romeo_and_juliet_act1_scene4',24,23,'MERCUTIO','Too great oppression for a tender thing.'),
('romeo_and_juliet_act1_scene4',25,24,'ROMEO','Is love a tender thing? it is too rough,'),
('romeo_and_juliet_act1_scene4',26,25,'ROMEO','Too rude, too boisterous, and it pricks like thorn.'),
('romeo_and_juliet_act1_scene4',27,26,'MERCUTIO','If love be rough with you, be rough with love;'),
('romeo_and_juliet_act1_scene4',28,27,'MERCUTIO','Prick love for pricking, and you beat love down.'),
('romeo_and_juliet_act1_scene4',29,28,'MERCUTIO','Give me a case to put my visage in:'),
('romeo_and_juliet_act1_scene4',30,29,'MERCUTIO','A visor for a visor! what care I'),
('romeo_and_juliet_act1_scene4',31,30,'MERCUTIO','What curious eye doth quote deformities?'),
('romeo_and_juliet_act1_scene4',32,31,'MERCUTIO','Here are the beetle brows shall blush for me.'),
('romeo_and_juliet_act1_scene4',33,32,'BENVOLIO','Come, knock and enter; and no sooner in,'),
('romeo_and_juliet_act1_scene4',34,33,'BENVOLIO','But every man betake him to his legs.'),
('romeo_and_juliet_act1_scene4',35,34,'ROMEO','A torch for me: let wantons light of heart'),
('romeo_and_juliet_act1_scene4',36,35,'ROMEO','Tickle the senseless rushes with their heels,'),
('romeo_and_juliet_act1_scene4',37,36,'ROMEO','For I am proverb’d with a grandsire phrase;'),
('romeo_and_juliet_act1_scene4',38,37,'ROMEO','I’ll be a candle-holder, and look on.'),
('romeo_and_juliet_act1_scene4',39,38,'ROMEO','The game was ne’er so fair, and I am done.'),
('romeo_and_juliet_act1_scene4',40,39,'MERCUTIO','Tut, dun’s the mouse, the constable’s own word:'),
('romeo_and_juliet_act1_scene4',41,40,'MERCUTIO','If thou art dun, we’ll draw thee from the mire'),
('romeo_and_juliet_act1_scene4',42,41,'MERCUTIO','Of this sir-reverence love, wherein thou stick’st'),
('romeo_and_juliet_act1_scene4',43,42,'MERCUTIO','Up to the ears. Come, we burn daylight, ho!'),
('romeo_and_juliet_act1_scene4',44,43,'ROMEO','Nay, that’s not so.'),
('romeo_and_juliet_act1_scene4',44,44,'MERCUTIO','I mean, sir, in delay'),
('romeo_and_juliet_act1_scene4',45,45,'MERCUTIO','We waste our lights in vain, like lamps by day.'),
('romeo_and_juliet_act1_scene4',46,46,'MERCUTIO','Take our good meaning, for our judgment sits'),
('romeo_and_juliet_act1_scene4',47,47,'MERCUTIO','Five times in that ere once in our five wits.'),
('romeo_and_juliet_act1_scene4',48,48,'ROMEO','And we mean well in going to this mask;'),
('romeo_and_juliet_act1_scene4',49,49,'ROMEO','But ’tis no wit to go.'),
('romeo_and_juliet_act1_scene4',49,50,'MERCUTIO','Why, may one ask?'),
('romeo_and_juliet_act1_scene4',50,51,'ROMEO','I dream’d a dream to-night.'),
('romeo_and_juliet_act1_scene4',50,52,'MERCUTIO','And so did I.'),
('romeo_and_juliet_act1_scene4',51,53,'ROMEO','Well, what was yours?'),
('romeo_and_juliet_act1_scene4',51,54,'MERCUTIO','That dreamers often lie.'),
('romeo_and_juliet_act1_scene4',52,55,'ROMEO','In bed asleep, while they do dream things true.'),
('romeo_and_juliet_act1_scene4',53,56,'MERCUTIO','O, then, I see Queen Mab hath been with you.'),
('romeo_and_juliet_act1_scene4',54,57,'MERCUTIO','She is the fairies’ midwife, and she comes'),
('romeo_and_juliet_act1_scene4',55,58,'MERCUTIO','In shape no bigger than an agate-stone'),
('romeo_and_juliet_act1_scene4',56,59,'MERCUTIO','On the fore-finger of an alderman,'),
('romeo_and_juliet_act1_scene4',57,60,'MERCUTIO','Drawn with a team of little atomies'),
('romeo_and_juliet_act1_scene4',58,61,'MERCUTIO','Athwart men’s noses as they lie asleep;'),
('romeo_and_juliet_act1_scene4',59,62,'MERCUTIO','Her wagon-spokes made of long spinners’ legs,'),
('romeo_and_juliet_act1_scene4',60,63,'MERCUTIO','The cover of the wings of grasshoppers,'),
('romeo_and_juliet_act1_scene4',61,64,'MERCUTIO','The traces of the smallest spider’s web,'),
('romeo_and_juliet_act1_scene4',62,65,'MERCUTIO','The collars of the moonshine’s watery beams,'),
('romeo_and_juliet_act1_scene4',63,66,'MERCUTIO','Her whip of cricket’s bone, the lash of film,'),
('romeo_and_juliet_act1_scene4',64,67,'MERCUTIO','Her waggoner a small grey-coated gnat,'),
('romeo_and_juliet_act1_scene4',65,68,'MERCUTIO','Not half so big as a round little worm'),
('romeo_and_juliet_act1_scene4',66,69,'MERCUTIO','Prick’d from the lazy finger of a maid;'),
('romeo_and_juliet_act1_scene4',67,70,'MERCUTIO','Her chariot is an empty hazel-nut'),
('romeo_and_juliet_act1_scene4',68,71,'MERCUTIO','Made by the joiner squirrel or old grub,'),
('romeo_and_juliet_act1_scene4',69,72,'MERCUTIO','Time out o’ mind the fairies’ coach-makers.'),
('romeo_and_juliet_act1_scene4',70,73,'MERCUTIO','And in this state she gallops night by night'),
('romeo_and_juliet_act1_scene4',71,74,'MERCUTIO','Through lovers’ brains, and then they dream of love;'),
('romeo_and_juliet_act1_scene4',72,75,'MERCUTIO','O’er courtiers’ knees, that dream on court’sies straight,'),
('romeo_and_juliet_act1_scene4',73,76,'MERCUTIO','O’er lawyers’ fingers, who straight dream on fees,'),
('romeo_and_juliet_act1_scene4',74,77,'MERCUTIO','O’er ladies’ lips, who straight on kisses dream,'),
('romeo_and_juliet_act1_scene4',75,78,'MERCUTIO','Which oft the angry Mab with blisters plagues,'),
('romeo_and_juliet_act1_scene4',76,79,'MERCUTIO','Because their breaths with sweetmeats tainted are:'),
('romeo_and_juliet_act1_scene4',77,80,'MERCUTIO','Sometime she gallops o’er a courtier’s nose,'),
('romeo_and_juliet_act1_scene4',78,81,'MERCUTIO','And then dreams he of smelling out a suit;'),
('romeo_and_juliet_act1_scene4',79,82,'MERCUTIO','And sometime comes she with a tithe-pig’s tail'),
('romeo_and_juliet_act1_scene4',80,83,'MERCUTIO','Tickling a parson’s nose as a’ lies asleep,'),
('romeo_and_juliet_act1_scene4',81,84,'MERCUTIO','Then dreams he of another benefice:'),
('romeo_and_juliet_act1_scene4',82,85,'MERCUTIO','Sometime she driveth o’er a soldier’s neck,'),
('romeo_and_juliet_act1_scene4',83,86,'MERCUTIO','And then dreams he of cutting foreign throats,'),
('romeo_and_juliet_act1_scene4',84,87,'MERCUTIO','Of breaches, ambuscadoes, Spanish blades,'),
('romeo_and_juliet_act1_scene4',85,88,'MERCUTIO','Of healths five-fathom deep; and then anon'),
('romeo_and_juliet_act1_scene4',86,89,'MERCUTIO','Drums in his ear, at which he starts and wakes,'),
('romeo_and_juliet_act1_scene4',87,90,'MERCUTIO','And being thus frighted swears a prayer or two'),
('romeo_and_juliet_act1_scene4',88,91,'MERCUTIO','And sleeps again. This is that very Mab'),
('romeo_and_juliet_act1_scene4',89,92,'MERCUTIO','That plats the manes of horses in the night,'),
('romeo_and_juliet_act1_scene4',90,93,'MERCUTIO','And bakes the elf-locks in foul sluttish hairs,'),
('romeo_and_juliet_act1_scene4',91,94,'MERCUTIO','Which once untangled much misfortune bodes:'),
('romeo_and_juliet_act1_scene4',92,95,'MERCUTIO','This is the hag, when maids lie on their backs,'),
('romeo_and_juliet_act1_scene4',93,96,'MERCUTIO','That presses them and learns them first to bear,'),
('romeo_and_juliet_act1_scene4',94,97,'MERCUTIO','Making them women of good carriage:'),
('romeo_and_juliet_act1_scene4',95,98,'MERCUTIO','This is she—'),
('romeo_and_juliet_act1_scene4',95,99,'ROMEO','Peace, peace, Mercutio, peace!'),
('romeo_and_juliet_act1_scene4',96,100,'ROMEO','Thou talk’st of nothing.'),
('romeo_and_juliet_act1_scene4',96,101,'MERCUTIO','True, I talk of dreams,'),
('romeo_and_juliet_act1_scene4',97,102,'MERCUTIO','Which are the children of an idle brain,'),
('romeo_and_juliet_act1_scene4',98,103,'MERCUTIO','Begot of nothing but vain fantasy,'),
('romeo_and_juliet_act1_scene4',99,104,'MERCUTIO','Which is as thin of substance as the air'),
('romeo_and_juliet_act1_scene4',100,105,'MERCUTIO','And more inconstant than the wind, who wooes'),
('romeo_and_juliet_act1_scene4',101,106,'MERCUTIO','Even now the frozen bosom of the north,'),
('romeo_and_juliet_act1_scene4',102,107,'MERCUTIO','And, being anger’d, puffs away from thence,'),
('romeo_and_juliet_act1_scene4',103,108,'MERCUTIO','Turning his face to the dew-dropping south.'),
('romeo_and_juliet_act1_scene4',104,109,'BENVOLIO','This wind, you talk of, blows us from ourselves;'),
('romeo_and_juliet_act1_scene4',105,110,'BENVOLIO','Supper is done, and we shall come too late.'),
('romeo_and_juliet_act1_scene4',106,111,'ROMEO','I fear, too early: for my mind misgives'),
('romeo_and_juliet_act1_scene4',107,112,'ROMEO','Some consequence yet hanging in the stars'),
('romeo_and_juliet_act1_scene4',108,113,'ROMEO','Shall bitterly begin his fearful date'),
('romeo_and_juliet_act1_scene4',109,114,'ROMEO','With this night’s revels and expire the term'),
('romeo_and_juliet_act1_scene4',110,115,'ROMEO','Of a despised life closed in my breast'),
('romeo_and_juliet_act1_scene4',111,116,'ROMEO','By some vile forfeit of untimely death.'),
('romeo_and_juliet_act1_scene4',112,117,'ROMEO','But He, that hath the steerage of my course,'),
('romeo_and_juliet_act1_scene4',113,118,'ROMEO','Direct my sail! On, lusty gentlemen.'),
('romeo_and_juliet_act1_scene4',113,119,'BENVOLIO','Strike, drum.'),
('romeo_and_juliet_act1_scene5',1,0,'FIRST SERVINGMAN','Where’s Potpan, that he helps not to take away? He shift a'),
('romeo_and_juliet_act1_scene5',2,1,'FIRST SERVINGMAN','trencher? he scrape a trencher!'),
('romeo_and_juliet_act1_scene5',3,2,'SECOND SERVINGMAN','When good manners shall lie all in one or two men’s hands'),
('romeo_and_juliet_act1_scene5',4,3,'SECOND SERVINGMAN','and they unwashed too, ’tis a foul thing.'),
('romeo_and_juliet_act1_scene5',5,4,'FIRST SERVINGMAN','Away with the joint-stools, remove the court-cupboard, look to the plate. Good'),
('romeo_and_juliet_act1_scene5',6,5,'FIRST SERVINGMAN','thou, save me a piece of marchpane; and, as thou lovest me,'),
('romeo_and_juliet_act1_scene5',7,6,'FIRST SERVINGMAN','let the porter let in Susan Grindstone and Nell. Antony, and Potpan!'),
('romeo_and_juliet_act1_scene5',8,7,'SECOND SERVINGMAN','Ay, boy, ready.'),
('romeo_and_juliet_act1_scene5',9,8,'FIRST SERVINGMAN','You are looked for and called for, asked for and sought for,'),
('romeo_and_juliet_act1_scene5',10,9,'FIRST SERVINGMAN','in the great chamber.'),
('romeo_and_juliet_act1_scene5',11,10,'SECOND SERVINGMAN','We cannot be here and there too. Cheerly, boys; be brisk awhile,'),
('romeo_and_juliet_act1_scene5',12,11,'SECOND SERVINGMAN','and the longer liver take all.'),
('romeo_and_juliet_act1_scene5',13,12,'CAPULET','Welcome, gentlemen! ladies that have their toes'),
('romeo_and_juliet_act1_scene5',14,13,'CAPULET','Unplagued with corns will have a bout with you.'),
('romeo_and_juliet_act1_scene5',15,14,'CAPULET','Ah ha, my mistresses! which of you all'),
('romeo_and_juliet_act1_scene5',16,15,'CAPULET','Will now deny to dance? she that makes dainty,'),
('romeo_and_juliet_act1_scene5',17,16,'CAPULET','She, I’ll swear, hath corns; am I come near ye now?'),
('romeo_and_juliet_act1_scene5',18,17,'CAPULET','Welcome, gentlemen! I have seen the day'),
('romeo_and_juliet_act1_scene5',19,18,'CAPULET','That I have worn a visor and could tell'),
('romeo_and_juliet_act1_scene5',20,19,'CAPULET','A whispering tale in a fair lady’s ear,'),
('romeo_and_juliet_act1_scene5',21,20,'CAPULET','Such as would please: ’tis gone, ’tis gone, ’tis gone:'),
('romeo_and_juliet_act1_scene5',22,21,'CAPULET','You are welcome, gentlemen! come, musicians, play.'),
('romeo_and_juliet_act1_scene5',23,22,'CAPULET','A hall, a hall! give room! and foot it, girls.'),
('romeo_and_juliet_act1_scene5',24,23,'CAPULET','More light, you knaves; and turn the tables up,'),
('romeo_and_juliet_act1_scene5',25,24,'CAPULET','And quench the fire, the room is grown too hot.'),
('romeo_and_juliet_act1_scene5',26,25,'CAPULET','Ah, sirrah, this unlook’d-for sport comes well.'),
('romeo_and_juliet_act1_scene5',27,26,'CAPULET','Nay, sit, nay, sit, good cousin Capulet;'),
('romeo_and_juliet_act1_scene5',28,27,'CAPULET','For you and I are past our dancing days:'),
('romeo_and_juliet_act1_scene5',29,28,'CAPULET','How long is’t now since last yourself and I'),
('romeo_and_juliet_act1_scene5',30,29,'CAPULET','Were in a mask?'),
('romeo_and_juliet_act1_scene5',30,30,'SECOND CAPULET','By’r lady, thirty years.'),
('romeo_and_juliet_act1_scene5',31,31,'CAPULET','What, man! ’tis not so much, ’tis not so much:'),
('romeo_and_juliet_act1_scene5',32,32,'CAPULET','’Tis since the nuptials of Lucentio,'),
('romeo_and_juliet_act1_scene5',33,33,'CAPULET','Come Pentecost as quickly as it will,'),
('romeo_and_juliet_act1_scene5',34,34,'CAPULET','Some five and twenty years; and then we mask’d.'),
('romeo_and_juliet_act1_scene5',35,35,'SECOND CAPULET','’Tis more, ’tis more: his son is elder, sir;'),
('romeo_and_juliet_act1_scene5',36,36,'SECOND CAPULET','His son is thirty.'),
('romeo_and_juliet_act1_scene5',36,37,'CAPULET','Will you tell me that?'),
('romeo_and_juliet_act1_scene5',37,38,'CAPULET','His son was but a ward two years ago.'),
('romeo_and_juliet_act1_scene5',38,39,'ROMEO','To a Servingman. What lady is that, which doth enrich the hand'),
('romeo_and_juliet_act1_scene5',39,40,'ROMEO','Of yonder knight?'),
('romeo_and_juliet_act1_scene5',39,41,'SERVINGMAN','I know not, sir.'),
('romeo_and_juliet_act1_scene5',40,42,'ROMEO','O, she doth teach the torches to burn bright!'),
('romeo_and_juliet_act1_scene5',41,43,'ROMEO','It seems she hangs upon the cheek of night'),
('romeo_and_juliet_act1_scene5',42,44,'ROMEO','Like a rich jewel in an Ethiope’s ear;'),
('romeo_and_juliet_act1_scene5',43,45,'ROMEO','Beauty too rich for use, for earth too dear!'),
('romeo_and_juliet_act1_scene5',44,46,'ROMEO','So shows a snowy dove trooping with crows,'),
('romeo_and_juliet_act1_scene5',45,47,'ROMEO','As yonder lady o’er her fellows shows.'),
('romeo_and_juliet_act1_scene5',46,48,'ROMEO','The measure done, I’ll watch her place of stand,'),
('romeo_and_juliet_act1_scene5',47,49,'ROMEO','And, touching hers, make blessed my rude hand.'),
('romeo_and_juliet_act1_scene5',48,50,'ROMEO','Did my heart love till now? forswear it, sight!'),
('romeo_and_juliet_act1_scene5',49,51,'ROMEO','For I ne’er saw true beauty till this night.'),
('romeo_and_juliet_act1_scene5',50,52,'TYBALT','This, by his voice, should be a Montague.'),
('romeo_and_juliet_act1_scene5',51,53,'TYBALT','Fetch me my rapier, boy. What dares the slave,'),
('romeo_and_juliet_act1_scene5',52,54,'TYBALT','Come hither, cover’d with an antic face,'),
('romeo_and_juliet_act1_scene5',53,55,'TYBALT','To fleer and scorn at our solemnity?'),
('romeo_and_juliet_act1_scene5',54,56,'TYBALT','Now, by the stock and honour of my kin,'),
('romeo_and_juliet_act1_scene5',55,57,'TYBALT','To strike him dead I hold it not a sin.'),
('romeo_and_juliet_act1_scene5',56,58,'CAPULET','Why, how now, kinsman! wherefore storm you so?'),
('romeo_and_juliet_act1_scene5',57,59,'TYBALT','Uncle, this is a Montague, our foe,'),
('romeo_and_juliet_act1_scene5',58,60,'TYBALT','A villain that is hither come in spite,'),
('romeo_and_juliet_act1_scene5',59,61,'TYBALT','To scorn at our solemnity this night.'),
('romeo_and_juliet_act1_scene5',60,62,'CAPULET','Young Romeo is it?'),
('romeo_and_juliet_act1_scene5',60,63,'TYBALT','’Tis he, that villain Romeo.'),
('romeo_and_juliet_act1_scene5',61,64,'CAPULET','Content thee, gentle coz, let him alone;'),
('romeo_and_juliet_act1_scene5',62,65,'CAPULET','He bears him like a portly gentleman;'),
('romeo_and_juliet_act1_scene5',63,66,'CAPULET','And, to say truth, Verona brags of him'),
('romeo_and_juliet_act1_scene5',64,67,'CAPULET','To be a virtuous and well govern’d youth:'),
('romeo_and_juliet_act1_scene5',65,68,'CAPULET','I would not for the wealth of all the town'),
('romeo_and_juliet_act1_scene5',66,69,'CAPULET','Here in my house do him disparagement:'),
('romeo_and_juliet_act1_scene5',67,70,'CAPULET','Therefore be patient, take no note of him:'),
('romeo_and_juliet_act1_scene5',68,71,'CAPULET','It is my will, the which if thou respect,'),
('romeo_and_juliet_act1_scene5',69,72,'CAPULET','Show a fair presence and put off these frowns,'),
('romeo_and_juliet_act1_scene5',70,73,'CAPULET','An ill-beseeming semblance for a feast.'),
('romeo_and_juliet_act1_scene5',71,74,'TYBALT','It fits, when such a villain is a guest:'),
('romeo_and_juliet_act1_scene5',72,75,'TYBALT','I’ll not endure him.'),
('romeo_and_juliet_act1_scene5',72,76,'CAPULET','He shall be endured:'),
('romeo_and_juliet_act1_scene5',73,77,'CAPULET','What, goodman boy! I say, he shall: go to;'),
('romeo_and_juliet_act1_scene5',74,78,'CAPULET','Am I the master here, or you? go to.'),
('romeo_and_juliet_act1_scene5',75,79,'CAPULET','You’ll not endure him! God shall mend my soul!'),
('romeo_and_juliet_act1_scene5',76,80,'CAPULET','You’ll make a mutiny among my guests!'),
('romeo_and_juliet_act1_scene5',77,81,'CAPULET','You will set cock-a-hoop! you’ll be the man!'),
('romeo_and_juliet_act1_scene5',78,82,'TYBALT','Why, uncle, ’tis a shame.'),
('romeo_and_juliet_act1_scene5',78,83,'CAPULET','Go to, go to;'),
('romeo_and_juliet_act1_scene5',79,84,'CAPULET','You are a saucy boy: is’t so, indeed?'),
('romeo_and_juliet_act1_scene5',80,85,'CAPULET','This trick may chance to scathe you, I know what:'),
('romeo_and_juliet_act1_scene5',81,86,'CAPULET','You must contrary me! marry, ’tis time.'),
('romeo_and_juliet_act1_scene5',82,87,'CAPULET','Well said, my hearts! You are a princox; go:'),
('romeo_and_juliet_act1_scene5',83,88,'CAPULET','Be quiet, or—More light, more light! For shame!'),
('romeo_and_juliet_act1_scene5',84,89,'CAPULET','I’ll make you quiet. What, cheerly, my hearts!'),
('romeo_and_juliet_act1_scene5',85,90,'TYBALT','Patience perforce with wilful choler meeting'),
('romeo_and_juliet_act1_scene5',86,91,'TYBALT','Makes my flesh tremble in their different greeting.'),
('romeo_and_juliet_act1_scene5',87,92,'TYBALT','I will withdraw: but this intrusion shall'),
('romeo_and_juliet_act1_scene5',88,93,'TYBALT','Now seeming sweet convert to bitter gall.'),
('romeo_and_juliet_act1_scene5',89,94,'ROMEO','To Juliet. If I profane with my unworthiest hand'),
('romeo_and_juliet_act1_scene5',90,95,'ROMEO','This holy shrine, the gentle fine is this:'),
('romeo_and_juliet_act1_scene5',91,96,'ROMEO','My lips, two blushing pilgrims, ready stand'),
('romeo_and_juliet_act1_scene5',92,97,'ROMEO','To smooth that rough touch with a tender kiss.'),
('romeo_and_juliet_act1_scene5',93,98,'JULIET','Good pilgrim, you do wrong your hand too much,'),
('romeo_and_juliet_act1_scene5',94,99,'JULIET','Which mannerly devotion shows in this;'),
('romeo_and_juliet_act1_scene5',95,100,'JULIET','For saints have hands that pilgrims’ hands do touch,'),
('romeo_and_juliet_act1_scene5',96,101,'JULIET','And palm to palm is holy palmers’ kiss.'),
('romeo_and_juliet_act1_scene5',97,102,'ROMEO','Have not saints lips, and holy palmers too?'),
('romeo_and_juliet_act1_scene5',98,103,'JULIET','Ay, pilgrim, lips that they must use in prayer.'),
('romeo_and_juliet_act1_scene5',99,104,'ROMEO','O, then, dear saint, let lips do what hands do;'),
('romeo_and_juliet_act1_scene5',100,105,'ROMEO','They pray, grant thou, lest faith turn to despair.'),
('romeo_and_juliet_act1_scene5',101,106,'JULIET','Saints do not move, though grant for prayers’ sake.'),
('romeo_and_juliet_act1_scene5',102,107,'ROMEO','Then move not, while my prayer’s effect I take.'),
('romeo_and_juliet_act1_scene5',103,108,'ROMEO','Thus from my lips, by yours, my sin is purged.'),
('romeo_and_juliet_act1_scene5',104,109,'JULIET','Then have my lips the sin that they have took.'),
('romeo_and_juliet_act1_scene5',105,110,'ROMEO','Sin from thy lips? O trespass sweetly urged!'),
('romeo_and_juliet_act1_scene5',106,111,'ROMEO','Give me my sin again.'),
('romeo_and_juliet_act1_scene5',106,112,'JULIET','You kiss by the book.'),
('romeo_and_juliet_act1_scene5',107,113,'NURSE','Madam, your mother craves a word with you.'),
('romeo_and_juliet_act1_scene5',108,114,'ROMEO','What is her mother?'),
('romeo_and_juliet_act1_scene5',108,115,'NURSE','Marry, bachelor,'),
('romeo_and_juliet_act1_scene5',109,116,'NURSE','Her mother is the lady of the house,'),
('romeo_and_juliet_act1_scene5',110,117,'NURSE','And a good lady, and a wise and virtuous:'),
('romeo_and_juliet_act1_scene5',111,118,'NURSE','I nursed her daughter, that you talk’d withal;'),
('romeo_and_juliet_act1_scene5',112,119,'NURSE','I tell you, he that can lay hold of her'),
('romeo_and_juliet_act1_scene5',113,120,'NURSE','Shall have the chinks.'),
('romeo_and_juliet_act1_scene5',113,121,'ROMEO','Is she a Capulet?'),
('romeo_and_juliet_act1_scene5',114,122,'ROMEO','O dear account! my life is my foe’s debt.'),
('romeo_and_juliet_act1_scene5',115,123,'BENVOLIO','Away, be gone; the sport is at the best.'),
('romeo_and_juliet_act1_scene5',116,124,'ROMEO','Ay, so I fear; the more is my unrest.'),
('romeo_and_juliet_act1_scene5',117,125,'CAPULET','Nay, gentlemen, prepare not to be gone;'),
('romeo_and_juliet_act1_scene5',118,126,'CAPULET','We have a trifling foolish banquet towards.'),
('romeo_and_juliet_act1_scene5',119,127,'CAPULET','Is it e’en so? why, then, I thank you all;'),
('romeo_and_juliet_act1_scene5',120,128,'CAPULET','I thank you, honest gentlemen; good night.'),
('romeo_and_juliet_act1_scene5',121,129,'CAPULET','More torches here! Come on then, let’s to bed.'),
('romeo_and_juliet_act1_scene5',122,130,'CAPULET','Ah, sirrah, by my fay, it waxes late:'),
('romeo_and_juliet_act1_scene5',123,131,'CAPULET','I’ll to my rest.'),
('romeo_and_juliet_act1_scene5',124,132,'JULIET','Come hither, nurse. What is yond gentleman?'),
('romeo_and_juliet_act1_scene5',125,133,'NURSE','The son and heir of old Tiberio.'),
('romeo_and_juliet_act1_scene5',126,134,'JULIET','What’s he that now is going out of door?'),
('romeo_and_juliet_act1_scene5',127,135,'NURSE','Marry, that, I think, be young Petrucio.'),
('romeo_and_juliet_act1_scene5',128,136,'JULIET','What’s he that follows there, that would not dance?'),
('romeo_and_juliet_act1_scene5',129,137,'NURSE','I know not.'),
('romeo_and_juliet_act1_scene5',130,138,'JULIET','Go ask his name: if he be married,'),
('romeo_and_juliet_act1_scene5',131,139,'JULIET','My grave is like to be my wedding bed.'),
('romeo_and_juliet_act1_scene5',132,140,'NURSE','His name is Romeo, and a Montague;'),
('romeo_and_juliet_act1_scene5',133,141,'NURSE','The only son of your great enemy.'),
('romeo_and_juliet_act1_scene5',134,142,'JULIET','My only love sprung from my only hate!'),
('romeo_and_juliet_act1_scene5',135,143,'JULIET','Too early seen unknown, and known too late!'),
('romeo_and_juliet_act1_scene5',136,144,'JULIET','Prodigious birth of love it is to me,'),
('romeo_and_juliet_act1_scene5',137,145,'JULIET','That I must love a loathed enemy.'),
('romeo_and_juliet_act1_scene5',138,146,'NURSE','What’s this? what’s this?'),
('romeo_and_juliet_act1_scene5',138,147,'JULIET','A rhyme I learn’d even now'),
('romeo_and_juliet_act1_scene5',139,148,'JULIET','Of one I danced withal. One calls within “Juliet.”'),
('romeo_and_juliet_act1_scene5',140,149,'NURSE','Anon, anon!'),
('romeo_and_juliet_act1_scene5',141,150,'NURSE','Come, let’s away; the strangers all are gone.'),
('romeo_and_juliet_act2_chorus',1,0,'CHORUS','Now old desire doth in his death-bed lie,'),
('romeo_and_juliet_act2_chorus',2,1,'CHORUS','And young affection gapes to be his heir;'),
('romeo_and_juliet_act2_chorus',3,2,'CHORUS','That fair for which love groan’d for and would die,'),
('romeo_and_juliet_act2_chorus',4,3,'CHORUS','With tender Juliet match’d, is now not fair.'),
('romeo_and_juliet_act2_chorus',5,4,'CHORUS','Now Romeo is beloved and loves again,'),
('romeo_and_juliet_act2_chorus',6,5,'CHORUS','Alike betwitched by the charm of looks,'),
('romeo_and_juliet_act2_chorus',7,6,'CHORUS','But to his foe supposed he must complain,'),
('romeo_and_juliet_act2_chorus',8,7,'CHORUS','And she steal love’s sweet bait from fearful hooks:'),
('romeo_and_juliet_act2_chorus',9,8,'CHORUS','Being held a foe, he may not have access'),
('romeo_and_juliet_act2_chorus',10,9,'CHORUS','To breathe such vows as lovers use to swear;'),
('romeo_and_juliet_act2_chorus',11,10,'CHORUS','And she as much in love, her means much less'),
('romeo_and_juliet_act2_chorus',12,11,'CHORUS','To meet her new-beloved any where:'),
('romeo_and_juliet_act2_chorus',13,12,'CHORUS','But passion lends them power, time means, to meet,'),
('romeo_and_juliet_act2_chorus',14,13,'CHORUS','Tempering extremities with extreme sweet.'),
('romeo_and_juliet_act2_scene1',1,0,'ROMEO','Can I go forward when my heart is here?'),
('romeo_and_juliet_act2_scene1',2,1,'ROMEO','Turn back, dull earth, and find thy centre out. He climbs the wall, and leaps down within it.'),
('romeo_and_juliet_act2_scene1',3,2,'BENVOLIO','Romeo! my cousin Romeo!'),
('romeo_and_juliet_act2_scene1',3,3,'MERCUTIO','He is wise;'),
('romeo_and_juliet_act2_scene1',4,4,'MERCUTIO','And, on my lie, hath stol’n him home to bed.'),
('romeo_and_juliet_act2_scene1',5,5,'BENVOLIO','He ran this way, and leap’d this orchard wall:'),
('romeo_and_juliet_act2_scene1',6,6,'BENVOLIO','Call, good Mercutio.'),
('romeo_and_juliet_act2_scene1',6,7,'MERCUTIO','Nay, I’ll conjure too.'),
('romeo_and_juliet_act2_scene1',7,8,'MERCUTIO','Romeo! humours! madman! passion! lover!'),
('romeo_and_juliet_act2_scene1',8,9,'MERCUTIO','Appear thou in the likeness of a sigh:'),
('romeo_and_juliet_act2_scene1',9,10,'MERCUTIO','Speak but one rhyme, and I am satisfied;'),
('romeo_and_juliet_act2_scene1',10,11,'MERCUTIO','Cry but “Ay me!” pronounce but “love” and “dove;”'),
('romeo_and_juliet_act2_scene1',11,12,'MERCUTIO','Speak to my gossip Venus one fair word,'),
('romeo_and_juliet_act2_scene1',12,13,'MERCUTIO','One nick-name for her purblind son and heir,'),
('romeo_and_juliet_act2_scene1',13,14,'MERCUTIO','Young Adam Cupid, he that shot so trim,'),
('romeo_and_juliet_act2_scene1',14,15,'MERCUTIO','When King Cophetua loved the beggar-maid!'),
('romeo_and_juliet_act2_scene1',15,16,'MERCUTIO','He heareth not, he stirreth not, he moveth not;'),
('romeo_and_juliet_act2_scene1',16,17,'MERCUTIO','The ape is dead, and I must conjure him.'),
('romeo_and_juliet_act2_scene1',17,18,'MERCUTIO','I conjure thee by Rosaline’s bright eyes,'),
('romeo_and_juliet_act2_scene1',18,19,'MERCUTIO','By her high forehead and her scarlet lip,'),
('romeo_and_juliet_act2_scene1',19,20,'MERCUTIO','By her fine foot, straight leg and quivering thigh'),
('romeo_and_juliet_act2_scene1',20,21,'MERCUTIO','And the demesnes that there adjacent lie,'),
('romeo_and_juliet_act2_scene1',21,22,'MERCUTIO','That in thy likeness thou appear to us!'),
('romeo_and_juliet_act2_scene1',22,23,'BENVOLIO','And if he hear thee, thou wilt anger him.'),
('romeo_and_juliet_act2_scene1',23,24,'MERCUTIO','This cannot anger him: ’twould anger him'),
('romeo_and_juliet_act2_scene1',24,25,'MERCUTIO','To raise a spirit in his mistress’ circle'),
('romeo_and_juliet_act2_scene1',25,26,'MERCUTIO','Of some strange nature, letting it there stand'),
('romeo_and_juliet_act2_scene1',26,27,'MERCUTIO','Till she had laid it and conjured it down;'),
('romeo_and_juliet_act2_scene1',27,28,'MERCUTIO','That were some spite: my invocation'),
('romeo_and_juliet_act2_scene1',28,29,'MERCUTIO','Is fair and honest, and in his mistress’ name'),
('romeo_and_juliet_act2_scene1',29,30,'MERCUTIO','I conjure only but to raise up him.'),
('romeo_and_juliet_act2_scene1',30,31,'BENVOLIO','Come, he hath hid himself among these trees,'),
('romeo_and_juliet_act2_scene1',31,32,'BENVOLIO','To be consorted with the humorous night:'),
('romeo_and_juliet_act2_scene1',32,33,'BENVOLIO','Blind is his love and best befits the dark.'),
('romeo_and_juliet_act2_scene1',33,34,'MERCUTIO','If love be blind, love cannot hit the mark.'),
('romeo_and_juliet_act2_scene1',34,35,'MERCUTIO','Now will he sit under a medlar tree,'),
('romeo_and_juliet_act2_scene1',35,36,'MERCUTIO','And wish his mistress were that kind of fruit'),
('romeo_and_juliet_act2_scene1',36,37,'MERCUTIO','As maids call medlars, when they laugh alone.'),
('romeo_and_juliet_act2_scene1',37,38,'MERCUTIO','O, Romeo, that she were, O, that she were'),
('romeo_and_juliet_act2_scene1',38,39,'MERCUTIO','An open-arse, thou a pop’rin pear!'),
('romeo_and_juliet_act2_scene1',39,40,'MERCUTIO','Romeo, good night: I’ll to my truckle-bed;'),
('romeo_and_juliet_act2_scene1',40,41,'MERCUTIO','This field-bed is too cold for me to sleep:'),
('romeo_and_juliet_act2_scene1',41,42,'MERCUTIO','Come, shall we go?'),
('romeo_and_juliet_act2_scene1',41,43,'BENVOLIO','Go, then; for ’tis in vain'),
('romeo_and_juliet_act2_scene1',42,44,'BENVOLIO','To seek him here that means not to be found.'),
('romeo_and_juliet_act2_scene2',1,0,'ROMEO','He jests at scars that never felt a wound. Juliet appears above at a window.'),
('romeo_and_juliet_act2_scene2',2,1,'ROMEO','But, soft! what light through yonder window breaks?'),
('romeo_and_juliet_act2_scene2',3,2,'ROMEO','It is the east, and Juliet is the sun.'),
('romeo_and_juliet_act2_scene2',4,3,'ROMEO','Arise, fair sun, and kill the envious moon,'),
('romeo_and_juliet_act2_scene2',5,4,'ROMEO','Who is already sick and pale with grief,'),
('romeo_and_juliet_act2_scene2',6,5,'ROMEO','That thou her maid art far more fair than she:'),
('romeo_and_juliet_act2_scene2',7,6,'ROMEO','Be not her maid, since she is envious;'),
('romeo_and_juliet_act2_scene2',8,7,'ROMEO','Her vestal livery is but sick and green'),
('romeo_and_juliet_act2_scene2',9,8,'ROMEO','And none but fools do wear it; cast it off.'),
('romeo_and_juliet_act2_scene2',10,9,'ROMEO','It is my lady, O, it is my love!'),
('romeo_and_juliet_act2_scene2',11,10,'ROMEO','O, that she knew she were!'),
('romeo_and_juliet_act2_scene2',12,11,'ROMEO','She speaks, yet she says nothing: what of that?'),
('romeo_and_juliet_act2_scene2',13,12,'ROMEO','Her eye discourses; I will answer it.'),
('romeo_and_juliet_act2_scene2',14,13,'ROMEO','I am too bold, ’tis not to me she speaks:'),
('romeo_and_juliet_act2_scene2',15,14,'ROMEO','Two of the fairest stars in all the heaven,'),
('romeo_and_juliet_act2_scene2',16,15,'ROMEO','Having some business, do entreat her eyes'),
('romeo_and_juliet_act2_scene2',17,16,'ROMEO','To twinkle in their spheres till they return.'),
('romeo_and_juliet_act2_scene2',18,17,'ROMEO','What if her eyes were there, they in her head?'),
('romeo_and_juliet_act2_scene2',19,18,'ROMEO','The brightness of her cheek would shame those stars,'),
('romeo_and_juliet_act2_scene2',20,19,'ROMEO','As daylight doth a lamp; her eyes in heaven'),
('romeo_and_juliet_act2_scene2',21,20,'ROMEO','Would through the airy region stream so bright'),
('romeo_and_juliet_act2_scene2',22,21,'ROMEO','That birds would sing and think it were not night.'),
('romeo_and_juliet_act2_scene2',23,22,'ROMEO','See, how she leans her cheek upon her hand!'),
('romeo_and_juliet_act2_scene2',24,23,'ROMEO','O, that I were a glove upon that hand,'),
('romeo_and_juliet_act2_scene2',25,24,'ROMEO','That I might touch that cheek!'),
('romeo_and_juliet_act2_scene2',25,25,'JULIET','Ay me!'),
('romeo_and_juliet_act2_scene2',26,26,'ROMEO','She speaks:'),
('romeo_and_juliet_act2_scene2',27,27,'ROMEO','O, speak again, bright angel! for thou art'),
('romeo_and_juliet_act2_scene2',28,28,'ROMEO','As glorious to this night, being o’er my head,'),
('romeo_and_juliet_act2_scene2',29,29,'ROMEO','As is a winged messenger of heaven'),
('romeo_and_juliet_act2_scene2',30,30,'ROMEO','Unto the white-upturned wondering eyes');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('romeo_and_juliet_act2_scene2',31,31,'ROMEO','Of mortals that fall back to gaze on him'),
('romeo_and_juliet_act2_scene2',32,32,'ROMEO','When he bestrides the lazy-pacing clouds'),
('romeo_and_juliet_act2_scene2',33,33,'ROMEO','And sails upon the bosom of the air.'),
('romeo_and_juliet_act2_scene2',34,34,'JULIET','O Romeo, Romeo! wherefore art thou Romeo?'),
('romeo_and_juliet_act2_scene2',35,35,'JULIET','Deny thy father and refuse thy name;'),
('romeo_and_juliet_act2_scene2',36,36,'JULIET','Or, if thou wilt not, be but sworn my love,'),
('romeo_and_juliet_act2_scene2',37,37,'JULIET','And I’ll no longer be a Capulet.'),
('romeo_and_juliet_act2_scene2',38,38,'ROMEO','Shall I hear more, or shall I speak at this?'),
('romeo_and_juliet_act2_scene2',39,39,'JULIET','’Tis but thy name that is my enemy;'),
('romeo_and_juliet_act2_scene2',40,40,'JULIET','Thou art thyself, though not a Montague.'),
('romeo_and_juliet_act2_scene2',41,41,'JULIET','What’s Montague? it is nor hand, nor foot,'),
('romeo_and_juliet_act2_scene2',42,42,'JULIET','Nor arm, nor face, nor any other part'),
('romeo_and_juliet_act2_scene2',43,43,'JULIET','Belonging to a man. O, be some other name!'),
('romeo_and_juliet_act2_scene2',44,44,'JULIET','What’s in a name? that which we call a rose'),
('romeo_and_juliet_act2_scene2',45,45,'JULIET','By any other name would smell as sweet;'),
('romeo_and_juliet_act2_scene2',46,46,'JULIET','So Romeo would, were he not Romeo call’d,'),
('romeo_and_juliet_act2_scene2',47,47,'JULIET','Retain that dear perfection which he owes'),
('romeo_and_juliet_act2_scene2',48,48,'JULIET','Without that title. Romeo, doff thy name,'),
('romeo_and_juliet_act2_scene2',49,49,'JULIET','And for that name which is no part of thee'),
('romeo_and_juliet_act2_scene2',50,50,'JULIET','Take all myself.'),
('romeo_and_juliet_act2_scene2',50,51,'ROMEO','I take thee at thy word:'),
('romeo_and_juliet_act2_scene2',51,52,'ROMEO','Call me but love, and I’ll be new baptized;'),
('romeo_and_juliet_act2_scene2',52,53,'ROMEO','Henceforth I never will be Romeo.'),
('romeo_and_juliet_act2_scene2',53,54,'JULIET','What man art thou that thus bescreen’d in night'),
('romeo_and_juliet_act2_scene2',54,55,'JULIET','So stumblest on my counsel?'),
('romeo_and_juliet_act2_scene2',54,56,'ROMEO','By a name'),
('romeo_and_juliet_act2_scene2',55,57,'ROMEO','I know not how to tell thee who I am:'),
('romeo_and_juliet_act2_scene2',56,58,'ROMEO','My name, dear saint, is hateful to myself,'),
('romeo_and_juliet_act2_scene2',57,59,'ROMEO','Because it is an enemy to thee;'),
('romeo_and_juliet_act2_scene2',58,60,'ROMEO','Had I it written, I would tear the word.'),
('romeo_and_juliet_act2_scene2',59,61,'JULIET','My ears have not yet drunk a hundred words'),
('romeo_and_juliet_act2_scene2',60,62,'JULIET','Of that tongue’s utterance, yet I know the sound:'),
('romeo_and_juliet_act2_scene2',61,63,'JULIET','Art thou not Romeo and a Montague?'),
('romeo_and_juliet_act2_scene2',62,64,'ROMEO','Neither, fair saint, if either thee dislike.'),
('romeo_and_juliet_act2_scene2',63,65,'JULIET','How camest thou hither, tell me, and wherefore?'),
('romeo_and_juliet_act2_scene2',64,66,'JULIET','The orchard walls are high and hard to climb,'),
('romeo_and_juliet_act2_scene2',65,67,'JULIET','And the place death, considering who thou art,'),
('romeo_and_juliet_act2_scene2',66,68,'JULIET','If any of my kinsmen find thee here.'),
('romeo_and_juliet_act2_scene2',67,69,'ROMEO','With love’s light wings did I o’er-perch these walls;'),
('romeo_and_juliet_act2_scene2',68,70,'ROMEO','For stony limits cannot hold love out,'),
('romeo_and_juliet_act2_scene2',69,71,'ROMEO','And what love can do that dares love attempt;'),
('romeo_and_juliet_act2_scene2',70,72,'ROMEO','Therefore thy kinsmen are no let to me.'),
('romeo_and_juliet_act2_scene2',71,73,'JULIET','If they do see thee, they will murder thee.'),
('romeo_and_juliet_act2_scene2',72,74,'ROMEO','Alack, there lies more peril in thine eye'),
('romeo_and_juliet_act2_scene2',73,75,'ROMEO','Than twenty of their swords: look thou but sweet,'),
('romeo_and_juliet_act2_scene2',74,76,'ROMEO','And I am proof against their enmity.'),
('romeo_and_juliet_act2_scene2',75,77,'JULIET','I would not for the world they saw thee here.'),
('romeo_and_juliet_act2_scene2',76,78,'ROMEO','I have night’s cloak to hide me from their sight;'),
('romeo_and_juliet_act2_scene2',77,79,'ROMEO','And but thou love me, let them find me here:'),
('romeo_and_juliet_act2_scene2',78,80,'ROMEO','My life were better ended by their hate,'),
('romeo_and_juliet_act2_scene2',79,81,'ROMEO','Than death prorogued, wanting of thy love.'),
('romeo_and_juliet_act2_scene2',80,82,'JULIET','By whose direction found’st thou out this place?'),
('romeo_and_juliet_act2_scene2',81,83,'ROMEO','By love, who first did prompt me to inquire;'),
('romeo_and_juliet_act2_scene2',82,84,'ROMEO','He lent me counsel and I lent him eyes.'),
('romeo_and_juliet_act2_scene2',83,85,'ROMEO','I am no pilot; yet, wert thou as far'),
('romeo_and_juliet_act2_scene2',84,86,'ROMEO','As that vast shore wash’d with the farthest sea,'),
('romeo_and_juliet_act2_scene2',85,87,'ROMEO','I would adventure for such merchandise.'),
('romeo_and_juliet_act2_scene2',86,88,'JULIET','Thou know’st the mask of night is on my face,'),
('romeo_and_juliet_act2_scene2',87,89,'JULIET','Else would a maiden blush bepaint my cheek'),
('romeo_and_juliet_act2_scene2',88,90,'JULIET','For that which thou hast heard me speak to-night.'),
('romeo_and_juliet_act2_scene2',89,91,'JULIET','Fain would I dwell on form, fain, fain deny'),
('romeo_and_juliet_act2_scene2',90,92,'JULIET','What I have spoke: but farewell compliment!'),
('romeo_and_juliet_act2_scene2',91,93,'JULIET','Dost thou love me? I know thou wilt say “Ay,”'),
('romeo_and_juliet_act2_scene2',92,94,'JULIET','And I will take thy word: yet, if thou swear’st,'),
('romeo_and_juliet_act2_scene2',93,95,'JULIET','Thou mayst prove false; at lovers’ perjuries,'),
('romeo_and_juliet_act2_scene2',94,96,'JULIET','They say, Jove laughs. O gentle Romeo,'),
('romeo_and_juliet_act2_scene2',95,97,'JULIET','If thou dost love, pronounce it faithfully:'),
('romeo_and_juliet_act2_scene2',96,98,'JULIET','Or if thou think’st I am too quickly won,'),
('romeo_and_juliet_act2_scene2',97,99,'JULIET','I’ll frown and be perverse and say thee nay,'),
('romeo_and_juliet_act2_scene2',98,100,'JULIET','So thou wilt woo; but else, not for the world.'),
('romeo_and_juliet_act2_scene2',99,101,'JULIET','In truth, fair Montague, I am too fond,'),
('romeo_and_juliet_act2_scene2',100,102,'JULIET','And therefore thou mayst think my ’havior light;'),
('romeo_and_juliet_act2_scene2',101,103,'JULIET','But trust me, gentleman, I’ll prove more true'),
('romeo_and_juliet_act2_scene2',102,104,'JULIET','Than those that have more cunning to be strange.'),
('romeo_and_juliet_act2_scene2',103,105,'JULIET','I should have been more strange, I must confess,'),
('romeo_and_juliet_act2_scene2',104,106,'JULIET','But that thou overheard’st, ere I was ware,'),
('romeo_and_juliet_act2_scene2',105,107,'JULIET','My true love’s passion: therefore pardon me,'),
('romeo_and_juliet_act2_scene2',106,108,'JULIET','And not impute this yielding to light love,'),
('romeo_and_juliet_act2_scene2',107,109,'JULIET','Which the dark night hath so discovered.'),
('romeo_and_juliet_act2_scene2',108,110,'ROMEO','Lady, by yonder blessed moon I swear'),
('romeo_and_juliet_act2_scene2',109,111,'ROMEO','That tips with silver all these fruit-tree tops—'),
('romeo_and_juliet_act2_scene2',110,112,'JULIET','O, swear not by the moon, the inconstant moon,'),
('romeo_and_juliet_act2_scene2',111,113,'JULIET','That monthly changes in her circled orb,'),
('romeo_and_juliet_act2_scene2',112,114,'JULIET','Lest that thy love prove likewise variable.'),
('romeo_and_juliet_act2_scene2',113,115,'ROMEO','What shall I swear by?'),
('romeo_and_juliet_act2_scene2',113,116,'JULIET','Do not swear at all;'),
('romeo_and_juliet_act2_scene2',114,117,'JULIET','Or, if thou wilt, swear by thy gracious self,'),
('romeo_and_juliet_act2_scene2',115,118,'JULIET','Which is the god of my idolatry,'),
('romeo_and_juliet_act2_scene2',116,119,'JULIET','And I’ll believe thee.'),
('romeo_and_juliet_act2_scene2',116,120,'ROMEO','If my heart’s dear love—'),
('romeo_and_juliet_act2_scene2',117,121,'JULIET','Well, do not swear: although I joy in thee,'),
('romeo_and_juliet_act2_scene2',118,122,'JULIET','I have no joy of this contract to-night:'),
('romeo_and_juliet_act2_scene2',119,123,'JULIET','It is too rash, too unadvised, too sudden;'),
('romeo_and_juliet_act2_scene2',120,124,'JULIET','Too like the lightning, which doth cease to be'),
('romeo_and_juliet_act2_scene2',121,125,'JULIET','Ere one can say “It lightens.” Sweet, good night!'),
('romeo_and_juliet_act2_scene2',122,126,'JULIET','This bud of love, by summer’s ripening breath,'),
('romeo_and_juliet_act2_scene2',123,127,'JULIET','May prove a beauteous flower when next we meet.'),
('romeo_and_juliet_act2_scene2',124,128,'JULIET','Good night, good night! as sweet repose and rest'),
('romeo_and_juliet_act2_scene2',125,129,'JULIET','Come to thy heart as that within my breast!'),
('romeo_and_juliet_act2_scene2',126,130,'ROMEO','O, wilt thou leave me so unsatisfied?'),
('romeo_and_juliet_act2_scene2',127,131,'JULIET','What satisfaction canst thou have to-night?'),
('romeo_and_juliet_act2_scene2',128,132,'ROMEO','The exchange of thy love’s faithful vow for mine.'),
('romeo_and_juliet_act2_scene2',129,133,'JULIET','I gave thee mine before thou didst request it:'),
('romeo_and_juliet_act2_scene2',130,134,'JULIET','And yet I would it were to give again.'),
('romeo_and_juliet_act2_scene2',131,135,'ROMEO','Wouldst thou withdraw it? for what purpose, love?'),
('romeo_and_juliet_act2_scene2',132,136,'JULIET','But to be frank, and give it thee again.'),
('romeo_and_juliet_act2_scene2',133,137,'JULIET','And yet I wish but for the thing I have:'),
('romeo_and_juliet_act2_scene2',134,138,'JULIET','My bounty is as boundless as the sea,'),
('romeo_and_juliet_act2_scene2',135,139,'JULIET','My love as deep; the more I give to thee,'),
('romeo_and_juliet_act2_scene2',136,140,'JULIET','The more I have, for both are infinite. Nurse calls within.'),
('romeo_and_juliet_act2_scene2',137,141,'JULIET','I hear some noise within; dear love, adieu!'),
('romeo_and_juliet_act2_scene2',138,142,'JULIET','Anon, good nurse! Sweet Montague, be true.'),
('romeo_and_juliet_act2_scene2',139,143,'JULIET','Stay but a little, I will come again.'),
('romeo_and_juliet_act2_scene2',140,144,'ROMEO','O blessed, blessed night! I am afeard,'),
('romeo_and_juliet_act2_scene2',141,145,'ROMEO','Being in night, all this is but a dream,'),
('romeo_and_juliet_act2_scene2',142,146,'ROMEO','Too flattering-sweet to be substantial.'),
('romeo_and_juliet_act2_scene2',143,147,'JULIET','Three words, dear Romeo, and good night indeed.'),
('romeo_and_juliet_act2_scene2',144,148,'JULIET','If that thy bent of love be honourable,'),
('romeo_and_juliet_act2_scene2',145,149,'JULIET','Thy purpose marriage, send me word to-morrow,'),
('romeo_and_juliet_act2_scene2',146,150,'JULIET','By one that I’ll procure to come to thee,'),
('romeo_and_juliet_act2_scene2',147,151,'JULIET','Where and what time thou wilt perform the rite;'),
('romeo_and_juliet_act2_scene2',148,152,'JULIET','And all my fortunes at thy foot I’ll lay'),
('romeo_and_juliet_act2_scene2',149,153,'JULIET','And follow thee my lord throughout the world.'),
('romeo_and_juliet_act2_scene2',150,154,'NURSE','Madam!'),
('romeo_and_juliet_act2_scene2',151,155,'JULIET','I come, anon.—But if thou mean’st not well,'),
('romeo_and_juliet_act2_scene2',152,156,'JULIET','I do beseech thee—'),
('romeo_and_juliet_act2_scene2',152,157,'NURSE','Madam!'),
('romeo_and_juliet_act2_scene2',153,158,'JULIET','By and by, I come:—'),
('romeo_and_juliet_act2_scene2',154,159,'JULIET','To cease thy suit, and leave me to my grief:'),
('romeo_and_juliet_act2_scene2',155,160,'JULIET','To-morrow will I send.'),
('romeo_and_juliet_act2_scene2',155,161,'ROMEO','So thrive my soul—'),
('romeo_and_juliet_act2_scene2',156,162,'JULIET','A thousand times good night!'),
('romeo_and_juliet_act2_scene2',157,163,'ROMEO','A thousand times the worse, to want thy light.'),
('romeo_and_juliet_act2_scene2',158,164,'ROMEO','Love goes toward love, as schoolboys from their books,'),
('romeo_and_juliet_act2_scene2',159,165,'ROMEO','But love from love, toward school with heavy looks. Retiring.'),
('romeo_and_juliet_act2_scene2',160,166,'JULIET','Hist! Romeo, hist! O, for a falconer’s voice,'),
('romeo_and_juliet_act2_scene2',161,167,'JULIET','To lure this tassel-gentle back again!'),
('romeo_and_juliet_act2_scene2',162,168,'JULIET','Bondage is hoarse, and may not speak aloud;'),
('romeo_and_juliet_act2_scene2',163,169,'JULIET','Else would I tear the cave where Echo lies,'),
('romeo_and_juliet_act2_scene2',164,170,'JULIET','And make her airy tongue more hoarse than mine,'),
('romeo_and_juliet_act2_scene2',165,171,'JULIET','With repetition of my Romeo’s name.'),
('romeo_and_juliet_act2_scene2',166,172,'ROMEO','It is my soul that calls upon my name:'),
('romeo_and_juliet_act2_scene2',167,173,'ROMEO','How silver-sweet sound lovers’ tongues by night,'),
('romeo_and_juliet_act2_scene2',168,174,'ROMEO','Like softest music to attending ears!'),
('romeo_and_juliet_act2_scene2',168,175,'JULIET','Romeo!'),
('romeo_and_juliet_act2_scene2',169,176,'ROMEO','My dear?'),
('romeo_and_juliet_act2_scene2',169,177,'JULIET','At what o’clock to-morrow'),
('romeo_and_juliet_act2_scene2',170,178,'JULIET','Shall I send to thee?'),
('romeo_and_juliet_act2_scene2',170,179,'ROMEO','At the hour of nine.'),
('romeo_and_juliet_act2_scene2',171,180,'JULIET','I will not fail: ’tis twenty years till then.'),
('romeo_and_juliet_act2_scene2',172,181,'JULIET','I have forgot why I did call thee back.'),
('romeo_and_juliet_act2_scene2',173,182,'ROMEO','Let me stand here till thou remember it.'),
('romeo_and_juliet_act2_scene2',174,183,'JULIET','I shall forget, to have thee still stand there,'),
('romeo_and_juliet_act2_scene2',175,184,'JULIET','Remembering how I love thy company.'),
('romeo_and_juliet_act2_scene2',176,185,'ROMEO','And I’ll still stay, to have thee still forget,'),
('romeo_and_juliet_act2_scene2',177,186,'ROMEO','Forgetting any other home but this.'),
('romeo_and_juliet_act2_scene2',178,187,'JULIET','’Tis almost morning; I would have thee gone:'),
('romeo_and_juliet_act2_scene2',179,188,'JULIET','And yet no further than a wanton’s bird;'),
('romeo_and_juliet_act2_scene2',180,189,'JULIET','Who lets it hop a little from her hand,'),
('romeo_and_juliet_act2_scene2',181,190,'JULIET','Like a poor prisoner in his twisted gyves,'),
('romeo_and_juliet_act2_scene2',182,191,'JULIET','And with a silk thread plucks it back again,'),
('romeo_and_juliet_act2_scene2',183,192,'JULIET','So loving-jealous of his liberty.'),
('romeo_and_juliet_act2_scene2',183,193,'ROMEO','I would I were thy bird.'),
('romeo_and_juliet_act2_scene2',184,194,'JULIET','Sweet, so would I:'),
('romeo_and_juliet_act2_scene2',185,195,'JULIET','Yet I should kill thee with much cherishing.'),
('romeo_and_juliet_act2_scene2',186,196,'JULIET','Good night, good night! parting is such sweet sorrow,'),
('romeo_and_juliet_act2_scene2',187,197,'JULIET','That I shall say good night till it be morrow.'),
('romeo_and_juliet_act2_scene2',188,198,'ROMEO','Sleep dwell upon thine eyes, peace in thy breast!'),
('romeo_and_juliet_act2_scene2',189,199,'ROMEO','Would I were sleep and peace, so sweet to rest!'),
('romeo_and_juliet_act2_scene2',190,200,'ROMEO','Hence will I to my ghostly father’s cell,'),
('romeo_and_juliet_act2_scene2',191,201,'ROMEO','His help to crave, and my dear hap to tell.'),
('romeo_and_juliet_act2_scene3',1,0,'FRIAR LAURENCE','The grey-eyed morn smiles on the frowning night,'),
('romeo_and_juliet_act2_scene3',2,1,'FRIAR LAURENCE','Chequering the eastern clouds with streaks of light,'),
('romeo_and_juliet_act2_scene3',3,2,'FRIAR LAURENCE','And flecked darkness like a drunkard reels'),
('romeo_and_juliet_act2_scene3',4,3,'FRIAR LAURENCE','From forth day’s path and Titan’s fiery wheels:'),
('romeo_and_juliet_act2_scene3',5,4,'FRIAR LAURENCE','Now, ere the sun advance his burning eye,'),
('romeo_and_juliet_act2_scene3',6,5,'FRIAR LAURENCE','The day to cheer and night’s dank dew to dry,'),
('romeo_and_juliet_act2_scene3',7,6,'FRIAR LAURENCE','I must up-fill this osier cage of ours'),
('romeo_and_juliet_act2_scene3',8,7,'FRIAR LAURENCE','With baleful weeds and precious-juiced flowers.'),
('romeo_and_juliet_act2_scene3',9,8,'FRIAR LAURENCE','The earth that’s nature’s mother is her tomb;'),
('romeo_and_juliet_act2_scene3',10,9,'FRIAR LAURENCE','What is her burying grave that is her womb,'),
('romeo_and_juliet_act2_scene3',11,10,'FRIAR LAURENCE','And from her womb children of divers kind'),
('romeo_and_juliet_act2_scene3',12,11,'FRIAR LAURENCE','We sucking on her natural bosom find,'),
('romeo_and_juliet_act2_scene3',13,12,'FRIAR LAURENCE','Many for many virtues excellent,'),
('romeo_and_juliet_act2_scene3',14,13,'FRIAR LAURENCE','None but for some and yet all different.'),
('romeo_and_juliet_act2_scene3',15,14,'FRIAR LAURENCE','O, mickle is the powerful grace that lies'),
('romeo_and_juliet_act2_scene3',16,15,'FRIAR LAURENCE','In herbs, plants, stones, and their true qualities:'),
('romeo_and_juliet_act2_scene3',17,16,'FRIAR LAURENCE','For nought so vile that on the earth doth live'),
('romeo_and_juliet_act2_scene3',18,17,'FRIAR LAURENCE','But to the earth some special good doth give,'),
('romeo_and_juliet_act2_scene3',19,18,'FRIAR LAURENCE','Nor aught so good but strain’d from that fair use'),
('romeo_and_juliet_act2_scene3',20,19,'FRIAR LAURENCE','Revolts from true birth, stumbling on abuse:'),
('romeo_and_juliet_act2_scene3',21,20,'FRIAR LAURENCE','Virtue itself turns vice, being misapplied;'),
('romeo_and_juliet_act2_scene3',22,21,'FRIAR LAURENCE','And vice sometimes by action dignified.'),
('romeo_and_juliet_act2_scene3',23,22,'FRIAR LAURENCE','Within the infant rind of this small flower'),
('romeo_and_juliet_act2_scene3',24,23,'FRIAR LAURENCE','Poison hath residence and medicine power:'),
('romeo_and_juliet_act2_scene3',25,24,'FRIAR LAURENCE','For this, being smelt, with that part cheers each part;'),
('romeo_and_juliet_act2_scene3',26,25,'FRIAR LAURENCE','Being tasted, slays all senses with the heart.'),
('romeo_and_juliet_act2_scene3',27,26,'FRIAR LAURENCE','Two such opposed kings encamp them still'),
('romeo_and_juliet_act2_scene3',28,27,'FRIAR LAURENCE','In man as well as herbs, grace and rude will;'),
('romeo_and_juliet_act2_scene3',29,28,'FRIAR LAURENCE','And where the worser is predominant,'),
('romeo_and_juliet_act2_scene3',30,29,'FRIAR LAURENCE','Full soon the canker death eats up that plant.'),
('romeo_and_juliet_act2_scene3',31,30,'ROMEO','Good morrow, father.'),
('romeo_and_juliet_act2_scene3',31,31,'FRIAR LAURENCE','Benedicite!'),
('romeo_and_juliet_act2_scene3',32,32,'FRIAR LAURENCE','What early tongue so sweet saluteth me?'),
('romeo_and_juliet_act2_scene3',33,33,'FRIAR LAURENCE','Young son, it argues a distemper’d head'),
('romeo_and_juliet_act2_scene3',34,34,'FRIAR LAURENCE','So soon to bid good morrow to thy bed:'),
('romeo_and_juliet_act2_scene3',35,35,'FRIAR LAURENCE','Care keeps his watch in every old man’s eye,'),
('romeo_and_juliet_act2_scene3',36,36,'FRIAR LAURENCE','And where care lodges, sleep will never lie;'),
('romeo_and_juliet_act2_scene3',37,37,'FRIAR LAURENCE','But where unbruised youth with unstuff’d brain'),
('romeo_and_juliet_act2_scene3',38,38,'FRIAR LAURENCE','Doth couch his limbs, there golden sleep doth reign:'),
('romeo_and_juliet_act2_scene3',39,39,'FRIAR LAURENCE','Therefore thy earliness doth me assure'),
('romeo_and_juliet_act2_scene3',40,40,'FRIAR LAURENCE','Thou art up-roused by some distemperature;'),
('romeo_and_juliet_act2_scene3',41,41,'FRIAR LAURENCE','Or if not so, then here I hit it right,'),
('romeo_and_juliet_act2_scene3',42,42,'FRIAR LAURENCE','Our Romeo hath not been in bed to-night.'),
('romeo_and_juliet_act2_scene3',43,43,'ROMEO','That last is true; the sweeter rest was mine.'),
('romeo_and_juliet_act2_scene3',44,44,'FRIAR LAURENCE','God pardon sin! wast thou with Rosaline?'),
('romeo_and_juliet_act2_scene3',45,45,'ROMEO','With Rosaline, my ghostly father? no;'),
('romeo_and_juliet_act2_scene3',46,46,'ROMEO','I have forgot that name, and that name’s woe.'),
('romeo_and_juliet_act2_scene3',47,47,'FRIAR LAURENCE','That’s my good son: but where hast thou been, then?'),
('romeo_and_juliet_act2_scene3',48,48,'ROMEO','I’ll tell thee, ere thou ask it me again.'),
('romeo_and_juliet_act2_scene3',49,49,'ROMEO','I have been feasting with mine enemy,'),
('romeo_and_juliet_act2_scene3',50,50,'ROMEO','Where on a sudden one hath wounded me,'),
('romeo_and_juliet_act2_scene3',51,51,'ROMEO','That’s by me wounded: both our remedies'),
('romeo_and_juliet_act2_scene3',52,52,'ROMEO','Within thy help and holy physic lies:'),
('romeo_and_juliet_act2_scene3',53,53,'ROMEO','I bear no hatred, blessed man, for, lo,'),
('romeo_and_juliet_act2_scene3',54,54,'ROMEO','My intercession likewise steads my foe.'),
('romeo_and_juliet_act2_scene3',55,55,'FRIAR LAURENCE','Be plain, good son, and homely in thy drift;'),
('romeo_and_juliet_act2_scene3',56,56,'FRIAR LAURENCE','Riddling confession finds but riddling shrift.'),
('romeo_and_juliet_act2_scene3',57,57,'ROMEO','Then plainly know my heart’s dear love is set'),
('romeo_and_juliet_act2_scene3',58,58,'ROMEO','On the fair daughter of rich Capulet:'),
('romeo_and_juliet_act2_scene3',59,59,'ROMEO','As mine on hers, so hers is set on mine;'),
('romeo_and_juliet_act2_scene3',60,60,'ROMEO','And all combined, save what thou must combine'),
('romeo_and_juliet_act2_scene3',61,61,'ROMEO','By holy marriage: when and where and how'),
('romeo_and_juliet_act2_scene3',62,62,'ROMEO','We met, we woo’d and made exchange of vow,'),
('romeo_and_juliet_act2_scene3',63,63,'ROMEO','I’ll tell thee as we pass; but this I pray,'),
('romeo_and_juliet_act2_scene3',64,64,'ROMEO','That thou consent to marry us to-day.'),
('romeo_and_juliet_act2_scene3',65,65,'FRIAR LAURENCE','Holy Saint Francis, what a change is here!'),
('romeo_and_juliet_act2_scene3',66,66,'FRIAR LAURENCE','Is Rosaline, whom thou didst love so dear,'),
('romeo_and_juliet_act2_scene3',67,67,'FRIAR LAURENCE','So soon forsaken? young men’s love then lies'),
('romeo_and_juliet_act2_scene3',68,68,'FRIAR LAURENCE','Not truly in their hearts, but in their eyes.'),
('romeo_and_juliet_act2_scene3',69,69,'FRIAR LAURENCE','Jesu Maria, what a deal of brine'),
('romeo_and_juliet_act2_scene3',70,70,'FRIAR LAURENCE','Hath wash’d thy sallow cheeks for Rosaline!'),
('romeo_and_juliet_act2_scene3',71,71,'FRIAR LAURENCE','How much salt water thrown away in waste,'),
('romeo_and_juliet_act2_scene3',72,72,'FRIAR LAURENCE','To season love, that of it doth not taste!'),
('romeo_and_juliet_act2_scene3',73,73,'FRIAR LAURENCE','The sun not yet thy sighs from heaven clears,'),
('romeo_and_juliet_act2_scene3',74,74,'FRIAR LAURENCE','Thy old groans ring yet in my ancient ears;'),
('romeo_and_juliet_act2_scene3',75,75,'FRIAR LAURENCE','Lo, here upon thy cheek the stain doth sit'),
('romeo_and_juliet_act2_scene3',76,76,'FRIAR LAURENCE','Of an old tear that is not wash’d off yet:'),
('romeo_and_juliet_act2_scene3',77,77,'FRIAR LAURENCE','If e’er thou wast thyself and these woes thine,'),
('romeo_and_juliet_act2_scene3',78,78,'FRIAR LAURENCE','Thou and these woes were all for Rosaline:'),
('romeo_and_juliet_act2_scene3',79,79,'FRIAR LAURENCE','And art thou changed? pronounce this sentence then,'),
('romeo_and_juliet_act2_scene3',80,80,'FRIAR LAURENCE','Women may fall, when there’s no strength in men.'),
('romeo_and_juliet_act2_scene3',81,81,'ROMEO','Thou chid’st me oft for loving Rosaline.'),
('romeo_and_juliet_act2_scene3',82,82,'FRIAR LAURENCE','For doting, not for loving, pupil mine.'),
('romeo_and_juliet_act2_scene3',83,83,'ROMEO','And bad’st me bury love.'),
('romeo_and_juliet_act2_scene3',83,84,'FRIAR LAURENCE','Not in a grave,'),
('romeo_and_juliet_act2_scene3',84,85,'FRIAR LAURENCE','To lay one in, another out to have.'),
('romeo_and_juliet_act2_scene3',85,86,'ROMEO','I pray thee, chide not: she whom I love now'),
('romeo_and_juliet_act2_scene3',86,87,'ROMEO','Doth grace for grace and love for love allow;'),
('romeo_and_juliet_act2_scene3',87,88,'ROMEO','The other did not so.'),
('romeo_and_juliet_act2_scene3',87,89,'FRIAR LAURENCE','O, she knew well'),
('romeo_and_juliet_act2_scene3',88,90,'FRIAR LAURENCE','Thy love did read by rote and could not spell.'),
('romeo_and_juliet_act2_scene3',89,91,'FRIAR LAURENCE','But come, young waverer, come, go with me,'),
('romeo_and_juliet_act2_scene3',90,92,'FRIAR LAURENCE','In one respect I’ll thy assistant be;'),
('romeo_and_juliet_act2_scene3',91,93,'FRIAR LAURENCE','For this alliance may so happy prove,'),
('romeo_and_juliet_act2_scene3',92,94,'FRIAR LAURENCE','To turn your households’ rancour to pure love.'),
('romeo_and_juliet_act2_scene3',93,95,'ROMEO','O, let us hence; I stand on sudden haste.'),
('romeo_and_juliet_act2_scene3',94,96,'FRIAR LAURENCE','Wisely and slow; they stumble that run fast.'),
('romeo_and_juliet_act2_scene4',1,0,'MERCUTIO','Where the devil should this Romeo be?'),
('romeo_and_juliet_act2_scene4',2,1,'MERCUTIO','Came he not home to-night?'),
('romeo_and_juliet_act2_scene4',3,2,'BENVOLIO','Not to his father’s; I spoke with his man.'),
('romeo_and_juliet_act2_scene4',4,3,'MERCUTIO','Ah, that same pale hard-hearted wench, that Rosaline,'),
('romeo_and_juliet_act2_scene4',5,4,'MERCUTIO','Torments him so, that he will sure run mad.'),
('romeo_and_juliet_act2_scene4',6,5,'BENVOLIO','Tybalt, the kinsman of old Capulet,'),
('romeo_and_juliet_act2_scene4',7,6,'BENVOLIO','Hath sent a letter to his father’s house.'),
('romeo_and_juliet_act2_scene4',8,7,'MERCUTIO','A challenge, on my life.'),
('romeo_and_juliet_act2_scene4',8,8,'BENVOLIO','Romeo will answer it.'),
('romeo_and_juliet_act2_scene4',9,9,'MERCUTIO','Any man that can write may answer a letter.'),
('romeo_and_juliet_act2_scene4',10,10,'BENVOLIO','Nay, he will answer the letter’s master, how he dares, being dared.'),
('romeo_and_juliet_act2_scene4',11,11,'MERCUTIO','Alas poor Romeo! he is already dead: stabbed with a white wench’s'),
('romeo_and_juliet_act2_scene4',12,12,'MERCUTIO','black eye; shot thorough the ear with a love-song; the very pin'),
('romeo_and_juliet_act2_scene4',13,13,'MERCUTIO','of his heart cleft with the blind bow-boy’s butt-shaft: and is he'),
('romeo_and_juliet_act2_scene4',14,14,'MERCUTIO','a man to encounter Tybalt?'),
('romeo_and_juliet_act2_scene4',14,15,'BENVOLIO','Why, what is Tybalt?'),
('romeo_and_juliet_act2_scene4',15,16,'MERCUTIO','More than prince of cats, I can tell you. O, he is'),
('romeo_and_juliet_act2_scene4',16,17,'MERCUTIO','the courageous captain of complements. He fights as you sing prick-song, keeps'),
('romeo_and_juliet_act2_scene4',17,18,'MERCUTIO','time, distance, and proportion; rests me his minim rest, one, two, and'),
('romeo_and_juliet_act2_scene4',18,19,'MERCUTIO','the third in your bosom: the very butcher of a silk button,'),
('romeo_and_juliet_act2_scene4',19,20,'MERCUTIO','a duellist, a duellist; a gentleman of the very first house, of'),
('romeo_and_juliet_act2_scene4',20,21,'MERCUTIO','the first and second cause: ah, the immortal passado! the punto reverso!'),
('romeo_and_juliet_act2_scene4',21,22,'MERCUTIO','the hai!'),
('romeo_and_juliet_act2_scene4',21,23,'BENVOLIO','The what?'),
('romeo_and_juliet_act2_scene4',22,24,'MERCUTIO','The pox of such antic, lisping, affecting fantasticoes; these new tuners of'),
('romeo_and_juliet_act2_scene4',23,25,'MERCUTIO','accents! “By Jesu, a very good blade! a very tall man! a'),
('romeo_and_juliet_act2_scene4',24,26,'MERCUTIO','very good whore!” Why, is not this a lamentable thing, grandsire, that'),
('romeo_and_juliet_act2_scene4',25,27,'MERCUTIO','we should be thus afflicted with these strange flies, these fashion-mongers, these'),
('romeo_and_juliet_act2_scene4',26,28,'MERCUTIO','perdona-mi’s, who stand so much on the new form, that they cannot'),
('romeo_and_juliet_act2_scene4',27,29,'MERCUTIO','sit at ease on the old bench? O, their bones, their bones!'),
('romeo_and_juliet_act2_scene4',28,30,'BENVOLIO','Here comes Romeo, here comes Romeo.'),
('romeo_and_juliet_act2_scene4',29,31,'MERCUTIO','Without his roe, like a dried herring: O flesh, flesh, how art'),
('romeo_and_juliet_act2_scene4',30,32,'MERCUTIO','thou fishified! Now is he for the numbers that Petrarch flowed in:'),
('romeo_and_juliet_act2_scene4',31,33,'MERCUTIO','Laura to his lady was but a kitchen-wench; marry, she had a'),
('romeo_and_juliet_act2_scene4',32,34,'MERCUTIO','better love to be-rhyme her; Dido a dowdy; Cleopatra a gipsy; Helen'),
('romeo_and_juliet_act2_scene4',33,35,'MERCUTIO','and Hero hildings and harlots; Thisbe a grey eye or so, but'),
('romeo_and_juliet_act2_scene4',34,36,'MERCUTIO','not to the purpose. Signior Romeo, bon jour! there’s a French salutation'),
('romeo_and_juliet_act2_scene4',35,37,'MERCUTIO','to your French slop. You gave us the counterfeit fairly last night.'),
('romeo_and_juliet_act2_scene4',36,38,'ROMEO','Good morrow to you both. What counterfeit did I give you?'),
('romeo_and_juliet_act2_scene4',37,39,'MERCUTIO','The slip, sir, the slip; can you not conceive?'),
('romeo_and_juliet_act2_scene4',38,40,'ROMEO','Pardon, good Mercutio, my business was great; and in such a case'),
('romeo_and_juliet_act2_scene4',39,41,'ROMEO','as mine a man may strain courtesy.'),
('romeo_and_juliet_act2_scene4',40,42,'MERCUTIO','That’s as much as to say, such a case as yours constrains'),
('romeo_and_juliet_act2_scene4',41,43,'MERCUTIO','a man to bow in the hams.'),
('romeo_and_juliet_act2_scene4',42,44,'ROMEO','Meaning, to court’sy.'),
('romeo_and_juliet_act2_scene4',42,45,'MERCUTIO','Thou hast most kindly hit it.'),
('romeo_and_juliet_act2_scene4',43,46,'ROMEO','A most courteous exposition.'),
('romeo_and_juliet_act2_scene4',44,47,'MERCUTIO','Nay, I am the very pink of courtesy.'),
('romeo_and_juliet_act2_scene4',45,48,'ROMEO','Pink for flower.'),
('romeo_and_juliet_act2_scene4',45,49,'MERCUTIO','Right.'),
('romeo_and_juliet_act2_scene4',46,50,'ROMEO','Why, then is my pump well flowered.'),
('romeo_and_juliet_act2_scene4',47,51,'MERCUTIO','Well said: follow me this jest now till thou hast worn out'),
('romeo_and_juliet_act2_scene4',48,52,'MERCUTIO','thy pump, that when the single sole of it is worn, the'),
('romeo_and_juliet_act2_scene4',49,53,'MERCUTIO','jest may remain after the wearing sole singular.'),
('romeo_and_juliet_act2_scene4',50,54,'ROMEO','O single-soled jest, solely singular for the singleness.'),
('romeo_and_juliet_act2_scene4',51,55,'MERCUTIO','Come between us, good Benvolio; my wits faint.'),
('romeo_and_juliet_act2_scene4',52,56,'ROMEO','Switch and spurs, switch and spurs; or I’ll cry a match.'),
('romeo_and_juliet_act2_scene4',53,57,'MERCUTIO','Nay, if thy wits run the wild-goose chase, I have done, for'),
('romeo_and_juliet_act2_scene4',54,58,'MERCUTIO','thou hast more of the wild-goose in one of thy wits than,'),
('romeo_and_juliet_act2_scene4',55,59,'MERCUTIO','I am sure, I have in my whole five: was I with'),
('romeo_and_juliet_act2_scene4',56,60,'MERCUTIO','you there for the goose?'),
('romeo_and_juliet_act2_scene4',57,61,'ROMEO','Thou wast never with me for anything when thou wast not there for the goose.'),
('romeo_and_juliet_act2_scene4',58,62,'MERCUTIO','I will bite thee by the ear for that jest.'),
('romeo_and_juliet_act2_scene4',59,63,'ROMEO','Nay, good goose, bite not.'),
('romeo_and_juliet_act2_scene4',60,64,'MERCUTIO','Thy wit is a very bitter sweeting; it is a most sharp sauce.'),
('romeo_and_juliet_act2_scene4',61,65,'ROMEO','And is it not well served in to a sweet goose?'),
('romeo_and_juliet_act2_scene4',62,66,'MERCUTIO','O here’s a wit of cheveril, that stretches from an inch narrow'),
('romeo_and_juliet_act2_scene4',63,67,'MERCUTIO','to an ell broad!'),
('romeo_and_juliet_act2_scene4',64,68,'ROMEO','I stretch it out for that word “broad;” which added to the'),
('romeo_and_juliet_act2_scene4',65,69,'ROMEO','goose, proves thee far and wide a broad goose.'),
('romeo_and_juliet_act2_scene4',66,70,'MERCUTIO','Why, is not this better now than groaning for love? now art'),
('romeo_and_juliet_act2_scene4',67,71,'MERCUTIO','thou sociable, now art thou Romeo; now art thou what thou art,'),
('romeo_and_juliet_act2_scene4',68,72,'MERCUTIO','by art as well as by nature: for this drivelling love is'),
('romeo_and_juliet_act2_scene4',69,73,'MERCUTIO','like a great natural, that runs lolling up and down to hide'),
('romeo_and_juliet_act2_scene4',70,74,'MERCUTIO','his bauble in a hole.'),
('romeo_and_juliet_act2_scene4',70,75,'BENVOLIO','Stop there, stop there.'),
('romeo_and_juliet_act2_scene4',71,76,'MERCUTIO','Thou desirest me to stop in my tale against the hair.'),
('romeo_and_juliet_act2_scene4',72,77,'BENVOLIO','Thou wouldst else have made thy tale large.'),
('romeo_and_juliet_act2_scene4',73,78,'MERCUTIO','O, thou art deceived; I would have made it short: for I'),
('romeo_and_juliet_act2_scene4',74,79,'MERCUTIO','was come to the whole depth of my tale; and meant, indeed,'),
('romeo_and_juliet_act2_scene4',75,80,'MERCUTIO','to occupy the argument no longer.'),
('romeo_and_juliet_act2_scene4',75,81,'ROMEO','Here’s goodly gear!'),
('romeo_and_juliet_act2_scene4',76,82,'MERCUTIO','A sail, a sail!'),
('romeo_and_juliet_act2_scene4',77,83,'BENVOLIO','Two, two; a shirt and a smock.'),
('romeo_and_juliet_act2_scene4',78,84,'NURSE','Peter!'),
('romeo_and_juliet_act2_scene4',78,85,'PETER','Anon!'),
('romeo_and_juliet_act2_scene4',79,86,'NURSE','My fan, Peter.'),
('romeo_and_juliet_act2_scene4',80,87,'MERCUTIO','Good Peter, to hide her face; for her fan’s the fairer face.'),
('romeo_and_juliet_act2_scene4',81,88,'NURSE','God ye good morrow, gentlemen.'),
('romeo_and_juliet_act2_scene4',81,89,'MERCUTIO','God ye good den, fair gentlewoman.'),
('romeo_and_juliet_act2_scene4',82,90,'NURSE','Is it good den?'),
('romeo_and_juliet_act2_scene4',83,91,'MERCUTIO','’Tis no less, I tell you, for the bawdy hand of the'),
('romeo_and_juliet_act2_scene4',84,92,'MERCUTIO','dial is now upon the prick of noon.'),
('romeo_and_juliet_act2_scene4',85,93,'NURSE','Out upon you! what a man are you!'),
('romeo_and_juliet_act2_scene4',86,94,'ROMEO','One, gentlewoman, that God hath made for himself to mar.'),
('romeo_and_juliet_act2_scene4',87,95,'NURSE','By my troth, it is well said; “for himself to mar,” quoth'),
('romeo_and_juliet_act2_scene4',88,96,'NURSE','a’? Gentlemen, can any of you tell me where I may find'),
('romeo_and_juliet_act2_scene4',89,97,'NURSE','the young Romeo?'),
('romeo_and_juliet_act2_scene4',90,98,'ROMEO','I can tell you; but young Romeo will be older when you'),
('romeo_and_juliet_act2_scene4',91,99,'ROMEO','have found him than he was when you sought him: I am'),
('romeo_and_juliet_act2_scene4',92,100,'ROMEO','the youngest of that name, for fault of a worse.'),
('romeo_and_juliet_act2_scene4',93,101,'NURSE','You say well.'),
('romeo_and_juliet_act2_scene4',94,102,'MERCUTIO','Yea, is the worst well? very well took, i’ faith; wisely, wisely.'),
('romeo_and_juliet_act2_scene4',95,103,'NURSE','If you be he, sir, I desire some confidence with you.'),
('romeo_and_juliet_act2_scene4',96,104,'BENVOLIO','She will indite him to some supper.'),
('romeo_and_juliet_act2_scene4',97,105,'MERCUTIO','A bawd, a bawd, a bawd! So ho!'),
('romeo_and_juliet_act2_scene4',98,106,'ROMEO','What hast thou found?'),
('romeo_and_juliet_act2_scene4',99,107,'MERCUTIO','No hare, sir; unless a hare, sir, in a Lenten pie, that'),
('romeo_and_juliet_act2_scene4',100,108,'MERCUTIO','is something stale and hoar ere it be spent. An old hare'),
('romeo_and_juliet_act2_scene4',101,109,'MERCUTIO','hoar, And an old hare hoar, Is very good meat in Lent:'),
('romeo_and_juliet_act2_scene4',102,110,'MERCUTIO','But a hare that is hoar Is too much for a score,'),
('romeo_and_juliet_act2_scene4',103,111,'MERCUTIO','When it hoars ere it be spent. Romeo, will you come to'),
('romeo_and_juliet_act2_scene4',104,112,'MERCUTIO','your father’s? we’ll to dinner, thither.'),
('romeo_and_juliet_act2_scene4',104,113,'ROMEO','I will follow you.'),
('romeo_and_juliet_act2_scene4',105,114,'MERCUTIO','Farewell, ancient lady; farewell, “lady, lady, lady.”'),
('romeo_and_juliet_act2_scene4',106,115,'NURSE','Marry, farewell! I pray you, sir, what saucy merchant was this, that'),
('romeo_and_juliet_act2_scene4',107,116,'NURSE','was so full of his ropery?'),
('romeo_and_juliet_act2_scene4',108,117,'ROMEO','A gentleman, nurse, that loves to hear himself talk, and will speak'),
('romeo_and_juliet_act2_scene4',109,118,'ROMEO','more in a minute than he will stand to in a month.'),
('romeo_and_juliet_act2_scene4',110,119,'NURSE','An a’ speak anything against me, I’ll take him down, an a’'),
('romeo_and_juliet_act2_scene4',111,120,'NURSE','were lustier than he is, and twenty such Jacks; and if I'),
('romeo_and_juliet_act2_scene4',112,121,'NURSE','cannot, I’ll find those that shall. Scurvy knave! I am none of'),
('romeo_and_juliet_act2_scene4',113,122,'NURSE','his flirt-gills; I am none of his skains-mates. And thou must stand'),
('romeo_and_juliet_act2_scene4',114,123,'NURSE','by too, and suffer every knave to use me at his pleasure?'),
('romeo_and_juliet_act2_scene4',115,124,'PETER','I saw no man use you at his pleasure; if I had,'),
('romeo_and_juliet_act2_scene4',116,125,'PETER','my weapon should quickly have been out, I warrant you: I dare'),
('romeo_and_juliet_act2_scene4',117,126,'PETER','draw as soon as another man, if I see occasion in a'),
('romeo_and_juliet_act2_scene4',118,127,'PETER','good quarrel, and the law on my side.'),
('romeo_and_juliet_act2_scene4',119,128,'NURSE','Now, afore God, I am so vexed, that every part about me'),
('romeo_and_juliet_act2_scene4',120,129,'NURSE','quivers. Scurvy knave! Pray you, sir, a word: and as I told'),
('romeo_and_juliet_act2_scene4',121,130,'NURSE','you, my young lady bade me inquire you out; what she bade'),
('romeo_and_juliet_act2_scene4',122,131,'NURSE','me say, I will keep to myself: but first let me tell'),
('romeo_and_juliet_act2_scene4',123,132,'NURSE','ye, if ye should lead her into a fool’s paradise, as they'),
('romeo_and_juliet_act2_scene4',124,133,'NURSE','say, it were a very gross kind of behavior, as they say:'),
('romeo_and_juliet_act2_scene4',125,134,'NURSE','for the gentlewoman is young; and, therefore, if you should deal double'),
('romeo_and_juliet_act2_scene4',126,135,'NURSE','with her, truly it were an ill thing to be offered to'),
('romeo_and_juliet_act2_scene4',127,136,'NURSE','any gentlewoman, and very weak dealing.'),
('romeo_and_juliet_act2_scene4',128,137,'ROMEO','Nurse, commend me to thy lady and mistress. I protest unto thee—'),
('romeo_and_juliet_act2_scene4',129,138,'NURSE','Good heart, and, i’ faith, I will tell her as much: Lord,'),
('romeo_and_juliet_act2_scene4',130,139,'NURSE','Lord, she will be a joyful woman.'),
('romeo_and_juliet_act2_scene4',131,140,'ROMEO','What wilt thou tell her, nurse? thou dost not mark me.'),
('romeo_and_juliet_act2_scene4',132,141,'NURSE','I will tell her, sir, that you do protest; which, as I'),
('romeo_and_juliet_act2_scene4',133,142,'NURSE','take it, is a gentlemanlike offer.'),
('romeo_and_juliet_act2_scene4',133,143,'ROMEO','Bid her devise'),
('romeo_and_juliet_act2_scene4',134,144,'ROMEO','Some means to come to shrift this afternoon;'),
('romeo_and_juliet_act2_scene4',135,145,'ROMEO','And there she shall at Friar Laurence’ cell'),
('romeo_and_juliet_act2_scene4',136,146,'ROMEO','Be shrived and married. Here is for thy pains.'),
('romeo_and_juliet_act2_scene4',137,147,'NURSE','No, truly, sir; not a penny.'),
('romeo_and_juliet_act2_scene4',137,148,'ROMEO','Go to; I say you shall.'),
('romeo_and_juliet_act2_scene4',138,149,'NURSE','This afternoon, sir? well, she shall be there.'),
('romeo_and_juliet_act2_scene4',139,150,'ROMEO','And stay, good nurse, behind the abbey wall:'),
('romeo_and_juliet_act2_scene4',140,151,'ROMEO','Within this hour my man shall be with thee'),
('romeo_and_juliet_act2_scene4',141,152,'ROMEO','And bring thee cords made like a tackled stair;'),
('romeo_and_juliet_act2_scene4',142,153,'ROMEO','Which to the high top-gallant of my joy'),
('romeo_and_juliet_act2_scene4',143,154,'ROMEO','Must be my convoy in the secret night.'),
('romeo_and_juliet_act2_scene4',144,155,'ROMEO','Farewell; be trusty, and I’ll quit thy pains:'),
('romeo_and_juliet_act2_scene4',145,156,'ROMEO','Farewell; commend me to thy mistress.'),
('romeo_and_juliet_act2_scene4',146,157,'NURSE','Now God in heaven bless thee! Hark you, sir.'),
('romeo_and_juliet_act2_scene4',147,158,'ROMEO','What say’st thou, my dear nurse?'),
('romeo_and_juliet_act2_scene4',148,159,'NURSE','Is your man secret? Did you ne’er hear say,'),
('romeo_and_juliet_act2_scene4',149,160,'NURSE','Two may keep counsel, putting one away?'),
('romeo_and_juliet_act2_scene4',150,161,'ROMEO','I warrant thee, my man’s as true as steel.'),
('romeo_and_juliet_act2_scene4',151,162,'NURSE','Well, sir; my mistress is the sweetest lady—Lord, Lord! when ’twas a'),
('romeo_and_juliet_act2_scene4',152,163,'NURSE','little prating thing:—O, there is a nobleman in town, one Paris, that'),
('romeo_and_juliet_act2_scene4',153,164,'NURSE','would fain lay knife aboard; but she, good soul, had as lief'),
('romeo_and_juliet_act2_scene4',154,165,'NURSE','see a toad, a very toad, as see him. I anger her'),
('romeo_and_juliet_act2_scene4',155,166,'NURSE','sometimes and tell her that Paris is the properer man; but, I’ll'),
('romeo_and_juliet_act2_scene4',156,167,'NURSE','warrant you, when I say so, she looks as pale as any'),
('romeo_and_juliet_act2_scene4',157,168,'NURSE','clout in the versal world. Doth not rosemary and Romeo begin both'),
('romeo_and_juliet_act2_scene4',158,169,'NURSE','with a letter?'),
('romeo_and_juliet_act2_scene4',159,170,'ROMEO','Ay, nurse; what of that? both with an R.'),
('romeo_and_juliet_act2_scene4',160,171,'NURSE','Ah, mocker! that’s the dog’s name; R is for the—No; I know'),
('romeo_and_juliet_act2_scene4',161,172,'NURSE','it begins with some other letter:—and she hath the prettiest sententious of'),
('romeo_and_juliet_act2_scene4',162,173,'NURSE','it, of you and rosemary, that it would do you good to'),
('romeo_and_juliet_act2_scene4',163,174,'NURSE','hear it.'),
('romeo_and_juliet_act2_scene4',163,175,'ROMEO','Commend me to thy lady.'),
('romeo_and_juliet_act2_scene4',164,176,'NURSE','Ay, a thousand times. Peter!'),
('romeo_and_juliet_act2_scene4',164,177,'PETER','Anon!'),
('romeo_and_juliet_act2_scene4',165,178,'NURSE','Peter, take my fan, and go before, and apace.'),
('romeo_and_juliet_act2_scene5',1,0,'JULIET','The clock struck nine when I did send the nurse;'),
('romeo_and_juliet_act2_scene5',2,1,'JULIET','In half an hour she promised to return.'),
('romeo_and_juliet_act2_scene5',3,2,'JULIET','Perchance she cannot meet him: that’s not so.'),
('romeo_and_juliet_act2_scene5',4,3,'JULIET','O, she is lame! love’s heralds should be thoughts,'),
('romeo_and_juliet_act2_scene5',5,4,'JULIET','Which ten times faster glide than the sun’s beams,'),
('romeo_and_juliet_act2_scene5',6,5,'JULIET','Driving back shadows over louring hills:'),
('romeo_and_juliet_act2_scene5',7,6,'JULIET','Therefore do nimble-pinion’d doves draw love,'),
('romeo_and_juliet_act2_scene5',8,7,'JULIET','And therefore hath the wind-swift Cupid wings.'),
('romeo_and_juliet_act2_scene5',9,8,'JULIET','Now is the sun upon the highmost hill'),
('romeo_and_juliet_act2_scene5',10,9,'JULIET','Of this day’s journey, and from nine till twelve'),
('romeo_and_juliet_act2_scene5',11,10,'JULIET','Is three long hours, yet she is not come.'),
('romeo_and_juliet_act2_scene5',12,11,'JULIET','Had she affections and warm youthful blood,'),
('romeo_and_juliet_act2_scene5',13,12,'JULIET','She would be as swift in motion as a ball;'),
('romeo_and_juliet_act2_scene5',14,13,'JULIET','My words would bandy her to my sweet love,'),
('romeo_and_juliet_act2_scene5',15,14,'JULIET','And his to me:'),
('romeo_and_juliet_act2_scene5',16,15,'JULIET','But old folks, many feign as they were dead;'),
('romeo_and_juliet_act2_scene5',17,16,'JULIET','Unwieldy, slow, heavy and pale as lead.'),
('romeo_and_juliet_act2_scene5',18,17,'JULIET','O God, she comes!'),
('romeo_and_juliet_act2_scene5',18,18,'NURSE','Peter, stay at the gate.'),
('romeo_and_juliet_act2_scene5',19,19,'JULIET','Now, good sweet nurse—O Lord, why look’st thou sad?'),
('romeo_and_juliet_act2_scene5',20,20,'JULIET','Though news be sad, yet tell them merrily;'),
('romeo_and_juliet_act2_scene5',21,21,'JULIET','If good, thou shamest the music of sweet news'),
('romeo_and_juliet_act2_scene5',22,22,'JULIET','By playing it to me with so sour a face.'),
('romeo_and_juliet_act2_scene5',23,23,'NURSE','I am a-weary, give me leave awhile:'),
('romeo_and_juliet_act2_scene5',24,24,'NURSE','Fie, how my bones ache! what a jaunt have I had!'),
('romeo_and_juliet_act2_scene5',25,25,'JULIET','I would thou hadst my bones, and I thy news.'),
('romeo_and_juliet_act2_scene5',26,26,'JULIET','Nay, come, I pray thee, speak; good, good nurse, speak.'),
('romeo_and_juliet_act2_scene5',27,27,'NURSE','Jesu, what haste? can you not stay awhile?'),
('romeo_and_juliet_act2_scene5',28,28,'NURSE','Do you not see that I am out of breath?'),
('romeo_and_juliet_act2_scene5',29,29,'JULIET','How art thou out of breath, when thou hast breath'),
('romeo_and_juliet_act2_scene5',30,30,'JULIET','To say to me that thou art out of breath?'),
('romeo_and_juliet_act2_scene5',31,31,'JULIET','The excuse that thou dost make in this delay'),
('romeo_and_juliet_act2_scene5',32,32,'JULIET','Is longer than the tale thou dost excuse.'),
('romeo_and_juliet_act2_scene5',33,33,'JULIET','Is thy news good, or bad? answer to that;'),
('romeo_and_juliet_act2_scene5',34,34,'JULIET','Say either, and I’ll stay the circumstance:'),
('romeo_and_juliet_act2_scene5',35,35,'JULIET','Let me be satisfied, is’t good or bad?'),
('romeo_and_juliet_act2_scene5',36,36,'NURSE','Well, you have made a simple choice; you know not how to'),
('romeo_and_juliet_act2_scene5',37,37,'NURSE','choose a man: Romeo! no, not he; though his face be better'),
('romeo_and_juliet_act2_scene5',38,38,'NURSE','than any man’s, yet his leg excels all men’s; and for a'),
('romeo_and_juliet_act2_scene5',39,39,'NURSE','hand, and a foot, and a body, though they be not to'),
('romeo_and_juliet_act2_scene5',40,40,'NURSE','be talked on, yet they are past compare: he is not the'),
('romeo_and_juliet_act2_scene5',41,41,'NURSE','flower of courtesy, but, I’ll warrant him, as gentle as a lamb.'),
('romeo_and_juliet_act2_scene5',42,42,'NURSE','Go thy ways, wench; serve God. What, have you dined at home?'),
('romeo_and_juliet_act2_scene5',43,43,'JULIET','No, no: but all this did I know before.'),
('romeo_and_juliet_act2_scene5',44,44,'JULIET','What says he of our marriage? what of that?'),
('romeo_and_juliet_act2_scene5',45,45,'NURSE','Lord, how my head aches! what a head have I!'),
('romeo_and_juliet_act2_scene5',46,46,'NURSE','It beats as it would fall in twenty pieces.'),
('romeo_and_juliet_act2_scene5',47,47,'NURSE','My back o’ t’other side—O, my back, my back!'),
('romeo_and_juliet_act2_scene5',48,48,'NURSE','Beshrew your heart for sending me about,'),
('romeo_and_juliet_act2_scene5',49,49,'NURSE','To catch my death with jaunting up and down!'),
('romeo_and_juliet_act2_scene5',50,50,'JULIET','I’ faith, I am sorry that thou art not well.'),
('romeo_and_juliet_act2_scene5',51,51,'JULIET','Sweet, sweet, sweet nurse, tell me, what says my love?'),
('romeo_and_juliet_act2_scene5',52,52,'NURSE','Your love says, like an honest gentleman, and a courteous, and a'),
('romeo_and_juliet_act2_scene5',53,53,'NURSE','kind, and a handsome, and, I warrant, a virtuous—Where is your mother?'),
('romeo_and_juliet_act2_scene5',54,54,'JULIET','Where is my mother! why, she is within;'),
('romeo_and_juliet_act2_scene5',55,55,'JULIET','Where should she be? How oddly thou repliest!'),
('romeo_and_juliet_act2_scene5',56,56,'JULIET','“Your love says, like an honest gentleman,'),
('romeo_and_juliet_act2_scene5',57,57,'JULIET','Where is your mother?”'),
('romeo_and_juliet_act2_scene5',57,58,'NURSE','O God’s lady dear!'),
('romeo_and_juliet_act2_scene5',58,59,'NURSE','Are you so hot? marry, come up, I trow;'),
('romeo_and_juliet_act2_scene5',59,60,'NURSE','Is this the poultice for my aching bones?'),
('romeo_and_juliet_act2_scene5',60,61,'NURSE','Henceforward do your messages yourself.'),
('romeo_and_juliet_act2_scene5',61,62,'JULIET','Here’s such a coil! come, what says Romeo?'),
('romeo_and_juliet_act2_scene5',62,63,'NURSE','Have you got leave to go to shrift to-day?'),
('romeo_and_juliet_act2_scene5',63,64,'JULIET','I have.'),
('romeo_and_juliet_act2_scene5',64,65,'NURSE','Then hie you hence to Friar Laurence’ cell;'),
('romeo_and_juliet_act2_scene5',65,66,'NURSE','There stays a husband to make you a wife:'),
('romeo_and_juliet_act2_scene5',66,67,'NURSE','Now comes the wanton blood up in your cheeks,'),
('romeo_and_juliet_act2_scene5',67,68,'NURSE','They’ll be in scarlet straight at any news.'),
('romeo_and_juliet_act2_scene5',68,69,'NURSE','Hie you to church; I must another way,'),
('romeo_and_juliet_act2_scene5',69,70,'NURSE','To fetch a ladder, by the which your love'),
('romeo_and_juliet_act2_scene5',70,71,'NURSE','Must climb a bird’s nest soon when it is dark:'),
('romeo_and_juliet_act2_scene5',71,72,'NURSE','I am the drudge and toil in your delight,'),
('romeo_and_juliet_act2_scene5',72,73,'NURSE','But you shall bear the burden soon at night.'),
('romeo_and_juliet_act2_scene5',73,74,'NURSE','Go; I’ll to dinner; hie you to the cell.'),
('romeo_and_juliet_act2_scene5',74,75,'JULIET','Hie to high fortune! Honest nurse, farewell.'),
('romeo_and_juliet_act2_scene6',1,0,'FRIAR LAURENCE','So smile the heavens upon this holy act,'),
('romeo_and_juliet_act2_scene6',2,1,'FRIAR LAURENCE','That after hours with sorrow chide us not!'),
('romeo_and_juliet_act2_scene6',3,2,'ROMEO','Amen, amen! but come what sorrow can,'),
('romeo_and_juliet_act2_scene6',4,3,'ROMEO','It cannot countervail the exchange of joy'),
('romeo_and_juliet_act2_scene6',5,4,'ROMEO','That one short minute gives me in her sight:'),
('romeo_and_juliet_act2_scene6',6,5,'ROMEO','Do thou but close our hands with holy words,'),
('romeo_and_juliet_act2_scene6',7,6,'ROMEO','Then love-devouring death do what he dare;'),
('romeo_and_juliet_act2_scene6',8,7,'ROMEO','It is enough I may but call her mine.'),
('romeo_and_juliet_act2_scene6',9,8,'FRIAR LAURENCE','These violent delights have violent ends'),
('romeo_and_juliet_act2_scene6',10,9,'FRIAR LAURENCE','And in their triumph die, like fire and powder,'),
('romeo_and_juliet_act2_scene6',11,10,'FRIAR LAURENCE','Which as they kiss consume: the sweetest honey'),
('romeo_and_juliet_act2_scene6',12,11,'FRIAR LAURENCE','Is loathsome in his own deliciousness'),
('romeo_and_juliet_act2_scene6',13,12,'FRIAR LAURENCE','And in the taste confounds the appetite:'),
('romeo_and_juliet_act2_scene6',14,13,'FRIAR LAURENCE','Therefore love moderately; long love doth so;'),
('romeo_and_juliet_act2_scene6',15,14,'FRIAR LAURENCE','Too swift arrives as tardy as too slow.'),
('romeo_and_juliet_act2_scene6',16,15,'JULIET','Good even to my ghostly confessor.'),
('romeo_and_juliet_act2_scene6',17,16,'FRIAR LAURENCE','Romeo shall thank thee, daughter, for us both.'),
('romeo_and_juliet_act2_scene6',18,17,'JULIET','As much to him, else is his thanks too much.'),
('romeo_and_juliet_act2_scene6',19,18,'ROMEO','Ah, Juliet, if the measure of thy joy'),
('romeo_and_juliet_act2_scene6',20,19,'ROMEO','Be heap’d like mine and that thy skill be more'),
('romeo_and_juliet_act2_scene6',21,20,'ROMEO','To blazon it, then sweeten with thy breath'),
('romeo_and_juliet_act2_scene6',22,21,'ROMEO','This neighbour air, and let rich music’s tongue'),
('romeo_and_juliet_act2_scene6',23,22,'ROMEO','Unfold the imagined happiness that both'),
('romeo_and_juliet_act2_scene6',24,23,'ROMEO','Receive in either by this dear encounter.'),
('romeo_and_juliet_act2_scene6',25,24,'JULIET','Conceit, more rich in matter than in words,'),
('romeo_and_juliet_act2_scene6',26,25,'JULIET','Brags of his substance, not of ornament:'),
('romeo_and_juliet_act2_scene6',27,26,'JULIET','They are but beggars that can count their worth;'),
('romeo_and_juliet_act2_scene6',28,27,'JULIET','But my true love is grown to such excess'),
('romeo_and_juliet_act2_scene6',29,28,'JULIET','I cannot sum up sum of half my wealth.'),
('romeo_and_juliet_act2_scene6',30,29,'FRIAR LAURENCE','Come, come with me, and we will make short work;'),
('romeo_and_juliet_act2_scene6',31,30,'FRIAR LAURENCE','For, by your leaves, you shall not stay alone'),
('romeo_and_juliet_act2_scene6',32,31,'FRIAR LAURENCE','Till holy church incorporate two in one.'),
('romeo_and_juliet_act3_scene1',1,0,'BENVOLIO','I pray thee, good Mercutio, let’s retire:'),
('romeo_and_juliet_act3_scene1',2,1,'BENVOLIO','The day is hot, the Capulets abroad,'),
('romeo_and_juliet_act3_scene1',3,2,'BENVOLIO','And, if we meet, we shall not scape a brawl;'),
('romeo_and_juliet_act3_scene1',4,3,'BENVOLIO','For now, these hot days, is the mad blood stirring.'),
('romeo_and_juliet_act3_scene1',5,4,'MERCUTIO','Thou art like one of those fellows that when he enters the'),
('romeo_and_juliet_act3_scene1',6,5,'MERCUTIO','confines of a tavern claps me his sword upon the table and'),
('romeo_and_juliet_act3_scene1',7,6,'MERCUTIO','says “God send me no need of thee!” and by the operation'),
('romeo_and_juliet_act3_scene1',8,7,'MERCUTIO','of the second cup draws it on the drawer, when indeed there'),
('romeo_and_juliet_act3_scene1',9,8,'MERCUTIO','is no need.'),
('romeo_and_juliet_act3_scene1',9,9,'BENVOLIO','Am I like such a fellow?'),
('romeo_and_juliet_act3_scene1',10,10,'MERCUTIO','Come, come, thou art as hot a Jack in thy mood as'),
('romeo_and_juliet_act3_scene1',11,11,'MERCUTIO','any in Italy, and as soon moved to be moody, and as'),
('romeo_and_juliet_act3_scene1',12,12,'MERCUTIO','soon moody to be moved.'),
('romeo_and_juliet_act3_scene1',12,13,'BENVOLIO','And what to?'),
('romeo_and_juliet_act3_scene1',13,14,'MERCUTIO','Nay, an there were two such, we should have none shortly, for'),
('romeo_and_juliet_act3_scene1',14,15,'MERCUTIO','one would kill the other. Thou! why, thou wilt quarrel with a'),
('romeo_and_juliet_act3_scene1',15,16,'MERCUTIO','man that hath a hair more, or a hair less, in his'),
('romeo_and_juliet_act3_scene1',16,17,'MERCUTIO','beard, than thou hast: thou wilt quarrel with a man for cracking'),
('romeo_and_juliet_act3_scene1',17,18,'MERCUTIO','nuts, having no other reason but because thou hast hazel eyes: what'),
('romeo_and_juliet_act3_scene1',18,19,'MERCUTIO','eye but such an eye would spy out such a quarrel? Thy'),
('romeo_and_juliet_act3_scene1',19,20,'MERCUTIO','head is as full of quarrels as an egg is full of'),
('romeo_and_juliet_act3_scene1',20,21,'MERCUTIO','meat, and yet thy head hath been beaten as addle as an'),
('romeo_and_juliet_act3_scene1',21,22,'MERCUTIO','egg for quarrelling: thou hast quarrelled with a man for coughing in'),
('romeo_and_juliet_act3_scene1',22,23,'MERCUTIO','the street, because he hath wakened thy dog that hath lain asleep'),
('romeo_and_juliet_act3_scene1',23,24,'MERCUTIO','in the sun: didst thou not fall out with a tailor for'),
('romeo_and_juliet_act3_scene1',24,25,'MERCUTIO','wearing his new doublet before Easter? with another, for tying his new'),
('romeo_and_juliet_act3_scene1',25,26,'MERCUTIO','shoes with old riband? and yet thou wilt tutor me from quarrelling!'),
('romeo_and_juliet_act3_scene1',26,27,'BENVOLIO','An I were so apt to quarrel as thou art, any man'),
('romeo_and_juliet_act3_scene1',27,28,'BENVOLIO','should buy the fee-simple of my life for an hour and a'),
('romeo_and_juliet_act3_scene1',28,29,'BENVOLIO','quarter.'),
('romeo_and_juliet_act3_scene1',28,30,'MERCUTIO','The fee-simple! O simple!'),
('romeo_and_juliet_act3_scene1',29,31,'BENVOLIO','By my head, here come the Capulets.'),
('romeo_and_juliet_act3_scene1',30,32,'MERCUTIO','By my heel, I care not.'),
('romeo_and_juliet_act3_scene1',31,33,'TYBALT','Follow me close, for I will speak to them. Gentlemen, good den:'),
('romeo_and_juliet_act3_scene1',32,34,'TYBALT','a word with one of you.'),
('romeo_and_juliet_act3_scene1',33,35,'MERCUTIO','And but one word with one of us? couple it with something;'),
('romeo_and_juliet_act3_scene1',34,36,'MERCUTIO','make it a word and a blow.'),
('romeo_and_juliet_act3_scene1',35,37,'TYBALT','You shall find me apt enough to that, sir, an you will give me occasion.'),
('romeo_and_juliet_act3_scene1',36,38,'MERCUTIO','Could you not take some occasion without giving?'),
('romeo_and_juliet_act3_scene1',37,39,'TYBALT','Mercutio, thou consort’st with Romeo—'),
('romeo_and_juliet_act3_scene1',38,40,'MERCUTIO','Consort! what, dost thou make us minstrels? an thou make minstrels of'),
('romeo_and_juliet_act3_scene1',39,41,'MERCUTIO','us, look to hear nothing but discords: here’s my fiddlestick; here’s that'),
('romeo_and_juliet_act3_scene1',40,42,'MERCUTIO','shall make you dance. ’Zounds, consort!'),
('romeo_and_juliet_act3_scene1',41,43,'BENVOLIO','We talk here in the public haunt of men:'),
('romeo_and_juliet_act3_scene1',42,44,'BENVOLIO','Either withdraw unto some private place,'),
('romeo_and_juliet_act3_scene1',43,45,'BENVOLIO','And reason coldly of your grievances,'),
('romeo_and_juliet_act3_scene1',44,46,'BENVOLIO','Or else depart; here all eyes gaze on us.'),
('romeo_and_juliet_act3_scene1',45,47,'MERCUTIO','Men’s eyes were made to look, and let them gaze;'),
('romeo_and_juliet_act3_scene1',46,48,'MERCUTIO','I will not budge for no man’s pleasure, I.'),
('romeo_and_juliet_act3_scene1',47,49,'TYBALT','Well, peace be with you, sir: here comes my man.'),
('romeo_and_juliet_act3_scene1',48,50,'MERCUTIO','But I’ll be hang’d, sir, if he wear your livery:'),
('romeo_and_juliet_act3_scene1',49,51,'MERCUTIO','Marry, go before to field, he’ll be your follower;'),
('romeo_and_juliet_act3_scene1',50,52,'MERCUTIO','Your worship in that sense may call him “man.”'),
('romeo_and_juliet_act3_scene1',51,53,'TYBALT','Romeo, the hate I bear thee can afford'),
('romeo_and_juliet_act3_scene1',52,54,'TYBALT','No better term than this—thou art a villain.'),
('romeo_and_juliet_act3_scene1',53,55,'ROMEO','Tybalt, the reason that I have to love thee'),
('romeo_and_juliet_act3_scene1',54,56,'ROMEO','Doth much excuse the appertaining rage'),
('romeo_and_juliet_act3_scene1',55,57,'ROMEO','To such a greeting: villain am I none;'),
('romeo_and_juliet_act3_scene1',56,58,'ROMEO','Therefore farewell; I see thou know’st me not.'),
('romeo_and_juliet_act3_scene1',57,59,'TYBALT','Boy, this shall not excuse the injuries'),
('romeo_and_juliet_act3_scene1',58,60,'TYBALT','That thou hast done me; therefore turn and draw.'),
('romeo_and_juliet_act3_scene1',59,61,'ROMEO','I do protest, I never injured thee,'),
('romeo_and_juliet_act3_scene1',60,62,'ROMEO','But love thee better than thou canst devise,'),
('romeo_and_juliet_act3_scene1',61,63,'ROMEO','Till thou shalt know the reason of my love:'),
('romeo_and_juliet_act3_scene1',62,64,'ROMEO','And so, good Capulet—which name I tender'),
('romeo_and_juliet_act3_scene1',63,65,'ROMEO','As dearly as my own—be satisfied.'),
('romeo_and_juliet_act3_scene1',63,66,'MERCUTIO','O calm, dishonourable, vile submission!'),
('romeo_and_juliet_act3_scene1',64,67,'MERCUTIO','Alla stoccata carries it away.'),
('romeo_and_juliet_act3_scene1',65,68,'MERCUTIO','Tybalt, you rat-catcher, will you walk?'),
('romeo_and_juliet_act3_scene1',65,69,'TYBALT','What wouldst thou have with me?'),
('romeo_and_juliet_act3_scene1',66,70,'MERCUTIO','Good king of cats, nothing but one of your nine lives; that'),
('romeo_and_juliet_act3_scene1',67,71,'MERCUTIO','I mean to make bold withal, and, as you shall use me'),
('romeo_and_juliet_act3_scene1',68,72,'MERCUTIO','hereafter, dry-beat the rest of the eight. Will you pluck your sword'),
('romeo_and_juliet_act3_scene1',69,73,'MERCUTIO','out of his pilcher by the ears? make haste, lest mine be'),
('romeo_and_juliet_act3_scene1',70,74,'MERCUTIO','about your ears ere it be out.'),
('romeo_and_juliet_act3_scene1',71,75,'TYBALT','I am for you.'),
('romeo_and_juliet_act3_scene1',71,76,'ROMEO','Gentle Mercutio, put thy rapier up.'),
('romeo_and_juliet_act3_scene1',72,77,'MERCUTIO','Come, sir, your passado. They fight.'),
('romeo_and_juliet_act3_scene1',72,78,'ROMEO','Draw, Benvolio; beat down their weapons.'),
('romeo_and_juliet_act3_scene1',73,79,'ROMEO','Gentlemen, for shame, forbear this outrage!'),
('romeo_and_juliet_act3_scene1',74,80,'ROMEO','Tybalt, Mercutio, the prince expressly hath'),
('romeo_and_juliet_act3_scene1',75,81,'ROMEO','Forbidden bandying in Verona streets:'),
('romeo_and_juliet_act3_scene1',76,82,'ROMEO','Hold, Tybalt! good Mercutio! Tybalt under Romeo’s arm stabs Mercutio, and flies with his followers.'),
('romeo_and_juliet_act3_scene1',77,83,'MERCUTIO','I am hurt.'),
('romeo_and_juliet_act3_scene1',78,84,'MERCUTIO','A plague o’ both your houses! I am sped.'),
('romeo_and_juliet_act3_scene1',79,85,'MERCUTIO','Is he gone, and hath nothing?'),
('romeo_and_juliet_act3_scene1',79,86,'BENVOLIO','What, art thou hurt?'),
('romeo_and_juliet_act3_scene1',80,87,'MERCUTIO','Ay, ay, a scratch, a scratch; marry, ’tis enough.'),
('romeo_and_juliet_act3_scene1',81,88,'MERCUTIO','Where is my page? Go, villain, fetch a surgeon.'),
('romeo_and_juliet_act3_scene1',82,89,'ROMEO','Courage, man; the hurt cannot be much.'),
('romeo_and_juliet_act3_scene1',83,90,'MERCUTIO','No, ’tis not so deep as a well, nor so wide as'),
('romeo_and_juliet_act3_scene1',84,91,'MERCUTIO','a church-door; but ’tis enough, ’twill serve: ask for me to-morrow, and'),
('romeo_and_juliet_act3_scene1',85,92,'MERCUTIO','you shall find me a grave man. I am peppered, I warrant,'),
('romeo_and_juliet_act3_scene1',86,93,'MERCUTIO','for this world. A plague o’ both your houses! ’Zounds, a dog,'),
('romeo_and_juliet_act3_scene1',87,94,'MERCUTIO','a rat, a mouse, a cat, to scratch a man to death!'),
('romeo_and_juliet_act3_scene1',88,95,'MERCUTIO','a braggart, a rogue, a villain, that fights by the book of'),
('romeo_and_juliet_act3_scene1',89,96,'MERCUTIO','arithmetic! Why the devil came you between us? I was hurt under'),
('romeo_and_juliet_act3_scene1',90,97,'MERCUTIO','your arm.'),
('romeo_and_juliet_act3_scene1',90,98,'ROMEO','I thought all for the best.'),
('romeo_and_juliet_act3_scene1',91,99,'MERCUTIO','Help me into some house, Benvolio,'),
('romeo_and_juliet_act3_scene1',92,100,'MERCUTIO','Or I shall faint. A plague o’ both your houses!'),
('romeo_and_juliet_act3_scene1',93,101,'MERCUTIO','They have made worms’ meat of me: I have it,'),
('romeo_and_juliet_act3_scene1',94,102,'MERCUTIO','And soundly too: your houses!'),
('romeo_and_juliet_act3_scene1',94,103,'ROMEO','This gentleman, the prince’s near ally,'),
('romeo_and_juliet_act3_scene1',95,104,'ROMEO','My very friend, hath got his mortal hurt'),
('romeo_and_juliet_act3_scene1',96,105,'ROMEO','In my behalf; my reputation stain’d'),
('romeo_and_juliet_act3_scene1',97,106,'ROMEO','With Tybalt’s slander—Tybalt, that an hour'),
('romeo_and_juliet_act3_scene1',98,107,'ROMEO','Hath been my kinsman! O sweet Juliet,'),
('romeo_and_juliet_act3_scene1',99,108,'ROMEO','Thy beauty hath made me effeminate'),
('romeo_and_juliet_act3_scene1',100,109,'ROMEO','And in my temper soften’d valour’s steel!'),
('romeo_and_juliet_act3_scene1',101,110,'BENVOLIO','O Romeo, Romeo, brave Mercutio’s dead!'),
('romeo_and_juliet_act3_scene1',102,111,'BENVOLIO','That gallant spirit hath aspired the clouds,'),
('romeo_and_juliet_act3_scene1',103,112,'BENVOLIO','Which too untimely here did scorn the earth.'),
('romeo_and_juliet_act3_scene1',104,113,'ROMEO','This day’s black fate on more days doth depend;'),
('romeo_and_juliet_act3_scene1',105,114,'ROMEO','This but begins the woe others must end.'),
('romeo_and_juliet_act3_scene1',106,115,'BENVOLIO','Here comes the furious Tybalt back again.'),
('romeo_and_juliet_act3_scene1',107,116,'ROMEO','Alive, in triumph! and Mercutio slain!'),
('romeo_and_juliet_act3_scene1',108,117,'ROMEO','Away to heaven, respective lenity,'),
('romeo_and_juliet_act3_scene1',109,118,'ROMEO','And fire-eyed fury be my conduct now!'),
('romeo_and_juliet_act3_scene1',110,119,'TYBALT','Thou, wretched boy, that didst consort him here,'),
('romeo_and_juliet_act3_scene1',111,120,'TYBALT','Shalt with him hence.'),
('romeo_and_juliet_act3_scene1',112,121,'ROMEO','This shall determine that. They fight; Tybalt falls.'),
('romeo_and_juliet_act3_scene1',113,122,'BENVOLIO','Romeo, away, be gone!'),
('romeo_and_juliet_act3_scene1',114,123,'BENVOLIO','The citizens are up, and Tybalt slain.'),
('romeo_and_juliet_act3_scene1',115,124,'BENVOLIO','Stand not amazed: the prince will doom thee death,'),
('romeo_and_juliet_act3_scene1',116,125,'BENVOLIO','If thou art taken: hence, be gone, away!'),
('romeo_and_juliet_act3_scene1',117,126,'ROMEO','O, I am fortune’s fool!'),
('romeo_and_juliet_act3_scene1',117,127,'BENVOLIO','Why dost thou stay?'),
('romeo_and_juliet_act3_scene1',118,128,'FIRST CITIZEN','Which way ran he that kill’d Mercutio?'),
('romeo_and_juliet_act3_scene1',119,129,'FIRST CITIZEN','Tybalt, that murderer, which way ran he?'),
('romeo_and_juliet_act3_scene1',120,130,'BENVOLIO','There lies that Tybalt.'),
('romeo_and_juliet_act3_scene1',120,131,'FIRST CITIZEN','Up, sir, go with me;'),
('romeo_and_juliet_act3_scene1',121,132,'FIRST CITIZEN','I charge thee in the princes name, obey.'),
('romeo_and_juliet_act3_scene1',122,133,'PRINCE','Where are the vile beginners of this fray?'),
('romeo_and_juliet_act3_scene1',123,134,'BENVOLIO','O noble prince, I can discover all'),
('romeo_and_juliet_act3_scene1',124,135,'BENVOLIO','The unlucky manage of this fatal brawl:'),
('romeo_and_juliet_act3_scene1',125,136,'BENVOLIO','There lies the man, slain by young Romeo,'),
('romeo_and_juliet_act3_scene1',126,137,'BENVOLIO','That slew thy kinsman, brave Mercutio.'),
('romeo_and_juliet_act3_scene1',127,138,'LADY CAPULET','Tybalt, my cousin! O my brother’s child!'),
('romeo_and_juliet_act3_scene1',128,139,'LADY CAPULET','O prince! O cousin! husband! O, the blood is spilt'),
('romeo_and_juliet_act3_scene1',129,140,'LADY CAPULET','Of my dear kinsman! Prince, as thou art true,'),
('romeo_and_juliet_act3_scene1',130,141,'LADY CAPULET','For blood of ours, shed blood of Montague.'),
('romeo_and_juliet_act3_scene1',131,142,'LADY CAPULET','O cousin, cousin!'),
('romeo_and_juliet_act3_scene1',131,143,'PRINCE','Benvolio, who began this bloody fray?'),
('romeo_and_juliet_act3_scene1',132,144,'BENVOLIO','Tybalt, here slain, whom Romeo’s hand did slay;'),
('romeo_and_juliet_act3_scene1',133,145,'BENVOLIO','Romeo that spoke him fair, bade him bethink'),
('romeo_and_juliet_act3_scene1',134,146,'BENVOLIO','How nice the quarrel was, and urged withal'),
('romeo_and_juliet_act3_scene1',135,147,'BENVOLIO','Your high displeasure: all this uttered'),
('romeo_and_juliet_act3_scene1',136,148,'BENVOLIO','With gentle breath, calm look, knees humbly bow’d,'),
('romeo_and_juliet_act3_scene1',137,149,'BENVOLIO','Could not take truce with the unruly spleen'),
('romeo_and_juliet_act3_scene1',138,150,'BENVOLIO','Of Tybalt deaf to peace, but that he tilts'),
('romeo_and_juliet_act3_scene1',139,151,'BENVOLIO','With piercing steel at bold Mercutio’s breast,'),
('romeo_and_juliet_act3_scene1',140,152,'BENVOLIO','Who, all as hot, turns deadly point to point,'),
('romeo_and_juliet_act3_scene1',141,153,'BENVOLIO','And, with a martial scorn, with one hand beats'),
('romeo_and_juliet_act3_scene1',142,154,'BENVOLIO','Cold death aside, and with the other sends'),
('romeo_and_juliet_act3_scene1',143,155,'BENVOLIO','It back to Tybalt, whose dexterity'),
('romeo_and_juliet_act3_scene1',144,156,'BENVOLIO','Retorts it: Romeo he cries aloud,'),
('romeo_and_juliet_act3_scene1',145,157,'BENVOLIO','“Hold, friends! friends, part!” and, swifter than his tongue,'),
('romeo_and_juliet_act3_scene1',146,158,'BENVOLIO','His agile arm beats down their fatal points,'),
('romeo_and_juliet_act3_scene1',147,159,'BENVOLIO','And ’twixt them rushes; underneath whose arm'),
('romeo_and_juliet_act3_scene1',148,160,'BENVOLIO','An envious thrust from Tybalt hit the life'),
('romeo_and_juliet_act3_scene1',149,161,'BENVOLIO','Of stout Mercutio, and then Tybalt fled;'),
('romeo_and_juliet_act3_scene1',150,162,'BENVOLIO','But by and by comes back to Romeo,'),
('romeo_and_juliet_act3_scene1',151,163,'BENVOLIO','Who had but newly entertain’d revenge,'),
('romeo_and_juliet_act3_scene1',152,164,'BENVOLIO','And to’t they go like lightning, for, ere I'),
('romeo_and_juliet_act3_scene1',153,165,'BENVOLIO','Could draw to part them, was stout Tybalt slain,'),
('romeo_and_juliet_act3_scene1',154,166,'BENVOLIO','And, as he fell, did Romeo turn and fly.'),
('romeo_and_juliet_act3_scene1',155,167,'BENVOLIO','This is the truth, or let Benvolio die.'),
('romeo_and_juliet_act3_scene1',156,168,'LADY CAPULET','He is a kinsman to the Montague;'),
('romeo_and_juliet_act3_scene1',157,169,'LADY CAPULET','Affection makes him false; he speaks not true:'),
('romeo_and_juliet_act3_scene1',158,170,'LADY CAPULET','Some twenty of them fought in this black strife,'),
('romeo_and_juliet_act3_scene1',159,171,'LADY CAPULET','And all those twenty could but kill one life.'),
('romeo_and_juliet_act3_scene1',160,172,'LADY CAPULET','I beg for justice, which thou, prince, must give;'),
('romeo_and_juliet_act3_scene1',161,173,'LADY CAPULET','Romeo slew Tybalt, Romeo must not live.'),
('romeo_and_juliet_act3_scene1',162,174,'PRINCE','Romeo slew him, he slew Mercutio;'),
('romeo_and_juliet_act3_scene1',163,175,'PRINCE','Who now the price of his dear blood doth owe?'),
('romeo_and_juliet_act3_scene1',164,176,'MONTAGUE','Not Romeo, prince, he was Mercutio’s friend;'),
('romeo_and_juliet_act3_scene1',165,177,'MONTAGUE','His fault concludes but what the law should end,'),
('romeo_and_juliet_act3_scene1',166,178,'MONTAGUE','The life of Tybalt.'),
('romeo_and_juliet_act3_scene1',166,179,'PRINCE','And for that offence'),
('romeo_and_juliet_act3_scene1',167,180,'PRINCE','Immediately we do exile him hence:'),
('romeo_and_juliet_act3_scene1',168,181,'PRINCE','I have an interest in your hate’s proceeding,'),
('romeo_and_juliet_act3_scene1',169,182,'PRINCE','My blood for your rude brawls doth lie a-bleeding;'),
('romeo_and_juliet_act3_scene1',170,183,'PRINCE','But I’ll amerce you with so strong a fine'),
('romeo_and_juliet_act3_scene1',171,184,'PRINCE','That you shall all repent the loss of mine:'),
('romeo_and_juliet_act3_scene1',172,185,'PRINCE','I will be deaf to pleading and excuses;'),
('romeo_and_juliet_act3_scene1',173,186,'PRINCE','Nor tears nor prayers shall purchase out abuses:'),
('romeo_and_juliet_act3_scene1',174,187,'PRINCE','Therefore use none: let Romeo hence in haste,'),
('romeo_and_juliet_act3_scene1',175,188,'PRINCE','Else, when he’s found, that hour is his last.'),
('romeo_and_juliet_act3_scene1',176,189,'PRINCE','Bear hence this body and attend our will:'),
('romeo_and_juliet_act3_scene1',177,190,'PRINCE','Mercy but murders, pardoning those that kill.'),
('romeo_and_juliet_act3_scene2',1,0,'JULIET','Gallop apace, you fiery-footed steeds,'),
('romeo_and_juliet_act3_scene2',2,1,'JULIET','Towards Phoebus’ lodging: such a waggoner'),
('romeo_and_juliet_act3_scene2',3,2,'JULIET','As Phaethon would whip you to the west,'),
('romeo_and_juliet_act3_scene2',4,3,'JULIET','And bring in cloudy night immediately.'),
('romeo_and_juliet_act3_scene2',5,4,'JULIET','Spread thy close curtain, love-performing night,'),
('romeo_and_juliet_act3_scene2',6,5,'JULIET','That runaways’ eyes may wink, and Romeo'),
('romeo_and_juliet_act3_scene2',7,6,'JULIET','Leap to these arms, untalk’d of and unseen.'),
('romeo_and_juliet_act3_scene2',8,7,'JULIET','Lovers can see to do their amorous rites'),
('romeo_and_juliet_act3_scene2',9,8,'JULIET','By their own beauties; or, if love be blind,'),
('romeo_and_juliet_act3_scene2',10,9,'JULIET','It best agrees with night. Come, civil night,'),
('romeo_and_juliet_act3_scene2',11,10,'JULIET','Thou sober-suited matron, all in black,'),
('romeo_and_juliet_act3_scene2',12,11,'JULIET','And learn me how to lose a winning match,'),
('romeo_and_juliet_act3_scene2',13,12,'JULIET','Play’d for a pair of stainless maidenhoods:'),
('romeo_and_juliet_act3_scene2',14,13,'JULIET','Hood my unmann’d blood, bating in my cheeks,'),
('romeo_and_juliet_act3_scene2',15,14,'JULIET','With thy black mantle; till strange love, grown bold,'),
('romeo_and_juliet_act3_scene2',16,15,'JULIET','Think true love acted simple modesty.'),
('romeo_and_juliet_act3_scene2',17,16,'JULIET','Come, night; come, Romeo; come, thou day in night;'),
('romeo_and_juliet_act3_scene2',18,17,'JULIET','For thou wilt lie upon the wings of night'),
('romeo_and_juliet_act3_scene2',19,18,'JULIET','Whiter than new snow on a raven’s back.'),
('romeo_and_juliet_act3_scene2',20,19,'JULIET','Come, gentle night, come, loving, black-brow’d night,'),
('romeo_and_juliet_act3_scene2',21,20,'JULIET','Give me my Romeo; and, when he shall die,'),
('romeo_and_juliet_act3_scene2',22,21,'JULIET','Take him and cut him out in little stars,'),
('romeo_and_juliet_act3_scene2',23,22,'JULIET','And he will make the face of heaven so fine'),
('romeo_and_juliet_act3_scene2',24,23,'JULIET','That all the world will be in love with night'),
('romeo_and_juliet_act3_scene2',25,24,'JULIET','And pay no worship to the garish sun.'),
('romeo_and_juliet_act3_scene2',26,25,'JULIET','O, I have bought the mansion of a love,'),
('romeo_and_juliet_act3_scene2',27,26,'JULIET','But not possess’d it, and, though I am sold,'),
('romeo_and_juliet_act3_scene2',28,27,'JULIET','Not yet enjoy’d: so tedious is this day'),
('romeo_and_juliet_act3_scene2',29,28,'JULIET','As is the night before some festival'),
('romeo_and_juliet_act3_scene2',30,29,'JULIET','To an impatient child that hath new robes'),
('romeo_and_juliet_act3_scene2',31,30,'JULIET','And may not wear them. O, here comes my nurse,'),
('romeo_and_juliet_act3_scene2',32,31,'JULIET','And she brings news; and every tongue that speaks'),
('romeo_and_juliet_act3_scene2',33,32,'JULIET','But Romeo’s name speaks heavenly eloquence.'),
('romeo_and_juliet_act3_scene2',33,33,'NURSE','Ay, ay, the cords.'),
('romeo_and_juliet_act3_scene2',34,34,'JULIET','Ay me! what news? why dost thou wring thy hands?'),
('romeo_and_juliet_act3_scene2',35,35,'NURSE','Ah, well-a-day! he’s dead, he’s dead, he’s dead!'),
('romeo_and_juliet_act3_scene2',36,36,'NURSE','We are undone, lady, we are undone!'),
('romeo_and_juliet_act3_scene2',37,37,'NURSE','Alack the day! he’s gone, he’s kill’d, he’s dead!'),
('romeo_and_juliet_act3_scene2',38,38,'JULIET','Can heaven be so envious?'),
('romeo_and_juliet_act3_scene2',38,39,'NURSE','Romeo can,'),
('romeo_and_juliet_act3_scene2',39,40,'NURSE','Though heaven cannot: O Romeo, Romeo!'),
('romeo_and_juliet_act3_scene2',40,41,'NURSE','Who ever would have thought it? Romeo!'),
('romeo_and_juliet_act3_scene2',41,42,'JULIET','What devil art thou, that dost torment me thus?'),
('romeo_and_juliet_act3_scene2',42,43,'JULIET','This torture should be roar’d in dismal hell.'),
('romeo_and_juliet_act3_scene2',43,44,'JULIET','Hath Romeo slain himself? say thou but “I,”'),
('romeo_and_juliet_act3_scene2',44,45,'JULIET','And that bare vowel “I” shall poison more'),
('romeo_and_juliet_act3_scene2',45,46,'JULIET','Than the death-darting eye of cockatrice:'),
('romeo_and_juliet_act3_scene2',46,47,'JULIET','I am not I, if there be such an I;'),
('romeo_and_juliet_act3_scene2',47,48,'JULIET','Or those eyes shut, that make thee answer “I.”'),
('romeo_and_juliet_act3_scene2',48,49,'JULIET','If he be slain, say “I”; or if not, no:'),
('romeo_and_juliet_act3_scene2',49,50,'JULIET','Brief sounds determine of my weal or woe.'),
('romeo_and_juliet_act3_scene2',50,51,'NURSE','I saw the wound, I saw it with mine eyes—'),
('romeo_and_juliet_act3_scene2',51,52,'NURSE','God save the mark!—here on his manly breast:'),
('romeo_and_juliet_act3_scene2',52,53,'NURSE','A piteous corse, a bloody piteous corse;');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('romeo_and_juliet_act3_scene2',53,54,'NURSE','Pale, pale as ashes, all bedaub’d in blood,'),
('romeo_and_juliet_act3_scene2',54,55,'NURSE','All in gore-blood; I swounded at the sight.'),
('romeo_and_juliet_act3_scene2',55,56,'JULIET','O, break, my heart! poor bankrupt, break at once!'),
('romeo_and_juliet_act3_scene2',56,57,'JULIET','To prison, eyes, ne’er look on liberty!'),
('romeo_and_juliet_act3_scene2',57,58,'JULIET','Vile earth, to earth resign; end motion here;'),
('romeo_and_juliet_act3_scene2',58,59,'JULIET','And thou and Romeo press one heavy bier!'),
('romeo_and_juliet_act3_scene2',59,60,'NURSE','O Tybalt, Tybalt, the best friend I had!'),
('romeo_and_juliet_act3_scene2',60,61,'NURSE','O courteous Tybalt! honest gentleman!'),
('romeo_and_juliet_act3_scene2',61,62,'NURSE','That ever I should live to see thee dead!'),
('romeo_and_juliet_act3_scene2',62,63,'JULIET','What storm is this that blows so contrary?'),
('romeo_and_juliet_act3_scene2',63,64,'JULIET','Is Romeo slaughter’d, and is Tybalt dead?'),
('romeo_and_juliet_act3_scene2',64,65,'JULIET','My dear-loved cousin, and my dearer lord?'),
('romeo_and_juliet_act3_scene2',65,66,'JULIET','Then, dreadful trumpet, sound the general doom!'),
('romeo_and_juliet_act3_scene2',66,67,'JULIET','For who is living, if those two are gone?'),
('romeo_and_juliet_act3_scene2',67,68,'NURSE','Tybalt is gone, and Romeo banished;'),
('romeo_and_juliet_act3_scene2',68,69,'NURSE','Romeo that kill’d him, he is banished.'),
('romeo_and_juliet_act3_scene2',69,70,'JULIET','O God! did Romeo’s hand shed Tybalt’s blood?'),
('romeo_and_juliet_act3_scene2',70,71,'NURSE','It did, it did; alas the day, it did!'),
('romeo_and_juliet_act3_scene2',71,72,'JULIET','O serpent heart, hid with a flowering face!'),
('romeo_and_juliet_act3_scene2',72,73,'JULIET','Did ever dragon keep so fair a cave?'),
('romeo_and_juliet_act3_scene2',73,74,'JULIET','Beautiful tyrant! fiend angelical!'),
('romeo_and_juliet_act3_scene2',74,75,'JULIET','Dove-feather’d raven! wolvish-ravening lamb!'),
('romeo_and_juliet_act3_scene2',75,76,'JULIET','Despised substance of divinest show!'),
('romeo_and_juliet_act3_scene2',76,77,'JULIET','Just opposite to what thou justly seem’st,'),
('romeo_and_juliet_act3_scene2',77,78,'JULIET','A damned saint, an honourable villain!'),
('romeo_and_juliet_act3_scene2',78,79,'JULIET','O nature, what hadst thou to do in hell,'),
('romeo_and_juliet_act3_scene2',79,80,'JULIET','When thou didst bower the spirit of a fiend'),
('romeo_and_juliet_act3_scene2',80,81,'JULIET','In moral paradise of such sweet flesh?'),
('romeo_and_juliet_act3_scene2',81,82,'JULIET','Was ever book containing such vile matter'),
('romeo_and_juliet_act3_scene2',82,83,'JULIET','So fairly bound? O, that deceit should dwell'),
('romeo_and_juliet_act3_scene2',83,84,'JULIET','In such a gorgeous palace!'),
('romeo_and_juliet_act3_scene2',83,85,'NURSE','There’s no trust,'),
('romeo_and_juliet_act3_scene2',84,86,'NURSE','No faith, no honesty in men; all perjured,'),
('romeo_and_juliet_act3_scene2',85,87,'NURSE','All forsworn, all naught, all dissemblers.'),
('romeo_and_juliet_act3_scene2',86,88,'NURSE','Ah, where’s my man? give me some aqua vitae:'),
('romeo_and_juliet_act3_scene2',87,89,'NURSE','These griefs, these woes, these sorrows make me old.'),
('romeo_and_juliet_act3_scene2',88,90,'NURSE','Shame come to Romeo!'),
('romeo_and_juliet_act3_scene2',88,91,'JULIET','Blister’d be thy tongue'),
('romeo_and_juliet_act3_scene2',89,92,'JULIET','For such a wish! he was not born to shame:'),
('romeo_and_juliet_act3_scene2',90,93,'JULIET','Upon his brow shame is ashamed to sit;'),
('romeo_and_juliet_act3_scene2',91,94,'JULIET','For ’tis a throne where honour may be crown’d'),
('romeo_and_juliet_act3_scene2',92,95,'JULIET','Sole monarch of the universal earth.'),
('romeo_and_juliet_act3_scene2',93,96,'JULIET','O, what a beast was I to chide at him!'),
('romeo_and_juliet_act3_scene2',94,97,'NURSE','Will you speak well of him that kill’d your cousin?'),
('romeo_and_juliet_act3_scene2',95,98,'JULIET','Shall I speak ill of him that is my husband?'),
('romeo_and_juliet_act3_scene2',96,99,'JULIET','Ah, poor my lord, what tongue shall smooth thy name,'),
('romeo_and_juliet_act3_scene2',97,100,'JULIET','When I, thy three-hours wife, have mangled it?'),
('romeo_and_juliet_act3_scene2',98,101,'JULIET','But, wherefore, villain, didst thou kill my cousin?'),
('romeo_and_juliet_act3_scene2',99,102,'JULIET','That villain cousin would have kill’d my husband:'),
('romeo_and_juliet_act3_scene2',100,103,'JULIET','Back, foolish tears, back to your native spring;'),
('romeo_and_juliet_act3_scene2',101,104,'JULIET','Your tributary drops belong to woe,'),
('romeo_and_juliet_act3_scene2',102,105,'JULIET','Which you, mistaking, offer up to joy.'),
('romeo_and_juliet_act3_scene2',103,106,'JULIET','My husband lives, that Tybalt would have slain;'),
('romeo_and_juliet_act3_scene2',104,107,'JULIET','And Tybalt’s dead, that would have slain my husband:'),
('romeo_and_juliet_act3_scene2',105,108,'JULIET','All this is comfort; wherefore weep I then?'),
('romeo_and_juliet_act3_scene2',106,109,'JULIET','Some word there was, worser than Tybalt’s death,'),
('romeo_and_juliet_act3_scene2',107,110,'JULIET','That murder’d me: I would forget it fain;'),
('romeo_and_juliet_act3_scene2',108,111,'JULIET','But, O, it presses to my memory,'),
('romeo_and_juliet_act3_scene2',109,112,'JULIET','Like damned guilty deeds to sinners’ minds:'),
('romeo_and_juliet_act3_scene2',110,113,'JULIET','“Tybalt is dead, and Romeo—banished;”'),
('romeo_and_juliet_act3_scene2',111,114,'JULIET','That “banished,” that one word “banished,”'),
('romeo_and_juliet_act3_scene2',112,115,'JULIET','Hath slain ten thousand Tybalts. Tybalt’s death'),
('romeo_and_juliet_act3_scene2',113,116,'JULIET','Was woe enough, if it had ended there:'),
('romeo_and_juliet_act3_scene2',114,117,'JULIET','Or, if sour woe delights in fellowship'),
('romeo_and_juliet_act3_scene2',115,118,'JULIET','And needly will be rank’d with other griefs,'),
('romeo_and_juliet_act3_scene2',116,119,'JULIET','Why follow’d not, when she said “Tybalt’s dead,”'),
('romeo_and_juliet_act3_scene2',117,120,'JULIET','“Thy father,” or “thy mother,” nay, or both,'),
('romeo_and_juliet_act3_scene2',118,121,'JULIET','Which modern lamentations might have moved?'),
('romeo_and_juliet_act3_scene2',119,122,'JULIET','But with a rearward following Tybalt’s death,'),
('romeo_and_juliet_act3_scene2',120,123,'JULIET','“Romeo is banished,” to speak that word,'),
('romeo_and_juliet_act3_scene2',121,124,'JULIET','Is father, mother, Tybalt, Romeo, Juliet,'),
('romeo_and_juliet_act3_scene2',122,125,'JULIET','All slain, all dead. “Romeo is banished!”'),
('romeo_and_juliet_act3_scene2',123,126,'JULIET','There is no end, no limit, measure, bound,'),
('romeo_and_juliet_act3_scene2',124,127,'JULIET','In that word’s death; no words can that woe sound.'),
('romeo_and_juliet_act3_scene2',125,128,'JULIET','Where is my father, and my mother, nurse?'),
('romeo_and_juliet_act3_scene2',126,129,'NURSE','Weeping and wailing over Tybalt’s corse:'),
('romeo_and_juliet_act3_scene2',127,130,'NURSE','Will you go to them? I will bring you thither.'),
('romeo_and_juliet_act3_scene2',128,131,'JULIET','Wash they his wounds with tears: mine shall be spent,'),
('romeo_and_juliet_act3_scene2',129,132,'JULIET','When theirs are dry, for Romeo’s banishment.'),
('romeo_and_juliet_act3_scene2',130,133,'JULIET','Take up those cords: poor ropes, you are beguiled,'),
('romeo_and_juliet_act3_scene2',131,134,'JULIET','Both you and I; for Romeo is exiled:'),
('romeo_and_juliet_act3_scene2',132,135,'JULIET','He made you for a highway to my bed;'),
('romeo_and_juliet_act3_scene2',133,136,'JULIET','But I, a maid, die maiden-widowed.'),
('romeo_and_juliet_act3_scene2',134,137,'JULIET','Come, cords, come, nurse; I’ll to my wedding-bed;'),
('romeo_and_juliet_act3_scene2',135,138,'JULIET','And death, not Romeo, take my maidenhead!'),
('romeo_and_juliet_act3_scene2',136,139,'NURSE','Hie to your chamber: I’ll find Romeo'),
('romeo_and_juliet_act3_scene2',137,140,'NURSE','To comfort you: I wot well where he is.'),
('romeo_and_juliet_act3_scene2',138,141,'NURSE','Hark ye, your Romeo will be here at night:'),
('romeo_and_juliet_act3_scene2',139,142,'NURSE','I’ll to him; he is hid at Laurence’ cell.'),
('romeo_and_juliet_act3_scene2',140,143,'JULIET','O, find him! give this ring to my true knight,'),
('romeo_and_juliet_act3_scene2',141,144,'JULIET','And bid him come to take his last farewell.'),
('romeo_and_juliet_act3_scene3',1,0,'FRIAR LAURENCE','Romeo, come forth; come forth, thou fearful man:'),
('romeo_and_juliet_act3_scene3',2,1,'FRIAR LAURENCE','Affliction is enamour’d of thy parts,'),
('romeo_and_juliet_act3_scene3',3,2,'FRIAR LAURENCE','And thou art wedded to calamity.'),
('romeo_and_juliet_act3_scene3',4,3,'ROMEO','Father, what news? what is the prince’s doom?'),
('romeo_and_juliet_act3_scene3',5,4,'ROMEO','What sorrow craves acquaintance at my hand,'),
('romeo_and_juliet_act3_scene3',6,5,'ROMEO','That I yet know not?'),
('romeo_and_juliet_act3_scene3',6,6,'FRIAR LAURENCE','Too familiar'),
('romeo_and_juliet_act3_scene3',7,7,'FRIAR LAURENCE','Is my dear son with such sour company:'),
('romeo_and_juliet_act3_scene3',8,8,'FRIAR LAURENCE','I bring thee tidings of the prince’s doom.'),
('romeo_and_juliet_act3_scene3',9,9,'ROMEO','What less than dooms-day is the prince’s doom?'),
('romeo_and_juliet_act3_scene3',10,10,'FRIAR LAURENCE','A gentler judgment vanish’d from his lips,'),
('romeo_and_juliet_act3_scene3',11,11,'FRIAR LAURENCE','Not body’s death, but body’s banishment.'),
('romeo_and_juliet_act3_scene3',11,12,'ROMEO','Ha, banishment! be merciful, say “death;”'),
('romeo_and_juliet_act3_scene3',12,13,'ROMEO','For exile hath more terror in his look,'),
('romeo_and_juliet_act3_scene3',13,14,'ROMEO','Much more than death: do not say “banishment.”'),
('romeo_and_juliet_act3_scene3',14,15,'FRIAR LAURENCE','Hence from Verona art thou banished:'),
('romeo_and_juliet_act3_scene3',15,16,'FRIAR LAURENCE','Be patient, for the world is broad and wide.'),
('romeo_and_juliet_act3_scene3',16,17,'ROMEO','There is no world without Verona walls,'),
('romeo_and_juliet_act3_scene3',17,18,'ROMEO','But purgatory, torture, hell itself.'),
('romeo_and_juliet_act3_scene3',18,19,'ROMEO','Hence-banished is banish’d from the world,'),
('romeo_and_juliet_act3_scene3',19,20,'ROMEO','And world’s exile is death: then banished,'),
('romeo_and_juliet_act3_scene3',20,21,'ROMEO','Is death mis-term’d: calling death banishment,'),
('romeo_and_juliet_act3_scene3',21,22,'ROMEO','Thou cutt’st my head off with a golden axe,'),
('romeo_and_juliet_act3_scene3',22,23,'ROMEO','And smilest upon the stroke that murders me.'),
('romeo_and_juliet_act3_scene3',23,24,'FRIAR LAURENCE','O deadly sin! O rude unthankfulness!'),
('romeo_and_juliet_act3_scene3',24,25,'FRIAR LAURENCE','Thy fault our law calls death; but the kind prince,'),
('romeo_and_juliet_act3_scene3',25,26,'FRIAR LAURENCE','Taking thy part, hath rush’d aside the law,'),
('romeo_and_juliet_act3_scene3',26,27,'FRIAR LAURENCE','And turn’d that black word death to banishment:'),
('romeo_and_juliet_act3_scene3',27,28,'FRIAR LAURENCE','This is dear mercy, and thou seest it not.'),
('romeo_and_juliet_act3_scene3',28,29,'ROMEO','’Tis torture, and not mercy: heaven is here,'),
('romeo_and_juliet_act3_scene3',29,30,'ROMEO','Where Juliet lives; and every cat and dog'),
('romeo_and_juliet_act3_scene3',30,31,'ROMEO','And little mouse, every unworthy thing,'),
('romeo_and_juliet_act3_scene3',31,32,'ROMEO','Live here in heaven and may look on her;'),
('romeo_and_juliet_act3_scene3',32,33,'ROMEO','But Romeo may not: more validity,'),
('romeo_and_juliet_act3_scene3',33,34,'ROMEO','More honourable state, more courtship lives'),
('romeo_and_juliet_act3_scene3',34,35,'ROMEO','In carrion-flies than Romeo: they may seize'),
('romeo_and_juliet_act3_scene3',35,36,'ROMEO','On the white wonder of dear Juliet’s hand'),
('romeo_and_juliet_act3_scene3',36,37,'ROMEO','And steal immortal blessing from her lips,'),
('romeo_and_juliet_act3_scene3',37,38,'ROMEO','Who even in pure and vestal modesty,'),
('romeo_and_juliet_act3_scene3',38,39,'ROMEO','Still blush, as thinking their own kisses sin;'),
('romeo_and_juliet_act3_scene3',39,40,'ROMEO','But Romeo may not; he is banished:'),
('romeo_and_juliet_act3_scene3',40,41,'ROMEO','Flies may do this, but I from this must fly:'),
('romeo_and_juliet_act3_scene3',41,42,'ROMEO','They are free men, but I am banished.'),
('romeo_and_juliet_act3_scene3',42,43,'ROMEO','And say’st thou yet that exile is not death?'),
('romeo_and_juliet_act3_scene3',43,44,'ROMEO','Hadst thou no poison mix’d, no sharp-ground knife,'),
('romeo_and_juliet_act3_scene3',44,45,'ROMEO','No sudden mean of death, though ne’er so mean,'),
('romeo_and_juliet_act3_scene3',45,46,'ROMEO','But “banished” to kill me?—“banished”?'),
('romeo_and_juliet_act3_scene3',46,47,'ROMEO','O friar, the damned use that word in hell;'),
('romeo_and_juliet_act3_scene3',47,48,'ROMEO','Howlings attend it: how hast thou the heart,'),
('romeo_and_juliet_act3_scene3',48,49,'ROMEO','Being a divine, a ghostly confessor,'),
('romeo_and_juliet_act3_scene3',49,50,'ROMEO','A sin-absolver, and my friend profess’d,'),
('romeo_and_juliet_act3_scene3',50,51,'ROMEO','To mangle me with that word “banished”?'),
('romeo_and_juliet_act3_scene3',51,52,'FRIAR LAURENCE','Thou fond mad man, hear me but speak a word.'),
('romeo_and_juliet_act3_scene3',52,53,'ROMEO','O, thou wilt speak again of banishment.'),
('romeo_and_juliet_act3_scene3',53,54,'FRIAR LAURENCE','I’ll give thee armour to keep off that word;'),
('romeo_and_juliet_act3_scene3',54,55,'FRIAR LAURENCE','Adversity’s sweet milk, philosophy,'),
('romeo_and_juliet_act3_scene3',55,56,'FRIAR LAURENCE','To comfort thee, though thou art banished.'),
('romeo_and_juliet_act3_scene3',56,57,'ROMEO','Yet “banished”? Hang up philosophy!'),
('romeo_and_juliet_act3_scene3',57,58,'ROMEO','Unless philosophy can make a Juliet,'),
('romeo_and_juliet_act3_scene3',58,59,'ROMEO','Displant a town, reverse a prince’s doom,'),
('romeo_and_juliet_act3_scene3',59,60,'ROMEO','It helps not, it prevails not: talk no more.'),
('romeo_and_juliet_act3_scene3',60,61,'FRIAR LAURENCE','O, then I see that madmen have no ears.'),
('romeo_and_juliet_act3_scene3',61,62,'ROMEO','How should they, when that wise men have no eyes?'),
('romeo_and_juliet_act3_scene3',62,63,'FRIAR LAURENCE','Let me dispute with thee of thy estate.'),
('romeo_and_juliet_act3_scene3',63,64,'ROMEO','Thou canst not speak of that thou dost not feel:'),
('romeo_and_juliet_act3_scene3',64,65,'ROMEO','Wert thou as young as I, Juliet thy love,'),
('romeo_and_juliet_act3_scene3',65,66,'ROMEO','An hour but married, Tybalt murdered,'),
('romeo_and_juliet_act3_scene3',66,67,'ROMEO','Doting like me and like me banished,'),
('romeo_and_juliet_act3_scene3',67,68,'ROMEO','Then mightst thou speak, then mightst thou tear thy hair,'),
('romeo_and_juliet_act3_scene3',68,69,'ROMEO','And fall upon the ground, as I do now,'),
('romeo_and_juliet_act3_scene3',69,70,'ROMEO','Taking the measure of an unmade grave.'),
('romeo_and_juliet_act3_scene3',70,71,'FRIAR LAURENCE','Arise; one knocks; good Romeo, hide thyself.'),
('romeo_and_juliet_act3_scene3',71,72,'ROMEO','Not I; unless the breath of heart-sick groans,'),
('romeo_and_juliet_act3_scene3',72,73,'ROMEO','Mist-like, infold me from the search of eyes.'),
('romeo_and_juliet_act3_scene3',73,74,'FRIAR LAURENCE','Hark, how they knock! Who’s there? Romeo, arise;'),
('romeo_and_juliet_act3_scene3',74,75,'FRIAR LAURENCE','Thou wilt be taken. Stay awhile! Stand up;'),
('romeo_and_juliet_act3_scene3',75,76,'FRIAR LAURENCE','Run to my study. By and by! God’s will,'),
('romeo_and_juliet_act3_scene3',76,77,'FRIAR LAURENCE','What simpleness is this! I come, I come!'),
('romeo_and_juliet_act3_scene3',77,78,'FRIAR LAURENCE','Who knocks so hard? whence come you? what’s your will?'),
('romeo_and_juliet_act3_scene3',78,79,'NURSE','Let me come in, and you shall know my errand;'),
('romeo_and_juliet_act3_scene3',79,80,'NURSE','I come from Lady Juliet.'),
('romeo_and_juliet_act3_scene3',79,81,'FRIAR LAURENCE','Welcome, then.'),
('romeo_and_juliet_act3_scene3',80,82,'NURSE','O holy friar, O, tell me, holy friar,'),
('romeo_and_juliet_act3_scene3',81,83,'NURSE','Where is my lady’s lord, where’s Romeo?'),
('romeo_and_juliet_act3_scene3',82,84,'FRIAR LAURENCE','There on the ground, with his own tears made drunk.'),
('romeo_and_juliet_act3_scene3',83,85,'NURSE','O, he is even in my mistress’ case,'),
('romeo_and_juliet_act3_scene3',84,86,'NURSE','Just in her case! O woeful sympathy!'),
('romeo_and_juliet_act3_scene3',85,87,'NURSE','Piteous predicament! Even so lies she,'),
('romeo_and_juliet_act3_scene3',86,88,'NURSE','Blubbering and weeping, weeping and blubbering.'),
('romeo_and_juliet_act3_scene3',87,89,'NURSE','Stand up, stand up; stand, an you be a man:'),
('romeo_and_juliet_act3_scene3',88,90,'NURSE','For Juliet’s sake, for her sake, rise and stand;'),
('romeo_and_juliet_act3_scene3',89,91,'NURSE','Why should you fall into so deep an O?'),
('romeo_and_juliet_act3_scene3',90,92,'ROMEO','Nurse!'),
('romeo_and_juliet_act3_scene3',91,93,'NURSE','Ah sir! ah sir! Well, death’s the end of all.'),
('romeo_and_juliet_act3_scene3',92,94,'ROMEO','Spakest thou of Juliet? how is it with her?'),
('romeo_and_juliet_act3_scene3',93,95,'ROMEO','Doth she not think me an old murderer,'),
('romeo_and_juliet_act3_scene3',94,96,'ROMEO','Now I have stain’d the childhood of our joy'),
('romeo_and_juliet_act3_scene3',95,97,'ROMEO','With blood removed but little from her own?'),
('romeo_and_juliet_act3_scene3',96,98,'ROMEO','Where is she? and how doth she? and what says'),
('romeo_and_juliet_act3_scene3',97,99,'ROMEO','My conceal’d lady to our cancell’d love?'),
('romeo_and_juliet_act3_scene3',98,100,'NURSE','O, she says nothing, sir, but weeps and weeps;'),
('romeo_and_juliet_act3_scene3',99,101,'NURSE','And now falls on her bed; and then starts up,'),
('romeo_and_juliet_act3_scene3',100,102,'NURSE','And Tybalt calls; and then on Romeo cries,'),
('romeo_and_juliet_act3_scene3',101,103,'NURSE','And then down falls again.'),
('romeo_and_juliet_act3_scene3',101,104,'ROMEO','As if that name,'),
('romeo_and_juliet_act3_scene3',102,105,'ROMEO','Shot from the deadly level of a gun,'),
('romeo_and_juliet_act3_scene3',103,106,'ROMEO','Did murder her; as that name’s cursed hand'),
('romeo_and_juliet_act3_scene3',104,107,'ROMEO','Murder’d her kinsman. O, tell me, friar, tell me,'),
('romeo_and_juliet_act3_scene3',105,108,'ROMEO','In what vile part of this anatomy'),
('romeo_and_juliet_act3_scene3',106,109,'ROMEO','Doth my name lodge? tell me, that I may sack'),
('romeo_and_juliet_act3_scene3',107,110,'ROMEO','The hateful mansion.'),
('romeo_and_juliet_act3_scene3',107,111,'FRIAR LAURENCE','Hold thy desperate hand:'),
('romeo_and_juliet_act3_scene3',108,112,'FRIAR LAURENCE','Art thou a man? thy form cries out thou art:'),
('romeo_and_juliet_act3_scene3',109,113,'FRIAR LAURENCE','Thy tears are womanish; thy wild acts denote'),
('romeo_and_juliet_act3_scene3',110,114,'FRIAR LAURENCE','The unreasonable fury of a beast:'),
('romeo_and_juliet_act3_scene3',111,115,'FRIAR LAURENCE','Unseemly woman in a seeming man!'),
('romeo_and_juliet_act3_scene3',112,116,'FRIAR LAURENCE','Or ill-beseeming beast in seeming both!'),
('romeo_and_juliet_act3_scene3',113,117,'FRIAR LAURENCE','Thou hast amazed me: by my holy order,'),
('romeo_and_juliet_act3_scene3',114,118,'FRIAR LAURENCE','I thought thy disposition better temper’d.'),
('romeo_and_juliet_act3_scene3',115,119,'FRIAR LAURENCE','Hast thou slain Tybalt? wilt thou slay thyself?'),
('romeo_and_juliet_act3_scene3',116,120,'FRIAR LAURENCE','And slay thy lady too that lives in thee,'),
('romeo_and_juliet_act3_scene3',117,121,'FRIAR LAURENCE','By doing damned hate upon thyself?'),
('romeo_and_juliet_act3_scene3',118,122,'FRIAR LAURENCE','Why rail’st thou on thy birth, the heaven, and earth?'),
('romeo_and_juliet_act3_scene3',119,123,'FRIAR LAURENCE','Since birth, and heaven, and earth, all three do meet'),
('romeo_and_juliet_act3_scene3',120,124,'FRIAR LAURENCE','In thee at once; which thou at once wouldst lose.'),
('romeo_and_juliet_act3_scene3',121,125,'FRIAR LAURENCE','Fie, fie, thou shamest thy shape, thy love, thy wit;'),
('romeo_and_juliet_act3_scene3',122,126,'FRIAR LAURENCE','Which, like a usurer, abound’st in all,'),
('romeo_and_juliet_act3_scene3',123,127,'FRIAR LAURENCE','And usest none in that true use indeed'),
('romeo_and_juliet_act3_scene3',124,128,'FRIAR LAURENCE','Which should bedeck thy shape, thy love, thy wit:'),
('romeo_and_juliet_act3_scene3',125,129,'FRIAR LAURENCE','Thy noble shape is but a form of wax,'),
('romeo_and_juliet_act3_scene3',126,130,'FRIAR LAURENCE','Digressing from the valour of a man;'),
('romeo_and_juliet_act3_scene3',127,131,'FRIAR LAURENCE','Thy dear love sworn but hollow perjury,'),
('romeo_and_juliet_act3_scene3',128,132,'FRIAR LAURENCE','Killing that love which thou hast vow’d to cherish;'),
('romeo_and_juliet_act3_scene3',129,133,'FRIAR LAURENCE','Thy wit, that ornament to shape and love,'),
('romeo_and_juliet_act3_scene3',130,134,'FRIAR LAURENCE','Mis-shapen in the conduct of them both,'),
('romeo_and_juliet_act3_scene3',131,135,'FRIAR LAURENCE','Like powder in a skilless soldier’s flask,'),
('romeo_and_juliet_act3_scene3',132,136,'FRIAR LAURENCE','Is set a-fire by thine own ignorance,'),
('romeo_and_juliet_act3_scene3',133,137,'FRIAR LAURENCE','And thou dismember’d with thine own defence.'),
('romeo_and_juliet_act3_scene3',134,138,'FRIAR LAURENCE','What, rouse thee, man! thy Juliet is alive,'),
('romeo_and_juliet_act3_scene3',135,139,'FRIAR LAURENCE','For whose dear sake thou wast but lately dead;'),
('romeo_and_juliet_act3_scene3',136,140,'FRIAR LAURENCE','There art thou happy: Tybalt would kill thee,'),
('romeo_and_juliet_act3_scene3',137,141,'FRIAR LAURENCE','But thou slew’st Tybalt; there are thou happy too:'),
('romeo_and_juliet_act3_scene3',138,142,'FRIAR LAURENCE','The law that threaten’d death becomes thy friend'),
('romeo_and_juliet_act3_scene3',139,143,'FRIAR LAURENCE','And turns it to exile; there art thou happy:'),
('romeo_and_juliet_act3_scene3',140,144,'FRIAR LAURENCE','A pack of blessings lights up upon thy back;'),
('romeo_and_juliet_act3_scene3',141,145,'FRIAR LAURENCE','Happiness courts thee in her best array;'),
('romeo_and_juliet_act3_scene3',142,146,'FRIAR LAURENCE','But, like a misbehaved and sullen wench,'),
('romeo_and_juliet_act3_scene3',143,147,'FRIAR LAURENCE','Thou pout’st upon thy fortune and thy love:'),
('romeo_and_juliet_act3_scene3',144,148,'FRIAR LAURENCE','Take heed, take heed, for such die miserable.'),
('romeo_and_juliet_act3_scene3',145,149,'FRIAR LAURENCE','Go, get thee to thy love, as was decreed,'),
('romeo_and_juliet_act3_scene3',146,150,'FRIAR LAURENCE','Ascend her chamber, hence and comfort her:'),
('romeo_and_juliet_act3_scene3',147,151,'FRIAR LAURENCE','But look thou stay not till the watch be set,'),
('romeo_and_juliet_act3_scene3',148,152,'FRIAR LAURENCE','For then thou canst not pass to Mantua;'),
('romeo_and_juliet_act3_scene3',149,153,'FRIAR LAURENCE','Where thou shalt live, till we can find a time'),
('romeo_and_juliet_act3_scene3',150,154,'FRIAR LAURENCE','To blaze your marriage, reconcile your friends,'),
('romeo_and_juliet_act3_scene3',151,155,'FRIAR LAURENCE','Beg pardon of the prince, and call thee back'),
('romeo_and_juliet_act3_scene3',152,156,'FRIAR LAURENCE','With twenty hundred thousand times more joy'),
('romeo_and_juliet_act3_scene3',153,157,'FRIAR LAURENCE','Than thou went’st forth in lamentation.'),
('romeo_and_juliet_act3_scene3',154,158,'FRIAR LAURENCE','Go before, nurse: commend me to thy lady;'),
('romeo_and_juliet_act3_scene3',155,159,'FRIAR LAURENCE','And bid her hasten all the house to bed,'),
('romeo_and_juliet_act3_scene3',156,160,'FRIAR LAURENCE','Which heavy sorrow makes them apt unto:'),
('romeo_and_juliet_act3_scene3',157,161,'FRIAR LAURENCE','Romeo is coming.'),
('romeo_and_juliet_act3_scene3',158,162,'NURSE','O Lord, I could have stay’d here all the night'),
('romeo_and_juliet_act3_scene3',159,163,'NURSE','To hear good counsel: O, what learning is!'),
('romeo_and_juliet_act3_scene3',160,164,'NURSE','My lord, I’ll tell my lady you will come.'),
('romeo_and_juliet_act3_scene3',161,165,'ROMEO','Do so, and bid my sweet prepare to chide.'),
('romeo_and_juliet_act3_scene3',162,166,'NURSE','Here, sir, a ring she bid me give you, sir:'),
('romeo_and_juliet_act3_scene3',163,167,'NURSE','Hie you, make haste, for it grows very late.'),
('romeo_and_juliet_act3_scene3',164,168,'ROMEO','How well my comfort is revived by this!'),
('romeo_and_juliet_act3_scene3',165,169,'FRIAR LAURENCE','Go hence; good night; and here stands all your state:'),
('romeo_and_juliet_act3_scene3',166,170,'FRIAR LAURENCE','Either be gone before the watch be set,'),
('romeo_and_juliet_act3_scene3',167,171,'FRIAR LAURENCE','Or by the break of day disguised from hence:'),
('romeo_and_juliet_act3_scene3',168,172,'FRIAR LAURENCE','Sojourn in Mantua; I’ll find out your man,'),
('romeo_and_juliet_act3_scene3',169,173,'FRIAR LAURENCE','And he shall signify from time to time'),
('romeo_and_juliet_act3_scene3',170,174,'FRIAR LAURENCE','Every good hap to you that chances here:'),
('romeo_and_juliet_act3_scene3',171,175,'FRIAR LAURENCE','Give me thy hand; ’tis late: farewell; good night.'),
('romeo_and_juliet_act3_scene3',172,176,'ROMEO','But that a joy past joy calls out on me,'),
('romeo_and_juliet_act3_scene3',173,177,'ROMEO','It were a grief, so brief to part with thee:'),
('romeo_and_juliet_act3_scene3',174,178,'ROMEO','Farewell.'),
('romeo_and_juliet_act3_scene4',1,0,'CAPULET','Things have fall’n out, sir, so unluckily,'),
('romeo_and_juliet_act3_scene4',2,1,'CAPULET','That we have had no time to move our daughter:'),
('romeo_and_juliet_act3_scene4',3,2,'CAPULET','Look you, she loved her kinsman Tybalt dearly,'),
('romeo_and_juliet_act3_scene4',4,3,'CAPULET','And so did I:—Well, we were born to die.'),
('romeo_and_juliet_act3_scene4',5,4,'CAPULET','’Tis very late, she’ll not come down to-night:'),
('romeo_and_juliet_act3_scene4',6,5,'CAPULET','I promise you, but for your company,'),
('romeo_and_juliet_act3_scene4',7,6,'CAPULET','I would have been a-bed an hour ago.'),
('romeo_and_juliet_act3_scene4',8,7,'PARIS','These times of woe afford no time to woo.'),
('romeo_and_juliet_act3_scene4',9,8,'PARIS','Madam, good night: commend me to your daughter.'),
('romeo_and_juliet_act3_scene4',10,9,'LADY CAPULET','I will, and know her mind early to-morrow;'),
('romeo_and_juliet_act3_scene4',11,10,'LADY CAPULET','To-night she is mew’d up to her heaviness.'),
('romeo_and_juliet_act3_scene4',12,11,'CAPULET','Sir Paris, I will make a desperate tender'),
('romeo_and_juliet_act3_scene4',13,12,'CAPULET','Of my child’s love: I think she will be ruled'),
('romeo_and_juliet_act3_scene4',14,13,'CAPULET','In all respects by me; nay, more, I doubt it not.'),
('romeo_and_juliet_act3_scene4',15,14,'CAPULET','Wife, go you to her ere you go to bed;'),
('romeo_and_juliet_act3_scene4',16,15,'CAPULET','Acquaint her here of my son Paris’ love;'),
('romeo_and_juliet_act3_scene4',17,16,'CAPULET','And bid her, mark you me, on Wednesday next—'),
('romeo_and_juliet_act3_scene4',18,17,'CAPULET','But, soft! what day is this?'),
('romeo_and_juliet_act3_scene4',18,18,'PARIS','Monday, my lord,'),
('romeo_and_juliet_act3_scene4',19,19,'CAPULET','Monday! ha, ha! Well, Wednesday is too soon,'),
('romeo_and_juliet_act3_scene4',20,20,'CAPULET','O’ Thursday let it be: o’ Thursday, tell her,'),
('romeo_and_juliet_act3_scene4',21,21,'CAPULET','She shall be married to this noble earl.'),
('romeo_and_juliet_act3_scene4',22,22,'CAPULET','Will you be ready? do you like this haste?'),
('romeo_and_juliet_act3_scene4',23,23,'CAPULET','We’ll keep no great ado—a friend or two;'),
('romeo_and_juliet_act3_scene4',24,24,'CAPULET','For, hark you, Tybalt being slain so late,'),
('romeo_and_juliet_act3_scene4',25,25,'CAPULET','It may be thought we held him carelessly,'),
('romeo_and_juliet_act3_scene4',26,26,'CAPULET','Being our kinsman, if we revel much:'),
('romeo_and_juliet_act3_scene4',27,27,'CAPULET','Therefore we’ll have some half a dozen friends,'),
('romeo_and_juliet_act3_scene4',28,28,'CAPULET','And there an end. But what say you to Thursday?'),
('romeo_and_juliet_act3_scene4',29,29,'PARIS','My lord, I would that Thursday were to-morrow.'),
('romeo_and_juliet_act3_scene4',30,30,'CAPULET','Well, get you gone: o’ Thursday be it, then.'),
('romeo_and_juliet_act3_scene4',31,31,'CAPULET','Go you to Juliet ere you go to bed,'),
('romeo_and_juliet_act3_scene4',32,32,'CAPULET','Prepare her, wife, against this wedding-day.'),
('romeo_and_juliet_act3_scene4',33,33,'CAPULET','Farewell, my lord. Light to my chamber, ho!'),
('romeo_and_juliet_act3_scene4',34,34,'CAPULET','Afore me! it is so very very late,'),
('romeo_and_juliet_act3_scene4',35,35,'CAPULET','That we may call it early by and by.'),
('romeo_and_juliet_act3_scene4',36,36,'CAPULET','Good night.'),
('romeo_and_juliet_act3_scene5',1,0,'JULIET','Wilt thou be gone? it is not yet near day:'),
('romeo_and_juliet_act3_scene5',2,1,'JULIET','It was the nightingale, and not the lark,'),
('romeo_and_juliet_act3_scene5',3,2,'JULIET','That pierced the fearful hollow of thine ear;'),
('romeo_and_juliet_act3_scene5',4,3,'JULIET','Nightly she sings on yon pomegranate-tree:'),
('romeo_and_juliet_act3_scene5',5,4,'JULIET','Believe me, love, it was the nightingale.'),
('romeo_and_juliet_act3_scene5',6,5,'ROMEO','It was the lark, the herald of the morn,'),
('romeo_and_juliet_act3_scene5',7,6,'ROMEO','No nightingale: look, love, what envious streaks'),
('romeo_and_juliet_act3_scene5',8,7,'ROMEO','Do lace the severing clouds in yonder east:'),
('romeo_and_juliet_act3_scene5',9,8,'ROMEO','Night’s candles are burnt out, and jocund day'),
('romeo_and_juliet_act3_scene5',10,9,'ROMEO','Stands tiptoe on the misty mountain tops.'),
('romeo_and_juliet_act3_scene5',11,10,'ROMEO','I must be gone and live, or stay and die.'),
('romeo_and_juliet_act3_scene5',12,11,'JULIET','Yon light is not day-light, I know it, I:'),
('romeo_and_juliet_act3_scene5',13,12,'JULIET','It is some meteor that the sun exhales,'),
('romeo_and_juliet_act3_scene5',14,13,'JULIET','To be to thee this night a torch-bearer,'),
('romeo_and_juliet_act3_scene5',15,14,'JULIET','And light thee on thy way to Mantua:'),
('romeo_and_juliet_act3_scene5',16,15,'JULIET','Therefore stay yet; thou need’st not to be gone.'),
('romeo_and_juliet_act3_scene5',17,16,'ROMEO','Let me be ta’en, let me be put to death;'),
('romeo_and_juliet_act3_scene5',18,17,'ROMEO','I am content, so thou wilt have it so.'),
('romeo_and_juliet_act3_scene5',19,18,'ROMEO','I’ll say yon grey is not the morning’s eye,'),
('romeo_and_juliet_act3_scene5',20,19,'ROMEO','’Tis but the pale reflex of Cynthia’s brow;'),
('romeo_and_juliet_act3_scene5',21,20,'ROMEO','Nor that is not the lark, whose notes do beat'),
('romeo_and_juliet_act3_scene5',22,21,'ROMEO','The vaulty heaven so high above our heads:'),
('romeo_and_juliet_act3_scene5',23,22,'ROMEO','I have more care to stay than will to go:'),
('romeo_and_juliet_act3_scene5',24,23,'ROMEO','Come, death, and welcome! Juliet wills it so.'),
('romeo_and_juliet_act3_scene5',25,24,'ROMEO','How is’t, my soul? let’s talk; it is not day.'),
('romeo_and_juliet_act3_scene5',26,25,'JULIET','It is, it is: hie hence, be gone, away!'),
('romeo_and_juliet_act3_scene5',27,26,'JULIET','It is the lark that sings so out of tune,'),
('romeo_and_juliet_act3_scene5',28,27,'JULIET','Straining harsh discords and unpleasing sharps.'),
('romeo_and_juliet_act3_scene5',29,28,'JULIET','Some say the lark makes sweet division;'),
('romeo_and_juliet_act3_scene5',30,29,'JULIET','This doth not so, for she divideth us:'),
('romeo_and_juliet_act3_scene5',31,30,'JULIET','Some say the lark and loathed toad change eyes;'),
('romeo_and_juliet_act3_scene5',32,31,'JULIET','O, now I would they had changed voices too!'),
('romeo_and_juliet_act3_scene5',33,32,'JULIET','Since arm from arm that voice doth us affray,'),
('romeo_and_juliet_act3_scene5',34,33,'JULIET','Hunting thee hence with hunt’s-up to the day.'),
('romeo_and_juliet_act3_scene5',35,34,'JULIET','O, now be gone; more light and light it grows.'),
('romeo_and_juliet_act3_scene5',36,35,'ROMEO','More light and light; more dark and dark our woes!'),
('romeo_and_juliet_act3_scene5',37,36,'NURSE','Madam!'),
('romeo_and_juliet_act3_scene5',37,37,'JULIET','Nurse?'),
('romeo_and_juliet_act3_scene5',38,38,'NURSE','Your lady mother is coming to your chamber:'),
('romeo_and_juliet_act3_scene5',39,39,'NURSE','The day is broke; be wary, look about.'),
('romeo_and_juliet_act3_scene5',40,40,'JULIET','Then, window, let day in, and let life out.'),
('romeo_and_juliet_act3_scene5',41,41,'ROMEO','Farewell, farewell! one kiss, and I’ll descend. He goeth down.'),
('romeo_and_juliet_act3_scene5',42,42,'JULIET','Art thou gone so? love, lord, ay, husband, friend!'),
('romeo_and_juliet_act3_scene5',43,43,'JULIET','I must hear from thee every day in the hour,'),
('romeo_and_juliet_act3_scene5',44,44,'JULIET','For in a minute there are many days:'),
('romeo_and_juliet_act3_scene5',45,45,'JULIET','O, by this count I shall be much in years'),
('romeo_and_juliet_act3_scene5',46,46,'JULIET','Ere I again behold my Romeo!'),
('romeo_and_juliet_act3_scene5',46,47,'ROMEO','Farewell!'),
('romeo_and_juliet_act3_scene5',47,48,'ROMEO','I will omit no opportunity'),
('romeo_and_juliet_act3_scene5',48,49,'ROMEO','That may convey my greetings, love, to thee.'),
('romeo_and_juliet_act3_scene5',49,50,'JULIET','O think’st thou we shall ever meet again?'),
('romeo_and_juliet_act3_scene5',50,51,'ROMEO','I doubt it not; and all these woes shall serve'),
('romeo_and_juliet_act3_scene5',51,52,'ROMEO','For sweet discourses in our time to come.'),
('romeo_and_juliet_act3_scene5',52,53,'JULIET','O God, I have an ill-divining soul!'),
('romeo_and_juliet_act3_scene5',53,54,'JULIET','Methinks I see thee, now thou art below,'),
('romeo_and_juliet_act3_scene5',54,55,'JULIET','As one dead in the bottom of a tomb:'),
('romeo_and_juliet_act3_scene5',55,56,'JULIET','Either my eyesight fails, or thou look’st pale.'),
('romeo_and_juliet_act3_scene5',56,57,'ROMEO','And trust me, love, in my eye so do you:'),
('romeo_and_juliet_act3_scene5',57,58,'ROMEO','Dry sorrow drinks our blood. Adieu, adieu!'),
('romeo_and_juliet_act3_scene5',58,59,'JULIET','O fortune, fortune! all men call thee fickle:'),
('romeo_and_juliet_act3_scene5',59,60,'JULIET','If thou art fickle, what dost thou with him'),
('romeo_and_juliet_act3_scene5',60,61,'JULIET','That is renown’d for faith? Be fickle, fortune;'),
('romeo_and_juliet_act3_scene5',61,62,'JULIET','For then, I hope, thou wilt not keep him long,'),
('romeo_and_juliet_act3_scene5',62,63,'JULIET','But send him back.'),
('romeo_and_juliet_act3_scene5',62,64,'LADY CAPULET','Ho, daughter! are you up?'),
('romeo_and_juliet_act3_scene5',63,65,'JULIET','Who is’t that calls? is it my lady mother?'),
('romeo_and_juliet_act3_scene5',64,66,'JULIET','Is she not down so late, or up so early?'),
('romeo_and_juliet_act3_scene5',65,67,'JULIET','What unaccustom’d cause procures her hither?'),
('romeo_and_juliet_act3_scene5',65,68,'LADY CAPULET','Why, how now, Juliet!'),
('romeo_and_juliet_act3_scene5',66,69,'JULIET','Madam, I am not well.'),
('romeo_and_juliet_act3_scene5',66,70,'LADY CAPULET','Evermore weeping for your cousin’s death?'),
('romeo_and_juliet_act3_scene5',67,71,'LADY CAPULET','What, wilt thou wash him from his grave with tears?'),
('romeo_and_juliet_act3_scene5',68,72,'LADY CAPULET','An if thou couldst, thou couldst not make him live;'),
('romeo_and_juliet_act3_scene5',69,73,'LADY CAPULET','Therefore, have done: some grief shows much of love;'),
('romeo_and_juliet_act3_scene5',70,74,'LADY CAPULET','But much of grief shows still some want of wit.'),
('romeo_and_juliet_act3_scene5',71,75,'JULIET','Yet let me weep for such a feeling loss.'),
('romeo_and_juliet_act3_scene5',72,76,'LADY CAPULET','So shall you feel the loss, but not the friend'),
('romeo_and_juliet_act3_scene5',73,77,'LADY CAPULET','Which you weep for.'),
('romeo_and_juliet_act3_scene5',73,78,'JULIET','Feeling so the loss,'),
('romeo_and_juliet_act3_scene5',74,79,'JULIET','I cannot choose but ever weep the friend.'),
('romeo_and_juliet_act3_scene5',75,80,'LADY CAPULET','Well, girl, thou weep’st not so much for his death,'),
('romeo_and_juliet_act3_scene5',76,81,'LADY CAPULET','As that the villain lives which slaughter’d him.'),
('romeo_and_juliet_act3_scene5',77,82,'JULIET','What villain, madam?'),
('romeo_and_juliet_act3_scene5',77,83,'LADY CAPULET','That same villain, Romeo.'),
('romeo_and_juliet_act3_scene5',78,84,'JULIET','Villain and he be many miles asunder.—'),
('romeo_and_juliet_act3_scene5',79,85,'JULIET','God Pardon him! I do, with all my heart;'),
('romeo_and_juliet_act3_scene5',80,86,'JULIET','And yet no man like he doth grieve my heart.'),
('romeo_and_juliet_act3_scene5',81,87,'LADY CAPULET','That is, because the traitor murderer lives.'),
('romeo_and_juliet_act3_scene5',82,88,'JULIET','Ay, madam, from the reach of these my hands:'),
('romeo_and_juliet_act3_scene5',83,89,'JULIET','Would none but I might venge my cousin’s death!'),
('romeo_and_juliet_act3_scene5',84,90,'LADY CAPULET','We will have vengeance for it, fear thou not:'),
('romeo_and_juliet_act3_scene5',85,91,'LADY CAPULET','Then weep no more. I’ll send to one in Mantua,'),
('romeo_and_juliet_act3_scene5',86,92,'LADY CAPULET','Where that same banish’d runagate doth live,'),
('romeo_and_juliet_act3_scene5',87,93,'LADY CAPULET','Shall give him such an unaccustom’d dram,'),
('romeo_and_juliet_act3_scene5',88,94,'LADY CAPULET','That he shall soon keep Tybalt company:'),
('romeo_and_juliet_act3_scene5',89,95,'LADY CAPULET','And then, I hope, thou wilt be satisfied.'),
('romeo_and_juliet_act3_scene5',90,96,'JULIET','Indeed, I never shall be satisfied'),
('romeo_and_juliet_act3_scene5',91,97,'JULIET','With Romeo, till I behold him—dead—'),
('romeo_and_juliet_act3_scene5',92,98,'JULIET','Is my poor heart so for a kinsman vex’d:'),
('romeo_and_juliet_act3_scene5',93,99,'JULIET','Madam, if you could find out but a man'),
('romeo_and_juliet_act3_scene5',94,100,'JULIET','To bear a poison, I would temper it;'),
('romeo_and_juliet_act3_scene5',95,101,'JULIET','That Romeo should, upon receipt thereof,'),
('romeo_and_juliet_act3_scene5',96,102,'JULIET','Soon sleep in quiet. O, how my heart abhors'),
('romeo_and_juliet_act3_scene5',97,103,'JULIET','To hear him named, and cannot come to him,'),
('romeo_and_juliet_act3_scene5',98,104,'JULIET','To wreak the love I bore my cousin'),
('romeo_and_juliet_act3_scene5',99,105,'JULIET','Upon his body that hath slaughter’d him!'),
('romeo_and_juliet_act3_scene5',100,106,'LADY CAPULET','Find thou the means, and I’ll find such a man.'),
('romeo_and_juliet_act3_scene5',101,107,'LADY CAPULET','But now I’ll tell thee joyful tidings, girl.'),
('romeo_and_juliet_act3_scene5',102,108,'JULIET','And joy comes well in such a needy time:'),
('romeo_and_juliet_act3_scene5',103,109,'JULIET','What are they, I beseech your ladyship?'),
('romeo_and_juliet_act3_scene5',104,110,'LADY CAPULET','Well, well, thou hast a careful father, child;'),
('romeo_and_juliet_act3_scene5',105,111,'LADY CAPULET','One who, to put thee from thy heaviness,'),
('romeo_and_juliet_act3_scene5',106,112,'LADY CAPULET','Hath sorted out a sudden day of joy,'),
('romeo_and_juliet_act3_scene5',107,113,'LADY CAPULET','That thou expect’st not nor I look’d not for.'),
('romeo_and_juliet_act3_scene5',108,114,'JULIET','Madam, in happy time, what day is that?'),
('romeo_and_juliet_act3_scene5',109,115,'LADY CAPULET','Marry, my child, early next Thursday morn,'),
('romeo_and_juliet_act3_scene5',110,116,'LADY CAPULET','The gallant, young and noble gentleman,'),
('romeo_and_juliet_act3_scene5',111,117,'LADY CAPULET','The County Paris, at Saint Peter’s Church,'),
('romeo_and_juliet_act3_scene5',112,118,'LADY CAPULET','Shall happily make thee there a joyful bride.'),
('romeo_and_juliet_act3_scene5',113,119,'JULIET','Now, by Saint Peter’s Church and Peter too,'),
('romeo_and_juliet_act3_scene5',114,120,'JULIET','He shall not make me there a joyful bride.'),
('romeo_and_juliet_act3_scene5',115,121,'JULIET','I wonder at this haste; that I must wed'),
('romeo_and_juliet_act3_scene5',116,122,'JULIET','Ere he, that should be husband, comes to woo.'),
('romeo_and_juliet_act3_scene5',117,123,'JULIET','I pray you, tell my lord and father, madam,'),
('romeo_and_juliet_act3_scene5',118,124,'JULIET','I will not marry yet; and, when I do, I swear,'),
('romeo_and_juliet_act3_scene5',119,125,'JULIET','It shall be Romeo, whom you know I hate,'),
('romeo_and_juliet_act3_scene5',120,126,'JULIET','Rather than Paris. These are news indeed!'),
('romeo_and_juliet_act3_scene5',121,127,'LADY CAPULET','Here comes your father; tell him so yourself,'),
('romeo_and_juliet_act3_scene5',122,128,'LADY CAPULET','And see how he will take it at your hands.'),
('romeo_and_juliet_act3_scene5',123,129,'CAPULET','When the sun sets, the air doth drizzle dew;'),
('romeo_and_juliet_act3_scene5',124,130,'CAPULET','But for the sunset of my brother’s son'),
('romeo_and_juliet_act3_scene5',125,131,'CAPULET','It rains downright.'),
('romeo_and_juliet_act3_scene5',126,132,'CAPULET','How now! a conduit, girl? what, still in tears?'),
('romeo_and_juliet_act3_scene5',127,133,'CAPULET','Evermore showering? In one little body'),
('romeo_and_juliet_act3_scene5',128,134,'CAPULET','Thou counterfeit’st a bark, a sea, a wind;'),
('romeo_and_juliet_act3_scene5',129,135,'CAPULET','For still thy eyes, which I may call the sea,'),
('romeo_and_juliet_act3_scene5',130,136,'CAPULET','Do ebb and flow with tears; the bark thy body is,'),
('romeo_and_juliet_act3_scene5',131,137,'CAPULET','Sailing in this salt flood; the winds, thy sighs;'),
('romeo_and_juliet_act3_scene5',132,138,'CAPULET','Who, raging with thy tears, and they with them,'),
('romeo_and_juliet_act3_scene5',133,139,'CAPULET','Without a sudden calm, will overset'),
('romeo_and_juliet_act3_scene5',134,140,'CAPULET','Thy tempest-tossed body. How now, wife!'),
('romeo_and_juliet_act3_scene5',135,141,'CAPULET','Have you deliver’d to her our decree?'),
('romeo_and_juliet_act3_scene5',136,142,'LADY CAPULET','Ay, sir; but she will none, she gives you thanks.'),
('romeo_and_juliet_act3_scene5',137,143,'LADY CAPULET','I would the fool were married to her grave!'),
('romeo_and_juliet_act3_scene5',138,144,'CAPULET','Soft! take me with you, take me with you, wife.'),
('romeo_and_juliet_act3_scene5',139,145,'CAPULET','How! will she none? doth she not give us thanks?'),
('romeo_and_juliet_act3_scene5',140,146,'CAPULET','Is she not proud? doth she not count her blest,'),
('romeo_and_juliet_act3_scene5',141,147,'CAPULET','Unworthy as she is, that we have wrought'),
('romeo_and_juliet_act3_scene5',142,148,'CAPULET','So worthy a gentleman to be her bridegroom?'),
('romeo_and_juliet_act3_scene5',143,149,'JULIET','Not proud, you have; but thankful, that you have:'),
('romeo_and_juliet_act3_scene5',144,150,'JULIET','Proud can I never be of what I hate;'),
('romeo_and_juliet_act3_scene5',145,151,'JULIET','But thankful even for hate, that is meant love.'),
('romeo_and_juliet_act3_scene5',146,152,'CAPULET','How now, how now, chop-logic! What is this?'),
('romeo_and_juliet_act3_scene5',147,153,'CAPULET','“Proud,” and “I thank you,” and “I thank you not;”'),
('romeo_and_juliet_act3_scene5',148,154,'CAPULET','And yet “not proud:” mistress minion, you,'),
('romeo_and_juliet_act3_scene5',149,155,'CAPULET','Thank me no thankings, nor proud me no prouds,'),
('romeo_and_juliet_act3_scene5',150,156,'CAPULET','But fettle your fine joints ’gainst Thursday next,'),
('romeo_and_juliet_act3_scene5',151,157,'CAPULET','To go with Paris to Saint Peter’s Church,'),
('romeo_and_juliet_act3_scene5',152,158,'CAPULET','Or I will drag thee on a hurdle thither.'),
('romeo_and_juliet_act3_scene5',153,159,'CAPULET','Out, you green-sickness carrion! out, you baggage!'),
('romeo_and_juliet_act3_scene5',154,160,'CAPULET','You tallow-face!'),
('romeo_and_juliet_act3_scene5',154,161,'LADY CAPULET','Fie, fie! what, are you mad?'),
('romeo_and_juliet_act3_scene5',155,162,'JULIET','Good father, I beseech you on my knees,'),
('romeo_and_juliet_act3_scene5',156,163,'JULIET','Hear me with patience but to speak a word.'),
('romeo_and_juliet_act3_scene5',157,164,'CAPULET','Hang thee, young baggage! disobedient wretch!'),
('romeo_and_juliet_act3_scene5',158,165,'CAPULET','I tell thee what: get thee to church o’ Thursday,'),
('romeo_and_juliet_act3_scene5',159,166,'CAPULET','Or never after look me in the face:'),
('romeo_and_juliet_act3_scene5',160,167,'CAPULET','Speak not, reply not, do not answer me;'),
('romeo_and_juliet_act3_scene5',161,168,'CAPULET','My fingers itch. Wife, we scarce thought us blest'),
('romeo_and_juliet_act3_scene5',162,169,'CAPULET','That God had lent us but this only child;'),
('romeo_and_juliet_act3_scene5',163,170,'CAPULET','But now I see this one is one too much,'),
('romeo_and_juliet_act3_scene5',164,171,'CAPULET','And that we have a curse in having her:'),
('romeo_and_juliet_act3_scene5',165,172,'CAPULET','Out on her, hilding!'),
('romeo_and_juliet_act3_scene5',165,173,'NURSE','God in heaven bless her!'),
('romeo_and_juliet_act3_scene5',166,174,'NURSE','You are to blame, my lord, to rate her so.'),
('romeo_and_juliet_act3_scene5',167,175,'CAPULET','And why, my lady wisdom? hold your tongue,'),
('romeo_and_juliet_act3_scene5',168,176,'CAPULET','Good prudence; smatter with your gossips, go.'),
('romeo_and_juliet_act3_scene5',169,177,'NURSE','I speak no treason.'),
('romeo_and_juliet_act3_scene5',169,178,'CAPULET','O, God ye god-den.'),
('romeo_and_juliet_act3_scene5',170,179,'NURSE','May not one speak?'),
('romeo_and_juliet_act3_scene5',170,180,'CAPULET','Peace, you mumbling fool!'),
('romeo_and_juliet_act3_scene5',171,181,'CAPULET','Utter your gravity o’er a gossip’s bowl;'),
('romeo_and_juliet_act3_scene5',172,182,'CAPULET','For here we need it not.'),
('romeo_and_juliet_act3_scene5',172,183,'LADY CAPULET','You are too hot.'),
('romeo_and_juliet_act3_scene5',173,184,'CAPULET','God’s bread! it makes me mad:'),
('romeo_and_juliet_act3_scene5',174,185,'CAPULET','Day, night, hour, tide, time, work, play,'),
('romeo_and_juliet_act3_scene5',175,186,'CAPULET','Alone, in company, still my care hath been'),
('romeo_and_juliet_act3_scene5',176,187,'CAPULET','To have her match’d: and having now provided'),
('romeo_and_juliet_act3_scene5',177,188,'CAPULET','A gentleman of noble parentage,'),
('romeo_and_juliet_act3_scene5',178,189,'CAPULET','Of fair demesnes, youthful, and nobly train’d,'),
('romeo_and_juliet_act3_scene5',179,190,'CAPULET','Stuff’d, as they say, with honourable parts,'),
('romeo_and_juliet_act3_scene5',180,191,'CAPULET','Proportion’d as one’s thought would wish a man;'),
('romeo_and_juliet_act3_scene5',181,192,'CAPULET','And then to have a wretched puling fool,'),
('romeo_and_juliet_act3_scene5',182,193,'CAPULET','A whining mammet, in her fortune’s tender,'),
('romeo_and_juliet_act3_scene5',183,194,'CAPULET','To answer “I’ll not wed; I cannot love,'),
('romeo_and_juliet_act3_scene5',184,195,'CAPULET','I am too young; I pray you, pardon me.”'),
('romeo_and_juliet_act3_scene5',185,196,'CAPULET','But, an you will not wed, I’ll pardon you:'),
('romeo_and_juliet_act3_scene5',186,197,'CAPULET','Graze where you will, you shall not house with me:'),
('romeo_and_juliet_act3_scene5',187,198,'CAPULET','Look to’t, think on’t, I do not use to jest.'),
('romeo_and_juliet_act3_scene5',188,199,'CAPULET','Thursday is near; lay hand on heart, advise:'),
('romeo_and_juliet_act3_scene5',189,200,'CAPULET','An you be mine, I’ll give you to my friend;'),
('romeo_and_juliet_act3_scene5',190,201,'CAPULET','An you be not, hang, beg, starve, die in the streets,'),
('romeo_and_juliet_act3_scene5',191,202,'CAPULET','For, by my soul, I’ll ne’er acknowledge thee,'),
('romeo_and_juliet_act3_scene5',192,203,'CAPULET','Nor what is mine shall never do thee good:'),
('romeo_and_juliet_act3_scene5',193,204,'CAPULET','Trust to’t, bethink you; I’ll not be forsworn.'),
('romeo_and_juliet_act3_scene5',194,205,'JULIET','Is there no pity sitting in the clouds,'),
('romeo_and_juliet_act3_scene5',195,206,'JULIET','That sees into the bottom of my grief?'),
('romeo_and_juliet_act3_scene5',196,207,'JULIET','O, sweet my mother, cast me not away!'),
('romeo_and_juliet_act3_scene5',197,208,'JULIET','Delay this marriage for a month, a week;'),
('romeo_and_juliet_act3_scene5',198,209,'JULIET','Or, if you do not, make the bridal bed'),
('romeo_and_juliet_act3_scene5',199,210,'JULIET','In that dim monument where Tybalt lies.'),
('romeo_and_juliet_act3_scene5',200,211,'LADY CAPULET','Talk not to me, for I’ll not speak a word:'),
('romeo_and_juliet_act3_scene5',201,212,'LADY CAPULET','Do as thou wilt, for I have done with thee.'),
('romeo_and_juliet_act3_scene5',202,213,'JULIET','O God!—O nurse, how shall this be prevented?'),
('romeo_and_juliet_act3_scene5',203,214,'JULIET','My husband is on earth, my faith in heaven;'),
('romeo_and_juliet_act3_scene5',204,215,'JULIET','How shall that faith return again to earth,'),
('romeo_and_juliet_act3_scene5',205,216,'JULIET','Unless that husband send it me from heaven'),
('romeo_and_juliet_act3_scene5',206,217,'JULIET','By leaving earth? comfort me, counsel me.'),
('romeo_and_juliet_act3_scene5',207,218,'JULIET','Alack, alack, that heaven should practise stratagems'),
('romeo_and_juliet_act3_scene5',208,219,'JULIET','Upon so soft a subject as myself!'),
('romeo_and_juliet_act3_scene5',209,220,'JULIET','What say’st thou? hast thou not a word of joy?'),
('romeo_and_juliet_act3_scene5',210,221,'JULIET','Some comfort, nurse.'),
('romeo_and_juliet_act3_scene5',210,222,'NURSE','Faith, here it is.'),
('romeo_and_juliet_act3_scene5',211,223,'NURSE','Romeo is banish’d; and all the world to nothing,'),
('romeo_and_juliet_act3_scene5',212,224,'NURSE','That he dares ne’er come back to challenge you;'),
('romeo_and_juliet_act3_scene5',213,225,'NURSE','Or, if he do, it needs must be by stealth.'),
('romeo_and_juliet_act3_scene5',214,226,'NURSE','Then, since the case so stands as now it doth,'),
('romeo_and_juliet_act3_scene5',215,227,'NURSE','I think it best you married with the county.'),
('romeo_and_juliet_act3_scene5',216,228,'NURSE','O, he’s a lovely gentleman!'),
('romeo_and_juliet_act3_scene5',217,229,'NURSE','Romeo’s a dishclout to him: an eagle, madam,'),
('romeo_and_juliet_act3_scene5',218,230,'NURSE','Hath not so green, so quick, so fair an eye'),
('romeo_and_juliet_act3_scene5',219,231,'NURSE','As Paris hath. Beshrew my very heart,'),
('romeo_and_juliet_act3_scene5',220,232,'NURSE','I think you are happy in this second match,'),
('romeo_and_juliet_act3_scene5',221,233,'NURSE','For it excels your first; or if it did not,'),
('romeo_and_juliet_act3_scene5',222,234,'NURSE','Your first is dead; or ’twere as good he were,'),
('romeo_and_juliet_act3_scene5',223,235,'NURSE','As living here and you no use of him.'),
('romeo_and_juliet_act3_scene5',224,236,'JULIET','Speakest thou from thy heart?'),
('romeo_and_juliet_act3_scene5',224,237,'NURSE','And from my soul too;'),
('romeo_and_juliet_act3_scene5',225,238,'NURSE','Or else beshrew them both.'),
('romeo_and_juliet_act3_scene5',225,239,'JULIET','Amen!'),
('romeo_and_juliet_act3_scene5',226,240,'NURSE','What?'),
('romeo_and_juliet_act3_scene5',227,241,'JULIET','Well, thou hast comforted me marvellous much.'),
('romeo_and_juliet_act3_scene5',228,242,'JULIET','Go in; and tell my lady I am gone,'),
('romeo_and_juliet_act3_scene5',229,243,'JULIET','Having displeased my father, to Laurence’ cell,'),
('romeo_and_juliet_act3_scene5',230,244,'JULIET','To make confession and to be absolved.'),
('romeo_and_juliet_act3_scene5',231,245,'NURSE','Marry, I will; and this is wisely done.'),
('romeo_and_juliet_act3_scene5',232,246,'JULIET','Ancient damnation! O most wicked fiend!'),
('romeo_and_juliet_act3_scene5',233,247,'JULIET','Is it more sin to wish me thus forsworn,'),
('romeo_and_juliet_act3_scene5',234,248,'JULIET','Or to dispraise my lord with that same tongue'),
('romeo_and_juliet_act3_scene5',235,249,'JULIET','Which she hath praised him with above compare'),
('romeo_and_juliet_act3_scene5',236,250,'JULIET','So many thousand times? Go, counsellor;'),
('romeo_and_juliet_act3_scene5',237,251,'JULIET','Thou and my bosom henceforth shall be twain.'),
('romeo_and_juliet_act3_scene5',238,252,'JULIET','I’ll to the friar, to know his remedy:'),
('romeo_and_juliet_act3_scene5',239,253,'JULIET','If all else fail, myself have power to die.'),
('romeo_and_juliet_act4_scene1',1,0,'FRIAR LAURENCE','On Thursday, sir? the time is very short.'),
('romeo_and_juliet_act4_scene1',2,1,'PARIS','My father Capulet will have it so;'),
('romeo_and_juliet_act4_scene1',3,2,'PARIS','And I am nothing slow to slack his haste.'),
('romeo_and_juliet_act4_scene1',4,3,'FRIAR LAURENCE','You say you do not know the lady’s mind:'),
('romeo_and_juliet_act4_scene1',5,4,'FRIAR LAURENCE','Uneven is the course, I like it not.'),
('romeo_and_juliet_act4_scene1',6,5,'PARIS','Immoderately she weeps for Tybalt’s death,'),
('romeo_and_juliet_act4_scene1',7,6,'PARIS','And therefore have I little talk’d of love;'),
('romeo_and_juliet_act4_scene1',8,7,'PARIS','For Venus smiles not in a house of tears.'),
('romeo_and_juliet_act4_scene1',9,8,'PARIS','Now, sir, her father counts it dangerous'),
('romeo_and_juliet_act4_scene1',10,9,'PARIS','That she doth give her sorrow so much sway,'),
('romeo_and_juliet_act4_scene1',11,10,'PARIS','And in his wisdom hastes our marriage,'),
('romeo_and_juliet_act4_scene1',12,11,'PARIS','To stop the inundation of her tears;'),
('romeo_and_juliet_act4_scene1',13,12,'PARIS','Which, too much minded by herself alone,'),
('romeo_and_juliet_act4_scene1',14,13,'PARIS','May be put from her by society:'),
('romeo_and_juliet_act4_scene1',15,14,'PARIS','Now do you know the reason of this haste.'),
('romeo_and_juliet_act4_scene1',16,15,'FRIAR LAURENCE','I would I knew not why it should be slow’d.'),
('romeo_and_juliet_act4_scene1',17,16,'FRIAR LAURENCE','Look, sir, here comes the lady towards my cell.'),
('romeo_and_juliet_act4_scene1',18,17,'PARIS','Happily met, my lady and my wife!'),
('romeo_and_juliet_act4_scene1',19,18,'JULIET','That may be, sir, when I may be a wife.'),
('romeo_and_juliet_act4_scene1',20,19,'PARIS','That may be must be, love, on Thursday next.'),
('romeo_and_juliet_act4_scene1',21,20,'JULIET','What must be shall be.'),
('romeo_and_juliet_act4_scene1',21,21,'FRIAR LAURENCE','That’s a certain text.'),
('romeo_and_juliet_act4_scene1',22,22,'PARIS','Come you to make confession to this father?'),
('romeo_and_juliet_act4_scene1',23,23,'JULIET','To answer that, I should confess to you.'),
('romeo_and_juliet_act4_scene1',24,24,'PARIS','Do not deny to him that you love me.'),
('romeo_and_juliet_act4_scene1',25,25,'JULIET','I will confess to you that I love him.'),
('romeo_and_juliet_act4_scene1',26,26,'PARIS','So will ye, I am sure, that you love me.'),
('romeo_and_juliet_act4_scene1',27,27,'JULIET','If I do so, it will be of more price,'),
('romeo_and_juliet_act4_scene1',28,28,'JULIET','Being spoke behind your back, than to your face.'),
('romeo_and_juliet_act4_scene1',29,29,'PARIS','Poor soul, thy face is much abused with tears.'),
('romeo_and_juliet_act4_scene1',30,30,'JULIET','The tears have got small victory by that;'),
('romeo_and_juliet_act4_scene1',31,31,'JULIET','For it was bad enough before their spite.'),
('romeo_and_juliet_act4_scene1',32,32,'PARIS','Thou wrong’st it, more than tears, with that report.'),
('romeo_and_juliet_act4_scene1',33,33,'JULIET','That is no slander, sir, which is a truth;'),
('romeo_and_juliet_act4_scene1',34,34,'JULIET','And what I spake, I spake it to my face.'),
('romeo_and_juliet_act4_scene1',35,35,'PARIS','Thy face is mine, and thou hast slander’d it.'),
('romeo_and_juliet_act4_scene1',36,36,'JULIET','It may be so, for it is not mine own.'),
('romeo_and_juliet_act4_scene1',37,37,'JULIET','Are you at leisure, holy father, now;'),
('romeo_and_juliet_act4_scene1',38,38,'JULIET','Or shall I come to you at evening mass?'),
('romeo_and_juliet_act4_scene1',39,39,'FRIAR LAURENCE','My leisure serves me, pensive daughter, now.'),
('romeo_and_juliet_act4_scene1',40,40,'FRIAR LAURENCE','My lord, we must entreat the time alone.'),
('romeo_and_juliet_act4_scene1',41,41,'PARIS','God shield I should disturb devotion!'),
('romeo_and_juliet_act4_scene1',42,42,'PARIS','Juliet, on Thursday early will I rouse ye:'),
('romeo_and_juliet_act4_scene1',43,43,'PARIS','Till then, adieu; and keep this holy kiss.'),
('romeo_and_juliet_act4_scene1',44,44,'JULIET','O shut the door! and when thou hast done so,'),
('romeo_and_juliet_act4_scene1',45,45,'JULIET','Come weep with me; past hope, past cure, past help!'),
('romeo_and_juliet_act4_scene1',46,46,'FRIAR LAURENCE','Ah, Juliet, I already know thy grief;'),
('romeo_and_juliet_act4_scene1',47,47,'FRIAR LAURENCE','It strains me past the compass of my wits:'),
('romeo_and_juliet_act4_scene1',48,48,'FRIAR LAURENCE','I hear thou must, and nothing may prorogue it,'),
('romeo_and_juliet_act4_scene1',49,49,'FRIAR LAURENCE','On Thursday next be married to this county.'),
('romeo_and_juliet_act4_scene1',50,50,'JULIET','Tell me not, friar, that thou hear’st of this,'),
('romeo_and_juliet_act4_scene1',51,51,'JULIET','Unless thou tell me how I may prevent it:'),
('romeo_and_juliet_act4_scene1',52,52,'JULIET','If, in thy wisdom, thou canst give no help,'),
('romeo_and_juliet_act4_scene1',53,53,'JULIET','Do thou but call my resolution wise,'),
('romeo_and_juliet_act4_scene1',54,54,'JULIET','And with this knife I’ll help it presently.'),
('romeo_and_juliet_act4_scene1',55,55,'JULIET','God join’d my heart and Romeo’s, thou our hands;'),
('romeo_and_juliet_act4_scene1',56,56,'JULIET','And ere this hand, by thee to Romeo seal’d,'),
('romeo_and_juliet_act4_scene1',57,57,'JULIET','Shall be the label to another deed,'),
('romeo_and_juliet_act4_scene1',58,58,'JULIET','Or my true heart with treacherous revolt'),
('romeo_and_juliet_act4_scene1',59,59,'JULIET','Turn to another, this shall slay them both:'),
('romeo_and_juliet_act4_scene1',60,60,'JULIET','Therefore, out of thy long-experienced time,'),
('romeo_and_juliet_act4_scene1',61,61,'JULIET','Give me some present counsel, or, behold,'),
('romeo_and_juliet_act4_scene1',62,62,'JULIET','’Twixt my extremes and me this bloody knife'),
('romeo_and_juliet_act4_scene1',63,63,'JULIET','Shall play the umpire, arbitrating that'),
('romeo_and_juliet_act4_scene1',64,64,'JULIET','Which the commission of thy years and art'),
('romeo_and_juliet_act4_scene1',65,65,'JULIET','Could to no issue of true honour bring.'),
('romeo_and_juliet_act4_scene1',66,66,'JULIET','Be not so long to speak; I long to die,'),
('romeo_and_juliet_act4_scene1',67,67,'JULIET','If what thou speak’st speak not of remedy.'),
('romeo_and_juliet_act4_scene1',68,68,'FRIAR LAURENCE','Hold, daughter: I do spy a kind of hope,'),
('romeo_and_juliet_act4_scene1',69,69,'FRIAR LAURENCE','Which craves as desperate an execution'),
('romeo_and_juliet_act4_scene1',70,70,'FRIAR LAURENCE','As that is desperate which we would prevent.'),
('romeo_and_juliet_act4_scene1',71,71,'FRIAR LAURENCE','If, rather than to marry County Paris,'),
('romeo_and_juliet_act4_scene1',72,72,'FRIAR LAURENCE','Thou hast the strength of will to slay thyself,'),
('romeo_and_juliet_act4_scene1',73,73,'FRIAR LAURENCE','Then is it likely thou wilt undertake'),
('romeo_and_juliet_act4_scene1',74,74,'FRIAR LAURENCE','A thing like death to chide away this shame,'),
('romeo_and_juliet_act4_scene1',75,75,'FRIAR LAURENCE','That copest with death himself to scape from it;'),
('romeo_and_juliet_act4_scene1',76,76,'FRIAR LAURENCE','And, if thou darest, I’ll give thee remedy.'),
('romeo_and_juliet_act4_scene1',77,77,'JULIET','O, bid me leap, rather than marry Paris,'),
('romeo_and_juliet_act4_scene1',78,78,'JULIET','From off the battlements of yonder tower;'),
('romeo_and_juliet_act4_scene1',79,79,'JULIET','Or walk in thievish ways; or bid me lurk'),
('romeo_and_juliet_act4_scene1',80,80,'JULIET','Where serpents are; chain me with roaring bears;'),
('romeo_and_juliet_act4_scene1',81,81,'JULIET','Or shut me nightly in a charnel-house,'),
('romeo_and_juliet_act4_scene1',82,82,'JULIET','O’er-cover’d quite with dead men’s rattling bones,'),
('romeo_and_juliet_act4_scene1',83,83,'JULIET','With reeky shanks and yellow chapless skulls;'),
('romeo_and_juliet_act4_scene1',84,84,'JULIET','Or bid me go into a new-made grave'),
('romeo_and_juliet_act4_scene1',85,85,'JULIET','And hide me with a dead man in his shroud;'),
('romeo_and_juliet_act4_scene1',86,86,'JULIET','Things that, to hear them told, have made me tremble;'),
('romeo_and_juliet_act4_scene1',87,87,'JULIET','And I will do it without fear or doubt,'),
('romeo_and_juliet_act4_scene1',88,88,'JULIET','To live an unstain’d wife to my sweet love.'),
('romeo_and_juliet_act4_scene1',89,89,'FRIAR LAURENCE','Hold, then; go home, be merry, give consent'),
('romeo_and_juliet_act4_scene1',90,90,'FRIAR LAURENCE','To marry Paris: Wednesday is to-morrow:'),
('romeo_and_juliet_act4_scene1',91,91,'FRIAR LAURENCE','To-morrow night look that thou lie alone;'),
('romeo_and_juliet_act4_scene1',92,92,'FRIAR LAURENCE','Let not thy nurse lie with thee in thy chamber:'),
('romeo_and_juliet_act4_scene1',93,93,'FRIAR LAURENCE','Take thou this vial, being then in bed,'),
('romeo_and_juliet_act4_scene1',94,94,'FRIAR LAURENCE','And this distilled liquor drink thou off;'),
('romeo_and_juliet_act4_scene1',95,95,'FRIAR LAURENCE','When presently through all thy veins shall run'),
('romeo_and_juliet_act4_scene1',96,96,'FRIAR LAURENCE','A cold and drowsy humour, for no pulse'),
('romeo_and_juliet_act4_scene1',97,97,'FRIAR LAURENCE','Shall keep his native progress, but surcease:'),
('romeo_and_juliet_act4_scene1',98,98,'FRIAR LAURENCE','No warmth, no breath, shall testify thou livest;'),
('romeo_and_juliet_act4_scene1',99,99,'FRIAR LAURENCE','The roses in thy lips and cheeks shall fade'),
('romeo_and_juliet_act4_scene1',100,100,'FRIAR LAURENCE','To paly ashes, thy eyes’ windows fall,'),
('romeo_and_juliet_act4_scene1',101,101,'FRIAR LAURENCE','Like death, when he shuts up the day of life;'),
('romeo_and_juliet_act4_scene1',102,102,'FRIAR LAURENCE','Each part, deprived of supple government,'),
('romeo_and_juliet_act4_scene1',103,103,'FRIAR LAURENCE','Shall, stiff and stark and cold, appear like death:'),
('romeo_and_juliet_act4_scene1',104,104,'FRIAR LAURENCE','And in this borrow’d likeness of shrunk death'),
('romeo_and_juliet_act4_scene1',105,105,'FRIAR LAURENCE','Thou shalt continue two and forty hours,'),
('romeo_and_juliet_act4_scene1',106,106,'FRIAR LAURENCE','And then awake as from a pleasant sleep.'),
('romeo_and_juliet_act4_scene1',107,107,'FRIAR LAURENCE','Now, when the bridegroom in the morning comes'),
('romeo_and_juliet_act4_scene1',108,108,'FRIAR LAURENCE','To rouse thee from thy bed, there art thou dead:'),
('romeo_and_juliet_act4_scene1',109,109,'FRIAR LAURENCE','Then, as the manner of our country is,'),
('romeo_and_juliet_act4_scene1',110,110,'FRIAR LAURENCE','In thy best robes uncover’d on the bier'),
('romeo_and_juliet_act4_scene1',111,111,'FRIAR LAURENCE','Thou shalt be borne to that same ancient vault'),
('romeo_and_juliet_act4_scene1',112,112,'FRIAR LAURENCE','Where all the kindred of the Capulets lie.'),
('romeo_and_juliet_act4_scene1',113,113,'FRIAR LAURENCE','In the meantime, against thou shalt awake,'),
('romeo_and_juliet_act4_scene1',114,114,'FRIAR LAURENCE','Shall Romeo by my letters know our drift,'),
('romeo_and_juliet_act4_scene1',115,115,'FRIAR LAURENCE','And hither shall he come: and he and I'),
('romeo_and_juliet_act4_scene1',116,116,'FRIAR LAURENCE','Will watch thy waking, and that very night'),
('romeo_and_juliet_act4_scene1',117,117,'FRIAR LAURENCE','Shall Romeo bear thee hence to Mantua.'),
('romeo_and_juliet_act4_scene1',118,118,'FRIAR LAURENCE','And this shall free thee from this present shame;'),
('romeo_and_juliet_act4_scene1',119,119,'FRIAR LAURENCE','If no inconstant toy, nor womanish fear,'),
('romeo_and_juliet_act4_scene1',120,120,'FRIAR LAURENCE','Abate thy valour in the acting it.'),
('romeo_and_juliet_act4_scene1',121,121,'JULIET','Give me, give me! O, tell not me of fear!'),
('romeo_and_juliet_act4_scene1',122,122,'FRIAR LAURENCE','Hold; get you gone, be strong and prosperous'),
('romeo_and_juliet_act4_scene1',123,123,'FRIAR LAURENCE','In this resolve: I’ll send a friar with speed'),
('romeo_and_juliet_act4_scene1',124,124,'FRIAR LAURENCE','To Mantua, with my letters to thy lord.'),
('romeo_and_juliet_act4_scene1',125,125,'JULIET','Love give me strength! and strength shall help afford.'),
('romeo_and_juliet_act4_scene1',126,126,'JULIET','Farewell, dear father!'),
('romeo_and_juliet_act4_scene2',1,0,'CAPULET','So many guests invite as here are writ.'),
('romeo_and_juliet_act4_scene2',2,1,'CAPULET','Sirrah, go hire me twenty cunning cooks.'),
('romeo_and_juliet_act4_scene2',3,2,'SECOND SERVINGMAN','You shall have none ill, sir; for I’ll try if they can lick their fingers.'),
('romeo_and_juliet_act4_scene2',4,3,'CAPULET','How canst thou try them so?'),
('romeo_and_juliet_act4_scene2',5,4,'SECOND SERVINGMAN','Marry, sir, ’tis an ill cook that cannot lick his own fingers:'),
('romeo_and_juliet_act4_scene2',6,5,'SECOND SERVINGMAN','therefore he that cannot lick his fingers goes not with me.'),
('romeo_and_juliet_act4_scene2',7,6,'CAPULET','Go, be gone.'),
('romeo_and_juliet_act4_scene2',8,7,'CAPULET','We shall be much unfurnish’d for this time.'),
('romeo_and_juliet_act4_scene2',9,8,'CAPULET','What, is my daughter gone to Friar Laurence?'),
('romeo_and_juliet_act4_scene2',10,9,'NURSE','Ay, forsooth.'),
('romeo_and_juliet_act4_scene2',11,10,'CAPULET','Well, he may chance to do some good on her:'),
('romeo_and_juliet_act4_scene2',12,11,'CAPULET','A peevish self-will’d harlotry it is.'),
('romeo_and_juliet_act4_scene2',13,12,'NURSE','See where she comes from shrift with merry look.'),
('romeo_and_juliet_act4_scene2',14,13,'CAPULET','How now, my headstrong! where have you been gadding?'),
('romeo_and_juliet_act4_scene2',15,14,'JULIET','Where I have learn’d me to repent the sin'),
('romeo_and_juliet_act4_scene2',16,15,'JULIET','Of disobedient opposition'),
('romeo_and_juliet_act4_scene2',17,16,'JULIET','To you and your behests, and am enjoin’d'),
('romeo_and_juliet_act4_scene2',18,17,'JULIET','By holy Laurence to fall prostrate here,'),
('romeo_and_juliet_act4_scene2',19,18,'JULIET','And beg your pardon: pardon, I beseech you!'),
('romeo_and_juliet_act4_scene2',20,19,'JULIET','Henceforward I am ever ruled by you.'),
('romeo_and_juliet_act4_scene2',21,20,'CAPULET','Send for the county; go tell him of this:'),
('romeo_and_juliet_act4_scene2',22,21,'CAPULET','I’ll have this knot knit up to-morrow morning.'),
('romeo_and_juliet_act4_scene2',23,22,'JULIET','I met the youthful lord at Laurence’ cell;'),
('romeo_and_juliet_act4_scene2',24,23,'JULIET','And gave him what becomed love I might'),
('romeo_and_juliet_act4_scene2',25,24,'JULIET','Not stepping o’er the bounds of modesty.'),
('romeo_and_juliet_act4_scene2',26,25,'CAPULET','Why, I am glad on’t; this is well: stand up:'),
('romeo_and_juliet_act4_scene2',27,26,'CAPULET','This is as’t should be. Let me see the county;'),
('romeo_and_juliet_act4_scene2',28,27,'CAPULET','Ay, marry, go, I say, and fetch him hither.'),
('romeo_and_juliet_act4_scene2',29,28,'CAPULET','Now, afore God! this reverend holy friar,'),
('romeo_and_juliet_act4_scene2',30,29,'CAPULET','All our whole city is much bound to him.'),
('romeo_and_juliet_act4_scene2',31,30,'JULIET','Nurse, will you go with me into my closet,'),
('romeo_and_juliet_act4_scene2',32,31,'JULIET','To help me sort such needful ornaments'),
('romeo_and_juliet_act4_scene2',33,32,'JULIET','As you think fit to furnish me to-morrow?'),
('romeo_and_juliet_act4_scene2',34,33,'LADY CAPULET','No, not till Thursday; there is time enough.'),
('romeo_and_juliet_act4_scene2',35,34,'CAPULET','Go, nurse, go with her: we’ll to church to-morrow.'),
('romeo_and_juliet_act4_scene2',36,35,'LADY CAPULET','We shall be short in our provision:'),
('romeo_and_juliet_act4_scene2',37,36,'LADY CAPULET','’Tis now near night.'),
('romeo_and_juliet_act4_scene2',37,37,'CAPULET','Tush, I will stir about,'),
('romeo_and_juliet_act4_scene2',38,38,'CAPULET','And all things shall be well, I warrant thee, wife:'),
('romeo_and_juliet_act4_scene2',39,39,'CAPULET','Go thou to Juliet, help to deck up her;'),
('romeo_and_juliet_act4_scene2',40,40,'CAPULET','I’ll not to bed to-night; let me alone;'),
('romeo_and_juliet_act4_scene2',41,41,'CAPULET','I’ll play the housewife for this once. What, ho!'),
('romeo_and_juliet_act4_scene2',42,42,'CAPULET','They are all forth. Well, I will walk myself'),
('romeo_and_juliet_act4_scene2',43,43,'CAPULET','To County Paris, to prepare him up'),
('romeo_and_juliet_act4_scene2',44,44,'CAPULET','Against to-morrow: my heart is wondrous light,'),
('romeo_and_juliet_act4_scene2',45,45,'CAPULET','Since this same wayward girl is so reclaim’d.'),
('romeo_and_juliet_act4_scene3',1,0,'JULIET','Ay, those attires are best: but, gentle nurse,'),
('romeo_and_juliet_act4_scene3',2,1,'JULIET','I pray thee, leave me to myself to-night;'),
('romeo_and_juliet_act4_scene3',3,2,'JULIET','For I have need of many orisons'),
('romeo_and_juliet_act4_scene3',4,3,'JULIET','To move the heavens to smile upon my state,'),
('romeo_and_juliet_act4_scene3',5,4,'JULIET','Which, well thou know’st, is cross and full of sin.'),
('romeo_and_juliet_act4_scene3',6,5,'LADY CAPULET','What, are you busy, ho? need you my help?'),
('romeo_and_juliet_act4_scene3',7,6,'JULIET','No, madam; we have cull’d such necessaries'),
('romeo_and_juliet_act4_scene3',8,7,'JULIET','As are behoveful for our state to-morrow:'),
('romeo_and_juliet_act4_scene3',9,8,'JULIET','So please you, let me now be left alone,'),
('romeo_and_juliet_act4_scene3',10,9,'JULIET','And let the nurse this night sit up with you;'),
('romeo_and_juliet_act4_scene3',11,10,'JULIET','For, I am sure, you have your hands full all,'),
('romeo_and_juliet_act4_scene3',12,11,'JULIET','In this so sudden business.'),
('romeo_and_juliet_act4_scene3',12,12,'LADY CAPULET','Good night:'),
('romeo_and_juliet_act4_scene3',13,13,'LADY CAPULET','Get thee to bed, and rest; for thou hast need.'),
('romeo_and_juliet_act4_scene3',14,14,'JULIET','Farewell! God knows when we shall meet again.'),
('romeo_and_juliet_act4_scene3',15,15,'JULIET','I have a faint cold fear thrills through my veins,'),
('romeo_and_juliet_act4_scene3',16,16,'JULIET','That almost freezes up the heat of life:'),
('romeo_and_juliet_act4_scene3',17,17,'JULIET','I’ll call them back again to comfort me:'),
('romeo_and_juliet_act4_scene3',18,18,'JULIET','Nurse! What should she do here?'),
('romeo_and_juliet_act4_scene3',19,19,'JULIET','My dismal scene I needs must act alone.'),
('romeo_and_juliet_act4_scene3',20,20,'JULIET','Come, vial.'),
('romeo_and_juliet_act4_scene3',21,21,'JULIET','What if this mixture do not work at all?'),
('romeo_and_juliet_act4_scene3',22,22,'JULIET','Shall I be married then to-morrow morning?'),
('romeo_and_juliet_act4_scene3',23,23,'JULIET','No, no: this shall forbid it: lie thou there. Laying down her dagger.'),
('romeo_and_juliet_act4_scene3',24,24,'JULIET','What if it be a poison, which the friar'),
('romeo_and_juliet_act4_scene3',25,25,'JULIET','Subtly hath minister’d to have me dead,'),
('romeo_and_juliet_act4_scene3',26,26,'JULIET','Lest in this marriage he should be dishonour’d,'),
('romeo_and_juliet_act4_scene3',27,27,'JULIET','Because he married me before to Romeo?'),
('romeo_and_juliet_act4_scene3',28,28,'JULIET','I fear it is: and yet, methinks, it should not,'),
('romeo_and_juliet_act4_scene3',29,29,'JULIET','For he hath still been tried a holy man.'),
('romeo_and_juliet_act4_scene3',30,30,'JULIET','How if, when I am laid into the tomb,'),
('romeo_and_juliet_act4_scene3',31,31,'JULIET','I wake before the time that Romeo'),
('romeo_and_juliet_act4_scene3',32,32,'JULIET','Come to redeem me? there’s a fearful point!'),
('romeo_and_juliet_act4_scene3',33,33,'JULIET','Shall I not, then, be stifled in the vault,'),
('romeo_and_juliet_act4_scene3',34,34,'JULIET','To whose foul mouth no healthsome air breathes in,'),
('romeo_and_juliet_act4_scene3',35,35,'JULIET','And there die strangled ere my Romeo comes?'),
('romeo_and_juliet_act4_scene3',36,36,'JULIET','Or, if I live, is it not very like,'),
('romeo_and_juliet_act4_scene3',37,37,'JULIET','The horrible conceit of death and night,'),
('romeo_and_juliet_act4_scene3',38,38,'JULIET','Together with the terror of the place—'),
('romeo_and_juliet_act4_scene3',39,39,'JULIET','As in a vault, an ancient receptacle,'),
('romeo_and_juliet_act4_scene3',40,40,'JULIET','Where, for these many hundred years, the bones'),
('romeo_and_juliet_act4_scene3',41,41,'JULIET','Of all my buried ancestors are pack’d:'),
('romeo_and_juliet_act4_scene3',42,42,'JULIET','Where bloody Tybalt, yet but green in earth,'),
('romeo_and_juliet_act4_scene3',43,43,'JULIET','Lies festering in his shroud; where, as they say,'),
('romeo_and_juliet_act4_scene3',44,44,'JULIET','At some hours in the night spirits resort;—'),
('romeo_and_juliet_act4_scene3',45,45,'JULIET','Alack, alack, is it not like that I,'),
('romeo_and_juliet_act4_scene3',46,46,'JULIET','So early waking, what with loathsome smells,'),
('romeo_and_juliet_act4_scene3',47,47,'JULIET','And shrieks like mandrakes’ torn out of the earth,'),
('romeo_and_juliet_act4_scene3',48,48,'JULIET','That living mortals, hearing them, run mad:—'),
('romeo_and_juliet_act4_scene3',49,49,'JULIET','O, if I wake, shall I not be distraught,'),
('romeo_and_juliet_act4_scene3',50,50,'JULIET','Environed with all these hideous fears?'),
('romeo_and_juliet_act4_scene3',51,51,'JULIET','And madly play with my forefather’s joints?'),
('romeo_and_juliet_act4_scene3',52,52,'JULIET','And pluck the mangled Tybalt from his shroud?'),
('romeo_and_juliet_act4_scene3',53,53,'JULIET','And, in this rage, with some great kinsman’s bone,'),
('romeo_and_juliet_act4_scene3',54,54,'JULIET','As with a club, dash out my desperate brains?'),
('romeo_and_juliet_act4_scene3',55,55,'JULIET','O, look! methinks I see my cousin’s ghost'),
('romeo_and_juliet_act4_scene3',56,56,'JULIET','Seeking out Romeo, that did spit his body'),
('romeo_and_juliet_act4_scene3',57,57,'JULIET','Upon a rapier’s point: stay, Tybalt, stay!'),
('romeo_and_juliet_act4_scene3',58,58,'JULIET','Romeo, I come! this do I drink to thee. She falls upon her bed, within the curtains.'),
('romeo_and_juliet_act4_scene4',1,0,'LADY CAPULET','Hold, take these keys, and fetch more spices, nurse.'),
('romeo_and_juliet_act4_scene4',2,1,'NURSE','They call for dates and quinces in the pastry.'),
('romeo_and_juliet_act4_scene4',3,2,'CAPULET','Come, stir, stir, stir! the second cock hath crow’d,'),
('romeo_and_juliet_act4_scene4',4,3,'CAPULET','The curfew-bell hath rung, ’tis three o’clock:'),
('romeo_and_juliet_act4_scene4',5,4,'CAPULET','Look to the baked meats, good Angelica:'),
('romeo_and_juliet_act4_scene4',6,5,'CAPULET','Spare not for cost.'),
('romeo_and_juliet_act4_scene4',6,6,'NURSE','Go, you cot-quean, go,');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('romeo_and_juliet_act4_scene4',7,7,'NURSE','Get you to bed; faith, You’ll be sick to-morrow'),
('romeo_and_juliet_act4_scene4',8,8,'NURSE','For this night’s watching.'),
('romeo_and_juliet_act4_scene4',9,9,'CAPULET','No, not a whit: what! I have watch’d ere now'),
('romeo_and_juliet_act4_scene4',10,10,'CAPULET','All night for lesser cause, and ne’er been sick.'),
('romeo_and_juliet_act4_scene4',11,11,'LADY CAPULET','Ay, you have been a mouse-hunt in your time;'),
('romeo_and_juliet_act4_scene4',12,12,'LADY CAPULET','But I will watch you from such watching now.'),
('romeo_and_juliet_act4_scene4',13,13,'CAPULET','A jealous-hood, a jealous hood!'),
('romeo_and_juliet_act4_scene4',14,14,'FIRST SERVINGMAN','Things for the cook, sir; but I know not what.'),
('romeo_and_juliet_act4_scene4',15,15,'CAPULET','Make haste, make haste. Sirrah, fetch drier logs:'),
('romeo_and_juliet_act4_scene4',16,16,'CAPULET','Call Peter, he will show thee where they are.'),
('romeo_and_juliet_act4_scene4',17,17,'SECOND SERVINGMAN','I have a head, sir, that will find out logs,'),
('romeo_and_juliet_act4_scene4',18,18,'SECOND SERVINGMAN','And never trouble Peter for the matter.'),
('romeo_and_juliet_act4_scene4',19,19,'CAPULET','Mass, and well said; a merry whoreson, ha!'),
('romeo_and_juliet_act4_scene4',20,20,'CAPULET','Thou shalt be logger-head. Good faith, ’tis day:'),
('romeo_and_juliet_act4_scene4',21,21,'CAPULET','The county will be here with music straight,'),
('romeo_and_juliet_act4_scene4',22,22,'CAPULET','For so he said he would: I hear him near.'),
('romeo_and_juliet_act4_scene4',23,23,'CAPULET','Nurse! Wife! What, ho! What, nurse, I say!'),
('romeo_and_juliet_act4_scene5',1,0,'NURSE','Mistress! what, mistress! Juliet! fast, I warrant her, she:'),
('romeo_and_juliet_act4_scene5',2,1,'NURSE','Why, lamb! why, lady! fie, you slug-a-bed!'),
('romeo_and_juliet_act4_scene5',3,2,'NURSE','Why, love, I say! madam! sweet-heart! why, bride!'),
('romeo_and_juliet_act4_scene5',4,3,'NURSE','What, not a word? you take your pennyworths now;'),
('romeo_and_juliet_act4_scene5',5,4,'NURSE','Sleep for a week; for the next night, I warrant,'),
('romeo_and_juliet_act4_scene5',6,5,'NURSE','The County Paris hath set up his rest,'),
('romeo_and_juliet_act4_scene5',7,6,'NURSE','That you shall rest but little. God forgive me,'),
('romeo_and_juliet_act4_scene5',8,7,'NURSE','Marry, and amen, how sound is she asleep!'),
('romeo_and_juliet_act4_scene5',9,8,'NURSE','I must needs wake her. Madam, madam, madam!'),
('romeo_and_juliet_act4_scene5',10,9,'NURSE','Ay, let the county take you in your bed;'),
('romeo_and_juliet_act4_scene5',11,10,'NURSE','He’ll fright you up, i’ faith. Will it not be? Undraws the curtains.'),
('romeo_and_juliet_act4_scene5',12,11,'NURSE','What, dress’d! and in your clothes! and down again!'),
('romeo_and_juliet_act4_scene5',13,12,'NURSE','I must needs wake you: Lady! lady! lady!'),
('romeo_and_juliet_act4_scene5',14,13,'NURSE','Alas, alas! Help, help! my lady’s dead!'),
('romeo_and_juliet_act4_scene5',15,14,'NURSE','O, well-a-day, that ever I was born!'),
('romeo_and_juliet_act4_scene5',16,15,'NURSE','Some aqua vitae, ho! My lord! my lady!'),
('romeo_and_juliet_act4_scene5',17,16,'LADY CAPULET','What noise is here?'),
('romeo_and_juliet_act4_scene5',17,17,'NURSE','O lamentable day!'),
('romeo_and_juliet_act4_scene5',18,18,'LADY CAPULET','What is the matter?'),
('romeo_and_juliet_act4_scene5',18,19,'NURSE','Look, look! O heavy day!'),
('romeo_and_juliet_act4_scene5',19,20,'LADY CAPULET','O me, O me! My child, my only life,'),
('romeo_and_juliet_act4_scene5',20,21,'LADY CAPULET','Revive, look up, or I will die with thee!'),
('romeo_and_juliet_act4_scene5',21,22,'LADY CAPULET','Help, help! Call help.'),
('romeo_and_juliet_act4_scene5',22,23,'CAPULET','For shame, bring Juliet forth; her lord is come.'),
('romeo_and_juliet_act4_scene5',23,24,'NURSE','She’s dead, deceased, she’s dead; alack the day!'),
('romeo_and_juliet_act4_scene5',24,25,'LADY CAPULET','Alack the day, she’s dead, she’s dead, she’s dead!'),
('romeo_and_juliet_act4_scene5',25,26,'CAPULET','Ha! let me see her: out, alas! she’s cold;'),
('romeo_and_juliet_act4_scene5',26,27,'CAPULET','Her blood is settled, and her joints are stiff;'),
('romeo_and_juliet_act4_scene5',27,28,'CAPULET','Life and these lips have long been separated:'),
('romeo_and_juliet_act4_scene5',28,29,'CAPULET','Death lies on her like an untimely frost'),
('romeo_and_juliet_act4_scene5',29,30,'CAPULET','Upon the sweetest flower of all the field.'),
('romeo_and_juliet_act4_scene5',30,31,'NURSE','O lamentable day!'),
('romeo_and_juliet_act4_scene5',30,32,'LADY CAPULET','O woeful time!'),
('romeo_and_juliet_act4_scene5',31,33,'CAPULET','Death, that hath ta’en her hence to make me wail,'),
('romeo_and_juliet_act4_scene5',32,34,'CAPULET','Ties up my tongue, and will not let me speak.'),
('romeo_and_juliet_act4_scene5',33,35,'FRIAR LAURENCE','Come, is the bride ready to go to church?'),
('romeo_and_juliet_act4_scene5',34,36,'CAPULET','Ready to go, but never to return.'),
('romeo_and_juliet_act4_scene5',35,37,'CAPULET','O son! the night before thy wedding-day'),
('romeo_and_juliet_act4_scene5',36,38,'CAPULET','Hath Death lain with thy wife. There she lies,'),
('romeo_and_juliet_act4_scene5',37,39,'CAPULET','Flower as she was, deflowered by him.'),
('romeo_and_juliet_act4_scene5',38,40,'CAPULET','Death is my son-in-law, Death is my heir;'),
('romeo_and_juliet_act4_scene5',39,41,'CAPULET','My daughter he hath wedded: I will die,'),
('romeo_and_juliet_act4_scene5',40,42,'CAPULET','And leave him all; life, living, all is Death’s.'),
('romeo_and_juliet_act4_scene5',41,43,'PARIS','Have I thought long to see this morning’s face,'),
('romeo_and_juliet_act4_scene5',42,44,'PARIS','And doth it give me such a sight as this?'),
('romeo_and_juliet_act4_scene5',43,45,'LADY CAPULET','Accursed, unhappy, wretched, hateful day!'),
('romeo_and_juliet_act4_scene5',44,46,'LADY CAPULET','Most miserable hour that e’er time saw'),
('romeo_and_juliet_act4_scene5',45,47,'LADY CAPULET','In lasting labour of his pilgrimage!'),
('romeo_and_juliet_act4_scene5',46,48,'LADY CAPULET','But one, poor one, one poor and loving child,'),
('romeo_and_juliet_act4_scene5',47,49,'LADY CAPULET','But one thing to rejoice and solace in,'),
('romeo_and_juliet_act4_scene5',48,50,'LADY CAPULET','And cruel death hath catch’d it from my sight!'),
('romeo_and_juliet_act4_scene5',49,51,'NURSE','O woe! O woeful, woeful, woeful day!'),
('romeo_and_juliet_act4_scene5',50,52,'NURSE','Most lamentable day, most woeful day,'),
('romeo_and_juliet_act4_scene5',51,53,'NURSE','That ever, ever, I did yet behold!'),
('romeo_and_juliet_act4_scene5',52,54,'NURSE','O day! O day! O day! O hateful day!'),
('romeo_and_juliet_act4_scene5',53,55,'NURSE','Never was seen so black a day as this:'),
('romeo_and_juliet_act4_scene5',54,56,'NURSE','O woeful day, O woeful day!'),
('romeo_and_juliet_act4_scene5',54,57,'PARIS','Beguiled, divorced, wronged, spited, slain!'),
('romeo_and_juliet_act4_scene5',55,58,'PARIS','Most detestable death, by thee beguiled,'),
('romeo_and_juliet_act4_scene5',56,59,'PARIS','By cruel cruel thee quite overthrown!'),
('romeo_and_juliet_act4_scene5',57,60,'PARIS','O love! O life! not life, but love in death!'),
('romeo_and_juliet_act4_scene5',58,61,'CAPULET','Despised, distressed, hated, martyr’d, kill’d!'),
('romeo_and_juliet_act4_scene5',59,62,'CAPULET','Uncomfortable time, why camest thou now'),
('romeo_and_juliet_act4_scene5',60,63,'CAPULET','To murder, murder our solemnity?'),
('romeo_and_juliet_act4_scene5',61,64,'CAPULET','O child! O child! my soul, and not my child!'),
('romeo_and_juliet_act4_scene5',62,65,'CAPULET','Dead art thou! Alack! my child is dead;'),
('romeo_and_juliet_act4_scene5',63,66,'CAPULET','And with my child my joys are buried.'),
('romeo_and_juliet_act4_scene5',64,67,'FRIAR LAURENCE','Peace, ho, for shame! confusion’s cure lives not'),
('romeo_and_juliet_act4_scene5',65,68,'FRIAR LAURENCE','In these confusions. Heaven and yourself'),
('romeo_and_juliet_act4_scene5',66,69,'FRIAR LAURENCE','Had part in this fair maid; now heaven hath all,'),
('romeo_and_juliet_act4_scene5',67,70,'FRIAR LAURENCE','And all the better is it for the maid:'),
('romeo_and_juliet_act4_scene5',68,71,'FRIAR LAURENCE','Your part in her you could not keep from death,'),
('romeo_and_juliet_act4_scene5',69,72,'FRIAR LAURENCE','But heaven keeps his part in eternal life.'),
('romeo_and_juliet_act4_scene5',70,73,'FRIAR LAURENCE','The most you sought was her promotion;'),
('romeo_and_juliet_act4_scene5',71,74,'FRIAR LAURENCE','For ’twas your heaven she should be advanced:'),
('romeo_and_juliet_act4_scene5',72,75,'FRIAR LAURENCE','And weep ye now, seeing she is advanced'),
('romeo_and_juliet_act4_scene5',73,76,'FRIAR LAURENCE','Above the clouds, as high as heaven itself?'),
('romeo_and_juliet_act4_scene5',74,77,'FRIAR LAURENCE','O, in this love, you love your child so ill,'),
('romeo_and_juliet_act4_scene5',75,78,'FRIAR LAURENCE','That you run mad, seeing that she is well:'),
('romeo_and_juliet_act4_scene5',76,79,'FRIAR LAURENCE','She’s not well married that lives married long;'),
('romeo_and_juliet_act4_scene5',77,80,'FRIAR LAURENCE','But she’s best married that dies married young.'),
('romeo_and_juliet_act4_scene5',78,81,'FRIAR LAURENCE','Dry up your tears, and stick your rosemary'),
('romeo_and_juliet_act4_scene5',79,82,'FRIAR LAURENCE','On this fair corse; and, as the custom is,'),
('romeo_and_juliet_act4_scene5',80,83,'FRIAR LAURENCE','In all her best array bear her to church:'),
('romeo_and_juliet_act4_scene5',81,84,'FRIAR LAURENCE','For though fond nature bids us all lament,'),
('romeo_and_juliet_act4_scene5',82,85,'FRIAR LAURENCE','Yet nature’s tears are reason’s merriment.'),
('romeo_and_juliet_act4_scene5',82,86,'CAPULET','All things that we ordained festival,'),
('romeo_and_juliet_act4_scene5',83,87,'CAPULET','Turn from their office to black funeral;'),
('romeo_and_juliet_act4_scene5',84,88,'CAPULET','Our instruments to melancholy bells,'),
('romeo_and_juliet_act4_scene5',85,89,'CAPULET','Our wedding cheer to a sad burial feast,'),
('romeo_and_juliet_act4_scene5',86,90,'CAPULET','Our solemn hymns to sullen dirges change,'),
('romeo_and_juliet_act4_scene5',87,91,'CAPULET','Our bridal flowers serve for a buried corse,'),
('romeo_and_juliet_act4_scene5',88,92,'CAPULET','And all things change them to the contrary.'),
('romeo_and_juliet_act4_scene5',89,93,'FRIAR LAURENCE','Sir, go you in; and, madam, go with him;'),
('romeo_and_juliet_act4_scene5',90,94,'FRIAR LAURENCE','And go, Sir Paris; everyone prepare'),
('romeo_and_juliet_act4_scene5',91,95,'FRIAR LAURENCE','To follow this fair corse unto her grave:'),
('romeo_and_juliet_act4_scene5',92,96,'FRIAR LAURENCE','The heavens do lour upon you for some ill;'),
('romeo_and_juliet_act4_scene5',93,97,'FRIAR LAURENCE','Move them no more by crossing their high will.'),
('romeo_and_juliet_act4_scene5',94,98,'FIRST MUSICIAN','Faith, we may put up our pipes, and be gone.'),
('romeo_and_juliet_act4_scene5',95,99,'NURSE','Honest good fellows, ah, put up, put up;'),
('romeo_and_juliet_act4_scene5',96,100,'NURSE','For, well you know, this is a pitiful case.'),
('romeo_and_juliet_act4_scene5',97,101,'FIRST MUSICIAN','Ay, by my troth, the case may be amended.'),
('romeo_and_juliet_act4_scene5',98,102,'PETER','Musicians, O, musicians, “Heart’s ease, Heart’s ease:” O, an you will have'),
('romeo_and_juliet_act4_scene5',99,103,'PETER','me live, play “Heart’s ease.”'),
('romeo_and_juliet_act4_scene5',99,104,'FIRST MUSICIAN','Why “Heart’s ease”?'),
('romeo_and_juliet_act4_scene5',100,105,'PETER','O, musicians, because my heart itself plays “My heart is full of'),
('romeo_and_juliet_act4_scene5',101,106,'PETER','woe:” O, play me some merry dump, to comfort me.'),
('romeo_and_juliet_act4_scene5',102,107,'FIRST MUSICIAN','Not a dump we; ’tis no time to play now.'),
('romeo_and_juliet_act4_scene5',103,108,'PETER','You will not, then?'),
('romeo_and_juliet_act4_scene5',103,109,'FIRST MUSICIAN','No.'),
('romeo_and_juliet_act4_scene5',104,110,'PETER','I will then give it you soundly.'),
('romeo_and_juliet_act4_scene5',105,111,'FIRST MUSICIAN','What will you give us?'),
('romeo_and_juliet_act4_scene5',106,112,'PETER','No money, on my faith, but the gleek; I will give you the minstrel.'),
('romeo_and_juliet_act4_scene5',107,113,'FIRST MUSICIAN','Then I will give you the serving-creature.'),
('romeo_and_juliet_act4_scene5',108,114,'PETER','Then will I lay the serving-creature’s dagger on your pate. I will'),
('romeo_and_juliet_act4_scene5',109,115,'PETER','carry no crotchets: I’ll re you, I’ll fa you; do you note'),
('romeo_and_juliet_act4_scene5',110,116,'PETER','me?'),
('romeo_and_juliet_act4_scene5',111,117,'FIRST MUSICIAN','An you re us and fa us, you note us.'),
('romeo_and_juliet_act4_scene5',112,118,'SECOND MUSICIAN','Pray you, put up your dagger, and put out your wit.'),
('romeo_and_juliet_act4_scene5',113,119,'PETER','Then have at you with my wit! I will dry-beat you with'),
('romeo_and_juliet_act4_scene5',114,120,'PETER','an iron wit, and put up my iron dagger. Answer me like'),
('romeo_and_juliet_act4_scene5',115,121,'PETER','men: “When griping grief the heart doth wound, And doleful dumps the'),
('romeo_and_juliet_act4_scene5',116,122,'PETER','mind oppress, Then music with her silver sound”— why “silver sound”? why'),
('romeo_and_juliet_act4_scene5',117,123,'PETER','“music with her silver sound”? What say you, Simon Catling?'),
('romeo_and_juliet_act4_scene5',118,124,'FIRST MUSICIAN','Marry, sir, because silver hath a sweet sound.'),
('romeo_and_juliet_act4_scene5',119,125,'PETER','Pretty! What say you, Hugh Rebeck?'),
('romeo_and_juliet_act4_scene5',120,126,'SECOND MUSICIAN','I say “silver sound,” because musicians sound for silver.'),
('romeo_and_juliet_act4_scene5',121,127,'PETER','Pretty too! What say you, James Soundpost?'),
('romeo_and_juliet_act4_scene5',122,128,'THIRD MUSICIAN','Faith, I know not what to say.'),
('romeo_and_juliet_act4_scene5',123,129,'PETER','O, I cry you mercy; you are the singer: I will say'),
('romeo_and_juliet_act4_scene5',124,130,'PETER','for you. It is “music with her silver sound,” because musicians have'),
('romeo_and_juliet_act4_scene5',125,131,'PETER','no gold for sounding: “Then music with her silver sound With speedy'),
('romeo_and_juliet_act4_scene5',126,132,'PETER','help doth lend redress.”'),
('romeo_and_juliet_act4_scene5',127,133,'FIRST MUSICIAN','What a pestilent knave is this same!'),
('romeo_and_juliet_act4_scene5',128,134,'SECOND MUSICIAN','Hang him, Jack! Come, we’ll in here; tarry for the mourners, and stay dinner.'),
('romeo_and_juliet_act5_scene1',1,0,'ROMEO','If I may trust the flattering truth of sleep,'),
('romeo_and_juliet_act5_scene1',2,1,'ROMEO','My dreams presage some joyful news at hand:'),
('romeo_and_juliet_act5_scene1',3,2,'ROMEO','My bosom’s lord sits lightly in his throne;'),
('romeo_and_juliet_act5_scene1',4,3,'ROMEO','And all this day an unaccustom’d spirit'),
('romeo_and_juliet_act5_scene1',5,4,'ROMEO','Lifts me above the ground with cheerful thoughts.'),
('romeo_and_juliet_act5_scene1',6,5,'ROMEO','I dreamt my lady came and found me dead—'),
('romeo_and_juliet_act5_scene1',7,6,'ROMEO','Strange dream, that gives a dead man leave to think!—'),
('romeo_and_juliet_act5_scene1',8,7,'ROMEO','And breathed such life with kisses in my lips,'),
('romeo_and_juliet_act5_scene1',9,8,'ROMEO','That I revived, and was an emperor.'),
('romeo_and_juliet_act5_scene1',10,9,'ROMEO','Ah me! how sweet is love itself possess’d,'),
('romeo_and_juliet_act5_scene1',11,10,'ROMEO','When but love’s shadows are so rich in joy!'),
('romeo_and_juliet_act5_scene1',12,11,'BALTHASAR','Then she is well, and nothing can be ill:'),
('romeo_and_juliet_act5_scene1',13,12,'BALTHASAR','Her body sleeps in Capel’s monument,'),
('romeo_and_juliet_act5_scene1',14,13,'BALTHASAR','And her immortal part with angels lives.'),
('romeo_and_juliet_act5_scene1',15,14,'BALTHASAR','I saw her laid low in her kindred’s vault,'),
('romeo_and_juliet_act5_scene1',16,15,'BALTHASAR','And presently took post to tell it you:'),
('romeo_and_juliet_act5_scene1',17,16,'BALTHASAR','O, pardon me for bringing these ill news,'),
('romeo_and_juliet_act5_scene1',18,17,'BALTHASAR','Since you did leave it for my office, sir.'),
('romeo_and_juliet_act5_scene1',19,18,'ROMEO','Is it even so? then I defy you, stars!'),
('romeo_and_juliet_act5_scene1',20,19,'ROMEO','Thou know’st my lodging: get me ink and paper,'),
('romeo_and_juliet_act5_scene1',21,20,'ROMEO','And hire post-horses; I will hence to-night.'),
('romeo_and_juliet_act5_scene1',22,21,'BALTHASAR','I do beseech you, sir, have patience:'),
('romeo_and_juliet_act5_scene1',23,22,'BALTHASAR','Your looks are pale and wild, and do import'),
('romeo_and_juliet_act5_scene1',24,23,'BALTHASAR','Some misadventure.'),
('romeo_and_juliet_act5_scene1',24,24,'ROMEO','Tush, thou art deceived:'),
('romeo_and_juliet_act5_scene1',25,25,'ROMEO','Leave me, and do the thing I bid thee do.'),
('romeo_and_juliet_act5_scene1',26,26,'ROMEO','Hast thou no letters to me from the friar?'),
('romeo_and_juliet_act5_scene1',27,27,'BALTHASAR','No, my good lord.'),
('romeo_and_juliet_act5_scene1',27,28,'ROMEO','No matter: get thee gone,'),
('romeo_and_juliet_act5_scene1',28,29,'ROMEO','And hire those horses; I’ll be with thee straight.'),
('romeo_and_juliet_act5_scene1',29,30,'ROMEO','Well, Juliet, I will lie with thee to-night.'),
('romeo_and_juliet_act5_scene1',30,31,'ROMEO','Let’s see for means: O mischief, thou art swift'),
('romeo_and_juliet_act5_scene1',31,32,'ROMEO','To enter in the thoughts of desperate men!'),
('romeo_and_juliet_act5_scene1',32,33,'ROMEO','I do remember an apothecary—'),
('romeo_and_juliet_act5_scene1',33,34,'ROMEO','And hereabouts he dwells—which late I noted'),
('romeo_and_juliet_act5_scene1',34,35,'ROMEO','In tatter’d weeds, with overwhelming brows,'),
('romeo_and_juliet_act5_scene1',35,36,'ROMEO','Culling of simples; meagre were his looks,'),
('romeo_and_juliet_act5_scene1',36,37,'ROMEO','Sharp misery had worn him to the bones:'),
('romeo_and_juliet_act5_scene1',37,38,'ROMEO','And in his needy shop a tortoise hung,'),
('romeo_and_juliet_act5_scene1',38,39,'ROMEO','An alligator stuff’d, and other skins'),
('romeo_and_juliet_act5_scene1',39,40,'ROMEO','Of ill-shaped fishes; and about his shelves'),
('romeo_and_juliet_act5_scene1',40,41,'ROMEO','A beggarly account of empty boxes,'),
('romeo_and_juliet_act5_scene1',41,42,'ROMEO','Green earthen pots, bladders and musty seeds,'),
('romeo_and_juliet_act5_scene1',42,43,'ROMEO','Remnants of packthread and old cakes of roses,'),
('romeo_and_juliet_act5_scene1',43,44,'ROMEO','Were thinly scatter’d, to make up a show.'),
('romeo_and_juliet_act5_scene1',44,45,'ROMEO','Noting this penury, to myself I said'),
('romeo_and_juliet_act5_scene1',45,46,'ROMEO','“An if a man did need a poison now,'),
('romeo_and_juliet_act5_scene1',46,47,'ROMEO','Whose sale is present death in Mantua,'),
('romeo_and_juliet_act5_scene1',47,48,'ROMEO','Here lives a caitiff wretch would sell it him.”'),
('romeo_and_juliet_act5_scene1',48,49,'ROMEO','O, this same thought did but forerun my need;'),
('romeo_and_juliet_act5_scene1',49,50,'ROMEO','And this same needy man must sell it me.'),
('romeo_and_juliet_act5_scene1',50,51,'ROMEO','As I remember, this should be the house.'),
('romeo_and_juliet_act5_scene1',51,52,'ROMEO','Being holiday, the beggar’s shop is shut.'),
('romeo_and_juliet_act5_scene1',52,53,'ROMEO','What, ho! apothecary!'),
('romeo_and_juliet_act5_scene1',52,54,'APOTHECARY','Who calls so loud?'),
('romeo_and_juliet_act5_scene1',53,55,'ROMEO','Come hither, man. I see that thou art poor:'),
('romeo_and_juliet_act5_scene1',54,56,'ROMEO','Hold, there is forty ducats: let me have'),
('romeo_and_juliet_act5_scene1',55,57,'ROMEO','A dram of poison, such soon-speeding gear'),
('romeo_and_juliet_act5_scene1',56,58,'ROMEO','As will disperse itself through all the veins'),
('romeo_and_juliet_act5_scene1',57,59,'ROMEO','That the life-weary taker may fall dead'),
('romeo_and_juliet_act5_scene1',58,60,'ROMEO','And that the trunk may be discharged of breath'),
('romeo_and_juliet_act5_scene1',59,61,'ROMEO','As violently as hasty powder fired'),
('romeo_and_juliet_act5_scene1',60,62,'ROMEO','Doth hurry from the fatal cannon’s womb.'),
('romeo_and_juliet_act5_scene1',61,63,'APOTHECARY','Such mortal drugs I have; but Mantua’s law'),
('romeo_and_juliet_act5_scene1',62,64,'APOTHECARY','Is death to any he that utters them.'),
('romeo_and_juliet_act5_scene1',63,65,'ROMEO','Art thou so bare and full of wretchedness,'),
('romeo_and_juliet_act5_scene1',64,66,'ROMEO','And fear’st to die? famine is in thy cheeks,'),
('romeo_and_juliet_act5_scene1',65,67,'ROMEO','Need and oppression starveth in thine eyes,'),
('romeo_and_juliet_act5_scene1',66,68,'ROMEO','Contempt and beggary hangs upon thy back;'),
('romeo_and_juliet_act5_scene1',67,69,'ROMEO','The world is not thy friend nor the world’s law;'),
('romeo_and_juliet_act5_scene1',68,70,'ROMEO','The world affords no law to make thee rich;'),
('romeo_and_juliet_act5_scene1',69,71,'ROMEO','Then be not poor, but break it, and take this.'),
('romeo_and_juliet_act5_scene1',70,72,'APOTHECARY','My poverty, but not my will, consents.'),
('romeo_and_juliet_act5_scene1',71,73,'ROMEO','I pay thy poverty, and not thy will.'),
('romeo_and_juliet_act5_scene1',72,74,'APOTHECARY','Put this in any liquid thing you will,'),
('romeo_and_juliet_act5_scene1',73,75,'APOTHECARY','And drink it off; and, if you had the strength'),
('romeo_and_juliet_act5_scene1',74,76,'APOTHECARY','Of twenty men, it would dispatch you straight.'),
('romeo_and_juliet_act5_scene1',75,77,'ROMEO','There is thy gold, worse poison to men’s souls,'),
('romeo_and_juliet_act5_scene1',76,78,'ROMEO','Doing more murders in this loathsome world,'),
('romeo_and_juliet_act5_scene1',77,79,'ROMEO','Than these poor compounds that thou mayst not sell.'),
('romeo_and_juliet_act5_scene1',78,80,'ROMEO','I sell thee poison; thou hast sold me none.'),
('romeo_and_juliet_act5_scene1',79,81,'ROMEO','Farewell: buy food, and get thyself in flesh.'),
('romeo_and_juliet_act5_scene1',80,82,'ROMEO','Come, cordial and not poison, go with me'),
('romeo_and_juliet_act5_scene1',81,83,'ROMEO','To Juliet’s grave; for there must I use thee.'),
('romeo_and_juliet_act5_scene2',1,0,'FRIAR JOHN','Holy Franciscan friar! brother, ho!'),
('romeo_and_juliet_act5_scene2',2,1,'FRIAR LAURENCE','This same should be the voice of Friar John.'),
('romeo_and_juliet_act5_scene2',3,2,'FRIAR LAURENCE','Welcome from Mantua: what says Romeo?'),
('romeo_and_juliet_act5_scene2',4,3,'FRIAR LAURENCE','Or, if his mind be writ, give me his letter.'),
('romeo_and_juliet_act5_scene2',5,4,'FRIAR JOHN','Going to find a bare-foot brother out'),
('romeo_and_juliet_act5_scene2',6,5,'FRIAR JOHN','One of our order, to associate me,'),
('romeo_and_juliet_act5_scene2',7,6,'FRIAR JOHN','Here in this city visiting the sick,'),
('romeo_and_juliet_act5_scene2',8,7,'FRIAR JOHN','And finding him, the searchers of the town,'),
('romeo_and_juliet_act5_scene2',9,8,'FRIAR JOHN','Suspecting that we both were in a house'),
('romeo_and_juliet_act5_scene2',10,9,'FRIAR JOHN','Where the infectious pestilence did reign,'),
('romeo_and_juliet_act5_scene2',11,10,'FRIAR JOHN','Seal’d up the doors, and would not let us forth;'),
('romeo_and_juliet_act5_scene2',12,11,'FRIAR JOHN','So that my speed to Mantua there was stay’d.'),
('romeo_and_juliet_act5_scene2',13,12,'FRIAR LAURENCE','Who bare my letter, then, to Romeo?'),
('romeo_and_juliet_act5_scene2',14,13,'FRIAR JOHN','I could not send it—here it is again—'),
('romeo_and_juliet_act5_scene2',15,14,'FRIAR JOHN','Nor get a messenger to bring it thee,'),
('romeo_and_juliet_act5_scene2',16,15,'FRIAR JOHN','So fearful were they of infection.'),
('romeo_and_juliet_act5_scene2',16,16,'FRIAR LAURENCE','Unhappy fortune! by my brotherhood,'),
('romeo_and_juliet_act5_scene2',17,17,'FRIAR LAURENCE','The letter was not nice but full of charge'),
('romeo_and_juliet_act5_scene2',18,18,'FRIAR LAURENCE','Of dear import, and the neglecting it'),
('romeo_and_juliet_act5_scene2',19,19,'FRIAR LAURENCE','May do much danger. Friar John, go hence;'),
('romeo_and_juliet_act5_scene2',20,20,'FRIAR LAURENCE','Get me an iron crow, and bring it straight'),
('romeo_and_juliet_act5_scene2',21,21,'FRIAR LAURENCE','Unto my cell.'),
('romeo_and_juliet_act5_scene2',22,22,'FRIAR JOHN','Brother, I’ll go and bring it thee.'),
('romeo_and_juliet_act5_scene2',23,23,'FRIAR LAURENCE','Now must I to the monument alone;'),
('romeo_and_juliet_act5_scene2',24,24,'FRIAR LAURENCE','Within three hours will fair Juliet wake:'),
('romeo_and_juliet_act5_scene2',25,25,'FRIAR LAURENCE','She will beshrew me much that Romeo'),
('romeo_and_juliet_act5_scene2',26,26,'FRIAR LAURENCE','Hath had no notice of these accidents;'),
('romeo_and_juliet_act5_scene2',27,27,'FRIAR LAURENCE','But I will write again to Mantua,'),
('romeo_and_juliet_act5_scene2',28,28,'FRIAR LAURENCE','And keep her at my cell till Romeo come;'),
('romeo_and_juliet_act5_scene2',29,29,'FRIAR LAURENCE','Poor living corse, closed in a dead man’s tomb!'),
('romeo_and_juliet_act5_scene3',1,0,'PARIS','Give me thy torch, boy: hence, and stand aloof:'),
('romeo_and_juliet_act5_scene3',2,1,'PARIS','Yet put it out, for I would not be seen.'),
('romeo_and_juliet_act5_scene3',3,2,'PARIS','Under yond yew-trees lay thee all along,'),
('romeo_and_juliet_act5_scene3',4,3,'PARIS','Holding thine ear close to the hollow ground;'),
('romeo_and_juliet_act5_scene3',5,4,'PARIS','So shall no foot upon the churchyard tread,'),
('romeo_and_juliet_act5_scene3',6,5,'PARIS','Being loose, unfirm, with digging up of graves,'),
('romeo_and_juliet_act5_scene3',7,6,'PARIS','But thou shalt hear it: whistle then to me,'),
('romeo_and_juliet_act5_scene3',8,7,'PARIS','As signal that thou hear’st something approach.'),
('romeo_and_juliet_act5_scene3',9,8,'PARIS','Give me those flowers. Do as I bid thee, go.'),
('romeo_and_juliet_act5_scene3',10,9,'PAGE','I am almost afraid to stand alone'),
('romeo_and_juliet_act5_scene3',11,10,'PAGE','Here in the churchyard; yet I will adventure.'),
('romeo_and_juliet_act5_scene3',12,11,'PARIS','Sweet flower, with flowers thy bridal bed I strew—'),
('romeo_and_juliet_act5_scene3',13,12,'PARIS','O woe! thy canopy is dust and stones;—'),
('romeo_and_juliet_act5_scene3',14,13,'PARIS','Which with sweet water nightly I will dew,'),
('romeo_and_juliet_act5_scene3',15,14,'PARIS','Or, wanting that, with tears distill’d by moans:'),
('romeo_and_juliet_act5_scene3',16,15,'PARIS','The obsequies that I for thee will keep'),
('romeo_and_juliet_act5_scene3',17,16,'PARIS','Nightly shall be to strew thy grave and weep. The Page whistles.'),
('romeo_and_juliet_act5_scene3',18,17,'PARIS','The boy gives warning something doth approach.'),
('romeo_and_juliet_act5_scene3',19,18,'PARIS','What cursed foot wanders this way to-night,'),
('romeo_and_juliet_act5_scene3',20,19,'PARIS','To cross my obsequies and true love’s rite?'),
('romeo_and_juliet_act5_scene3',21,20,'PARIS','What, with a torch! muffle me, night, awhile.'),
('romeo_and_juliet_act5_scene3',22,21,'ROMEO','Give me that mattock and the wrenching iron.'),
('romeo_and_juliet_act5_scene3',23,22,'ROMEO','Hold, take this letter; early in the morning'),
('romeo_and_juliet_act5_scene3',24,23,'ROMEO','See thou deliver it to my lord and father.'),
('romeo_and_juliet_act5_scene3',25,24,'ROMEO','Give me the light: upon thy life, I charge thee,'),
('romeo_and_juliet_act5_scene3',26,25,'ROMEO','Whate’er thou hear’st or seest, stand all aloof,'),
('romeo_and_juliet_act5_scene3',27,26,'ROMEO','And do not interrupt me in my course.'),
('romeo_and_juliet_act5_scene3',28,27,'ROMEO','Why I descend into this bed of death,'),
('romeo_and_juliet_act5_scene3',29,28,'ROMEO','Is partly to behold my lady’s face;'),
('romeo_and_juliet_act5_scene3',30,29,'ROMEO','But chiefly to take thence from her dead finger'),
('romeo_and_juliet_act5_scene3',31,30,'ROMEO','A precious ring, a ring that I must use'),
('romeo_and_juliet_act5_scene3',32,31,'ROMEO','In dear employment: therefore hence, be gone:'),
('romeo_and_juliet_act5_scene3',33,32,'ROMEO','But if thou, jealous, dost return to pry'),
('romeo_and_juliet_act5_scene3',34,33,'ROMEO','In what I further shall intend to do,'),
('romeo_and_juliet_act5_scene3',35,34,'ROMEO','By heaven, I will tear thee joint by joint'),
('romeo_and_juliet_act5_scene3',36,35,'ROMEO','And strew this hungry churchyard with thy limbs:'),
('romeo_and_juliet_act5_scene3',37,36,'ROMEO','The time and my intents are savage-wild,'),
('romeo_and_juliet_act5_scene3',38,37,'ROMEO','More fierce and more inexorable far'),
('romeo_and_juliet_act5_scene3',39,38,'ROMEO','Than empty tigers or the roaring sea.'),
('romeo_and_juliet_act5_scene3',40,39,'BALTHASAR','I will be gone, sir, and not trouble you.'),
('romeo_and_juliet_act5_scene3',41,40,'ROMEO','So shalt thou show me friendship. Take thou that:'),
('romeo_and_juliet_act5_scene3',42,41,'ROMEO','Live, and be prosperous: and farewell, good fellow.'),
('romeo_and_juliet_act5_scene3',43,42,'BALTHASAR','For all this same, I’ll hide me hereabout:'),
('romeo_and_juliet_act5_scene3',44,43,'BALTHASAR','His looks I fear, and his intents I doubt.'),
('romeo_and_juliet_act5_scene3',45,44,'ROMEO','Thou detestable maw, thou womb of death,'),
('romeo_and_juliet_act5_scene3',46,45,'ROMEO','Gorged with the dearest morsel of the earth,'),
('romeo_and_juliet_act5_scene3',47,46,'ROMEO','Thus I enforce thy rotten jaws to open,'),
('romeo_and_juliet_act5_scene3',48,47,'ROMEO','And, in despite, I’ll cram thee with more food! Opens the tomb.'),
('romeo_and_juliet_act5_scene3',49,48,'PARIS','This is that banish’d haughty Montague,'),
('romeo_and_juliet_act5_scene3',50,49,'PARIS','That murder’d my love’s cousin, with which grief,'),
('romeo_and_juliet_act5_scene3',51,50,'PARIS','It is supposed, the fair creature died;'),
('romeo_and_juliet_act5_scene3',52,51,'PARIS','And here is come to do some villainous shame'),
('romeo_and_juliet_act5_scene3',53,52,'PARIS','To the dead bodies: I will apprehend him. Comes forward.'),
('romeo_and_juliet_act5_scene3',54,53,'PARIS','Stop thy unhallow’d toil, vile Montague!'),
('romeo_and_juliet_act5_scene3',55,54,'PARIS','Can vengeance be pursued further than death?'),
('romeo_and_juliet_act5_scene3',56,55,'PARIS','Condemned villain, I do apprehend thee:'),
('romeo_and_juliet_act5_scene3',57,56,'PARIS','Obey, and go with me; for thou must die.'),
('romeo_and_juliet_act5_scene3',58,57,'ROMEO','I must indeed; and therefore came I hither.'),
('romeo_and_juliet_act5_scene3',59,58,'ROMEO','Good gentle youth, tempt not a desperate man;'),
('romeo_and_juliet_act5_scene3',60,59,'ROMEO','Fly hence, and leave me: think upon these gone;'),
('romeo_and_juliet_act5_scene3',61,60,'ROMEO','Let them affright thee. I beseech thee, youth,'),
('romeo_and_juliet_act5_scene3',62,61,'ROMEO','Put not another sin upon my head,'),
('romeo_and_juliet_act5_scene3',63,62,'ROMEO','By urging me to fury: O, be gone!'),
('romeo_and_juliet_act5_scene3',64,63,'ROMEO','By heaven, I love thee better than myself;'),
('romeo_and_juliet_act5_scene3',65,64,'ROMEO','For I come hither arm’d against myself:'),
('romeo_and_juliet_act5_scene3',66,65,'ROMEO','Stay not, be gone; live, and hereafter say,'),
('romeo_and_juliet_act5_scene3',67,66,'ROMEO','A madman’s mercy bade thee run away.'),
('romeo_and_juliet_act5_scene3',68,67,'PARIS','I do defy thy conjurations,'),
('romeo_and_juliet_act5_scene3',69,68,'PARIS','And apprehend thee for a felon here.'),
('romeo_and_juliet_act5_scene3',70,69,'ROMEO','Wilt thou provoke me? then have at thee, boy! They fight.'),
('romeo_and_juliet_act5_scene3',71,70,'PAGE','O Lord, they fight! I will go call the watch.'),
('romeo_and_juliet_act5_scene3',72,71,'PARIS','O, I am slain! If thou be merciful,'),
('romeo_and_juliet_act5_scene3',73,72,'PARIS','Open the tomb, lay me with Juliet.'),
('romeo_and_juliet_act5_scene3',74,73,'ROMEO','In faith, I will. Let me peruse this face.'),
('romeo_and_juliet_act5_scene3',75,74,'ROMEO','Mercutio’s kinsman, noble County Paris!'),
('romeo_and_juliet_act5_scene3',76,75,'ROMEO','What said my man, when my betossed soul'),
('romeo_and_juliet_act5_scene3',77,76,'ROMEO','Did not attend him as we rode? I think'),
('romeo_and_juliet_act5_scene3',78,77,'ROMEO','He told me Paris should have married Juliet:'),
('romeo_and_juliet_act5_scene3',79,78,'ROMEO','Said he not so? or did I dream it so?'),
('romeo_and_juliet_act5_scene3',80,79,'ROMEO','Or am I mad, hearing him talk of Juliet,'),
('romeo_and_juliet_act5_scene3',81,80,'ROMEO','To think it was so? O, give me thy hand,'),
('romeo_and_juliet_act5_scene3',82,81,'ROMEO','One writ with me in sour misfortune’s book!'),
('romeo_and_juliet_act5_scene3',83,82,'ROMEO','I’ll bury thee in a triumphant grave;'),
('romeo_and_juliet_act5_scene3',84,83,'ROMEO','A grave? O no! a lantern, slaughter’d youth,'),
('romeo_and_juliet_act5_scene3',85,84,'ROMEO','For here lies Juliet, and her beauty makes'),
('romeo_and_juliet_act5_scene3',86,85,'ROMEO','This vault a feasting presence full of light.'),
('romeo_and_juliet_act5_scene3',87,86,'ROMEO','Death, lie thou there, by a dead man interr’d. Laying Paris in the tomb.'),
('romeo_and_juliet_act5_scene3',88,87,'ROMEO','How oft when men are at the point of death'),
('romeo_and_juliet_act5_scene3',89,88,'ROMEO','Have they been merry! which their keepers call'),
('romeo_and_juliet_act5_scene3',90,89,'ROMEO','A lightning before death: O, how may I'),
('romeo_and_juliet_act5_scene3',91,90,'ROMEO','Call this a lightning? O my love! my wife!'),
('romeo_and_juliet_act5_scene3',92,91,'ROMEO','Death, that hath suck’d the honey of thy breath,'),
('romeo_and_juliet_act5_scene3',93,92,'ROMEO','Hath had no power yet upon thy beauty:'),
('romeo_and_juliet_act5_scene3',94,93,'ROMEO','Thou art not conquer’d; beauty’s ensign yet'),
('romeo_and_juliet_act5_scene3',95,94,'ROMEO','Is crimson in thy lips and in thy cheeks,'),
('romeo_and_juliet_act5_scene3',96,95,'ROMEO','And death’s pale flag is not advanced there.'),
('romeo_and_juliet_act5_scene3',97,96,'ROMEO','Tybalt, liest thou there in thy bloody sheet?'),
('romeo_and_juliet_act5_scene3',98,97,'ROMEO','O, what more favour can I do to thee,'),
('romeo_and_juliet_act5_scene3',99,98,'ROMEO','Than with that hand that cut thy youth in twain'),
('romeo_and_juliet_act5_scene3',100,99,'ROMEO','To sunder his that was thine enemy?'),
('romeo_and_juliet_act5_scene3',101,100,'ROMEO','Forgive me, cousin! Ah, dear Juliet,'),
('romeo_and_juliet_act5_scene3',102,101,'ROMEO','Why art thou yet so fair? shall I believe'),
('romeo_and_juliet_act5_scene3',103,102,'ROMEO','That unsubstantial death is amorous,'),
('romeo_and_juliet_act5_scene3',104,103,'ROMEO','And that the lean abhorred monster keeps'),
('romeo_and_juliet_act5_scene3',105,104,'ROMEO','Thee here in dark to be his paramour?'),
('romeo_and_juliet_act5_scene3',106,105,'ROMEO','For fear of that, I still will stay with thee;'),
('romeo_and_juliet_act5_scene3',107,106,'ROMEO','And never from this palace of dim night'),
('romeo_and_juliet_act5_scene3',108,107,'ROMEO','Depart again: here, here will I remain'),
('romeo_and_juliet_act5_scene3',109,108,'ROMEO','With worms that are thy chamber-maids; O, here'),
('romeo_and_juliet_act5_scene3',110,109,'ROMEO','Will I set up my everlasting rest,'),
('romeo_and_juliet_act5_scene3',111,110,'ROMEO','And shake the yoke of inauspicious stars'),
('romeo_and_juliet_act5_scene3',112,111,'ROMEO','From this world-wearied flesh. Eyes, look your last!'),
('romeo_and_juliet_act5_scene3',113,112,'ROMEO','Arms, take your last embrace! and, lips, O you'),
('romeo_and_juliet_act5_scene3',114,113,'ROMEO','The doors of breath, seal with a righteous kiss'),
('romeo_and_juliet_act5_scene3',115,114,'ROMEO','A dateless bargain to engrossing death!'),
('romeo_and_juliet_act5_scene3',116,115,'ROMEO','Come, bitter conduct, come, unsavoury guide!'),
('romeo_and_juliet_act5_scene3',117,116,'ROMEO','Thou desperate pilot, now at once run on'),
('romeo_and_juliet_act5_scene3',118,117,'ROMEO','The dashing rocks thy sea-sick weary bark!'),
('romeo_and_juliet_act5_scene3',119,118,'ROMEO','Here’s to my love! Drinks. O true apothecary!'),
('romeo_and_juliet_act5_scene3',120,119,'ROMEO','Thy drugs are quick. Thus with a kiss I die.'),
('romeo_and_juliet_act5_scene3',121,120,'FRIAR LAURENCE','Saint Francis be my speed! how oft to-night'),
('romeo_and_juliet_act5_scene3',122,121,'FRIAR LAURENCE','Have my old feet stumbled at graves! Who’s there?'),
('romeo_and_juliet_act5_scene3',123,122,'BALTHASAR','Here’s one, a friend, and one that knows you well.'),
('romeo_and_juliet_act5_scene3',124,123,'FRIAR LAURENCE','Bliss be upon you! Tell me, good my friend,'),
('romeo_and_juliet_act5_scene3',125,124,'FRIAR LAURENCE','What torch is yond, that vainly lends his light'),
('romeo_and_juliet_act5_scene3',126,125,'FRIAR LAURENCE','To grubs and eyeless skulls? as I discern,'),
('romeo_and_juliet_act5_scene3',127,126,'FRIAR LAURENCE','It burneth in the Capel’s monument.'),
('romeo_and_juliet_act5_scene3',128,127,'BALTHASAR','It doth so, holy sir; and there’s my master,'),
('romeo_and_juliet_act5_scene3',129,128,'BALTHASAR','One that you love.'),
('romeo_and_juliet_act5_scene3',129,129,'FRIAR LAURENCE','Who is it?'),
('romeo_and_juliet_act5_scene3',130,130,'BALTHASAR','Romeo.'),
('romeo_and_juliet_act5_scene3',130,131,'FRIAR LAURENCE','How long hath he been there?'),
('romeo_and_juliet_act5_scene3',131,132,'BALTHASAR','Full half an hour.'),
('romeo_and_juliet_act5_scene3',131,133,'FRIAR LAURENCE','Go with me to the vault.'),
('romeo_and_juliet_act5_scene3',132,134,'BALTHASAR','I dare not, sir:'),
('romeo_and_juliet_act5_scene3',133,135,'BALTHASAR','My master knows not but I am gone hence;'),
('romeo_and_juliet_act5_scene3',134,136,'BALTHASAR','And fearfully did menace me with death,'),
('romeo_and_juliet_act5_scene3',135,137,'BALTHASAR','If I did stay to look on his intents.'),
('romeo_and_juliet_act5_scene3',136,138,'FRIAR LAURENCE','Stay, then; I’ll go alone. Fear comes upon me:'),
('romeo_and_juliet_act5_scene3',137,139,'FRIAR LAURENCE','O, much I fear some ill unlucky thing.'),
('romeo_and_juliet_act5_scene3',138,140,'BALTHASAR','As I did sleep under this yew-tree here,'),
('romeo_and_juliet_act5_scene3',139,141,'BALTHASAR','I dreamt my master and another fought,'),
('romeo_and_juliet_act5_scene3',140,142,'BALTHASAR','And that my master slew him.'),
('romeo_and_juliet_act5_scene3',140,143,'FRIAR LAURENCE','Romeo!'),
('romeo_and_juliet_act5_scene3',141,144,'FRIAR LAURENCE','Alack, alack, what blood is this, which stains'),
('romeo_and_juliet_act5_scene3',142,145,'FRIAR LAURENCE','The stony entrance of this sepulchre?'),
('romeo_and_juliet_act5_scene3',143,146,'FRIAR LAURENCE','What mean these masterless and gory swords'),
('romeo_and_juliet_act5_scene3',144,147,'FRIAR LAURENCE','To lie discolour’d by this place of peace? Enters the tomb.'),
('romeo_and_juliet_act5_scene3',145,148,'FRIAR LAURENCE','Romeo! O, pale! Who else? what, Paris too?'),
('romeo_and_juliet_act5_scene3',146,149,'FRIAR LAURENCE','And steep’d in blood? Ah, what an unkind hour'),
('romeo_and_juliet_act5_scene3',147,150,'FRIAR LAURENCE','Is guilty of this lamentable chance!'),
('romeo_and_juliet_act5_scene3',148,151,'FRIAR LAURENCE','The lady stirs. Juliet wakes.'),
('romeo_and_juliet_act5_scene3',149,152,'JULIET','O comfortable friar! where is my lord?'),
('romeo_and_juliet_act5_scene3',150,153,'JULIET','I do remember well where I should be,'),
('romeo_and_juliet_act5_scene3',151,154,'JULIET','And there I am. Where is my Romeo? Noise within.'),
('romeo_and_juliet_act5_scene3',152,155,'FRIAR LAURENCE','I hear some noise. Lady, come from that nest'),
('romeo_and_juliet_act5_scene3',153,156,'FRIAR LAURENCE','Of death, contagion, and unnatural sleep:'),
('romeo_and_juliet_act5_scene3',154,157,'FRIAR LAURENCE','A greater power than we can contradict'),
('romeo_and_juliet_act5_scene3',155,158,'FRIAR LAURENCE','Hath thwarted our intents. Come, come away.'),
('romeo_and_juliet_act5_scene3',156,159,'FRIAR LAURENCE','Thy husband in thy bosom there lies dead;'),
('romeo_and_juliet_act5_scene3',157,160,'FRIAR LAURENCE','And Paris too. Come, I’ll dispose of thee'),
('romeo_and_juliet_act5_scene3',158,161,'FRIAR LAURENCE','Among a sisterhood of holy nuns:'),
('romeo_and_juliet_act5_scene3',159,162,'FRIAR LAURENCE','Stay not to question, for the watch is coming;'),
('romeo_and_juliet_act5_scene3',160,163,'FRIAR LAURENCE','Come, go, good Juliet noise again, I dare no longer stay.'),
('romeo_and_juliet_act5_scene3',161,164,'JULIET','Go, get thee hence, for I will not away.'),
('romeo_and_juliet_act5_scene3',162,165,'JULIET','What’s here? a cup, closed in my true love’s hand?'),
('romeo_and_juliet_act5_scene3',163,166,'JULIET','Poison, I see, hath been his timeless end:'),
('romeo_and_juliet_act5_scene3',164,167,'JULIET','O churl! drunk all, and left no friendly drop'),
('romeo_and_juliet_act5_scene3',165,168,'JULIET','To help me after? I will kiss thy lips;'),
('romeo_and_juliet_act5_scene3',166,169,'JULIET','Haply some poison yet doth hang on them,'),
('romeo_and_juliet_act5_scene3',167,170,'JULIET','To make die with a restorative.'),
('romeo_and_juliet_act5_scene3',168,171,'JULIET','Thy lips are warm.'),
('romeo_and_juliet_act5_scene3',168,172,'FIRST WATCHMAN','Lead, boy: which way?'),
('romeo_and_juliet_act5_scene3',169,173,'JULIET','Yea, noise? then I’ll be brief. O happy dagger! Snatching Romeo’s dagger.'),
('romeo_and_juliet_act5_scene3',170,174,'JULIET','This is thy sheath ; there rust, and let me die.'),
('romeo_and_juliet_act5_scene3',171,175,'PAGE','This is the place; there, where the torch doth burn.'),
('romeo_and_juliet_act5_scene3',172,176,'FIRST WATCHMAN','The ground is bloody; search about the churchyard:'),
('romeo_and_juliet_act5_scene3',173,177,'FIRST WATCHMAN','Go, some of you, whoe’er you find attach.'),
('romeo_and_juliet_act5_scene3',174,178,'FIRST WATCHMAN','Pitiful sight! here lies the county slain;'),
('romeo_and_juliet_act5_scene3',175,179,'FIRST WATCHMAN','And Juliet bleeding, warm, and newly dead,'),
('romeo_and_juliet_act5_scene3',176,180,'FIRST WATCHMAN','Who here hath lain these two days buried.'),
('romeo_and_juliet_act5_scene3',177,181,'FIRST WATCHMAN','Go, tell the prince: run to the Capulets:'),
('romeo_and_juliet_act5_scene3',178,182,'FIRST WATCHMAN','Raise up the Montagues: some others search:'),
('romeo_and_juliet_act5_scene3',179,183,'FIRST WATCHMAN','We see the ground whereon these woes do lie;'),
('romeo_and_juliet_act5_scene3',180,184,'FIRST WATCHMAN','But the true ground of all these piteous woes'),
('romeo_and_juliet_act5_scene3',181,185,'FIRST WATCHMAN','We cannot without circumstance descry.'),
('romeo_and_juliet_act5_scene3',182,186,'SECOND WATCHMAN','Here’s Romeo’s man; we found him in the churchyard.'),
('romeo_and_juliet_act5_scene3',183,187,'FIRST WATCHMAN','Hold him in safety, till the prince come hither.'),
('romeo_and_juliet_act5_scene3',184,188,'THIRD WATCHMAN','Here is a friar, that trembles, sighs, and weeps:'),
('romeo_and_juliet_act5_scene3',185,189,'THIRD WATCHMAN','We took this mattock and this spade from him,'),
('romeo_and_juliet_act5_scene3',186,190,'THIRD WATCHMAN','As he was coming from this churchyard side.'),
('romeo_and_juliet_act5_scene3',187,191,'FIRST WATCHMAN','A great suspicion: stay the friar too.'),
('romeo_and_juliet_act5_scene3',188,192,'PRINCE','What misadventure is so early up,'),
('romeo_and_juliet_act5_scene3',189,193,'PRINCE','That calls our person from our morning’s rest?'),
('romeo_and_juliet_act5_scene3',190,194,'CAPULET','What should it be, that they so shriek abroad?'),
('romeo_and_juliet_act5_scene3',191,195,'LADY CAPULET','The people in the street cry Romeo,'),
('romeo_and_juliet_act5_scene3',192,196,'LADY CAPULET','Some Juliet, and some Paris; and all run,'),
('romeo_and_juliet_act5_scene3',193,197,'LADY CAPULET','With open outcry, toward our monument.'),
('romeo_and_juliet_act5_scene3',194,198,'PRINCE','What fear is this which startles in our ears?'),
('romeo_and_juliet_act5_scene3',195,199,'FIRST WATCHMAN','Sovereign, here lies the County Paris slain;'),
('romeo_and_juliet_act5_scene3',196,200,'FIRST WATCHMAN','And Romeo dead; and Juliet, dead before,'),
('romeo_and_juliet_act5_scene3',197,201,'FIRST WATCHMAN','Warm and new kill’d.'),
('romeo_and_juliet_act5_scene3',198,202,'PRINCE','Search, seek, and know how this foul murder comes.'),
('romeo_and_juliet_act5_scene3',199,203,'FIRST WATCHMAN','Here is a friar, and slaughter’d Romeo’s man;'),
('romeo_and_juliet_act5_scene3',200,204,'FIRST WATCHMAN','With instruments upon them, fit to open'),
('romeo_and_juliet_act5_scene3',201,205,'FIRST WATCHMAN','These dead men’s tombs.'),
('romeo_and_juliet_act5_scene3',202,206,'CAPULET','O heavens! O wife, look how our daughter bleeds!'),
('romeo_and_juliet_act5_scene3',203,207,'CAPULET','This dagger hath mista’en—for, lo, his house'),
('romeo_and_juliet_act5_scene3',204,208,'CAPULET','Is empty on the back of Montague—'),
('romeo_and_juliet_act5_scene3',205,209,'CAPULET','And it mis-sheathed in my daughter’s bosom!'),
('romeo_and_juliet_act5_scene3',206,210,'LADY CAPULET','O me! this sight of death is as a bell,'),
('romeo_and_juliet_act5_scene3',207,211,'LADY CAPULET','That warns my old age to a sepulchre.'),
('romeo_and_juliet_act5_scene3',208,212,'PRINCE','Come, Montague; for thou art early up,'),
('romeo_and_juliet_act5_scene3',209,213,'PRINCE','To see thy son and heir more early down.'),
('romeo_and_juliet_act5_scene3',210,214,'MONTAGUE','Alas, my liege, my wife is dead to-night;'),
('romeo_and_juliet_act5_scene3',211,215,'MONTAGUE','Grief of my son’s exile hath stopp’d her breath:'),
('romeo_and_juliet_act5_scene3',212,216,'MONTAGUE','What further woe conspires against mine age?'),
('romeo_and_juliet_act5_scene3',213,217,'PRINCE','Look, and thou shalt see.'),
('romeo_and_juliet_act5_scene3',214,218,'MONTAGUE','O thou untaught! what manners is in this,'),
('romeo_and_juliet_act5_scene3',215,219,'MONTAGUE','To press before thy father to a grave?'),
('romeo_and_juliet_act5_scene3',216,220,'PRINCE','Seal up the mouth of outrage for a while,'),
('romeo_and_juliet_act5_scene3',217,221,'PRINCE','Till we can clear these ambiguities,'),
('romeo_and_juliet_act5_scene3',218,222,'PRINCE','And know their spring, their head, their true descent;'),
('romeo_and_juliet_act5_scene3',219,223,'PRINCE','And then will I be general of your woes,'),
('romeo_and_juliet_act5_scene3',220,224,'PRINCE','And lead you even to death: meantime forbear,'),
('romeo_and_juliet_act5_scene3',221,225,'PRINCE','And let mischance be slave to patience.'),
('romeo_and_juliet_act5_scene3',222,226,'PRINCE','Bring forth the parties of suspicion.'),
('romeo_and_juliet_act5_scene3',223,227,'FRIAR LAURENCE','I am the greatest, able to do least,'),
('romeo_and_juliet_act5_scene3',224,228,'FRIAR LAURENCE','Yet most suspected, as the time and place'),
('romeo_and_juliet_act5_scene3',225,229,'FRIAR LAURENCE','Doth make against me, of this direful murder;'),
('romeo_and_juliet_act5_scene3',226,230,'FRIAR LAURENCE','And here I stand, both to impeach and purge'),
('romeo_and_juliet_act5_scene3',227,231,'FRIAR LAURENCE','Myself condemned and myself excused.'),
('romeo_and_juliet_act5_scene3',228,232,'PRINCE','Then say at once what thou dost know in this.'),
('romeo_and_juliet_act5_scene3',229,233,'FRIAR LAURENCE','I will be brief, for my short date of breath'),
('romeo_and_juliet_act5_scene3',230,234,'FRIAR LAURENCE','Is not so long as is a tedious tale.'),
('romeo_and_juliet_act5_scene3',231,235,'FRIAR LAURENCE','Romeo, there dead, was husband to that Juliet;'),
('romeo_and_juliet_act5_scene3',232,236,'FRIAR LAURENCE','And she, there dead, that Romeo’s faithful wife:'),
('romeo_and_juliet_act5_scene3',233,237,'FRIAR LAURENCE','I married them; and their stol’n marriage-day'),
('romeo_and_juliet_act5_scene3',234,238,'FRIAR LAURENCE','Was Tybalt’s dooms-day, whose untimely death'),
('romeo_and_juliet_act5_scene3',235,239,'FRIAR LAURENCE','Banish’d the new-made bridegroom from this city,'),
('romeo_and_juliet_act5_scene3',236,240,'FRIAR LAURENCE','For whom, and not for Tybalt, Juliet pined.'),
('romeo_and_juliet_act5_scene3',237,241,'FRIAR LAURENCE','You, to remove that siege of grief from her,'),
('romeo_and_juliet_act5_scene3',238,242,'FRIAR LAURENCE','Betroth’d and would have married her perforce'),
('romeo_and_juliet_act5_scene3',239,243,'FRIAR LAURENCE','To County Paris: then comes she to me,'),
('romeo_and_juliet_act5_scene3',240,244,'FRIAR LAURENCE','And, with wild looks, bid me devise some mean'),
('romeo_and_juliet_act5_scene3',241,245,'FRIAR LAURENCE','To rid her from this second marriage,'),
('romeo_and_juliet_act5_scene3',242,246,'FRIAR LAURENCE','Or in my cell there would she kill herself.'),
('romeo_and_juliet_act5_scene3',243,247,'FRIAR LAURENCE','Then gave I her, so tutor’d by my art,'),
('romeo_and_juliet_act5_scene3',244,248,'FRIAR LAURENCE','A sleeping potion; which so took effect'),
('romeo_and_juliet_act5_scene3',245,249,'FRIAR LAURENCE','As I intended, for it wrought on her'),
('romeo_and_juliet_act5_scene3',246,250,'FRIAR LAURENCE','The form of death: meantime I writ to Romeo,'),
('romeo_and_juliet_act5_scene3',247,251,'FRIAR LAURENCE','That he should hither come as this dire night,'),
('romeo_and_juliet_act5_scene3',248,252,'FRIAR LAURENCE','To help to take her from her borrow’d grave,'),
('romeo_and_juliet_act5_scene3',249,253,'FRIAR LAURENCE','Being the time the potion’s force should cease.'),
('romeo_and_juliet_act5_scene3',250,254,'FRIAR LAURENCE','But he which bore my letter, Friar John,'),
('romeo_and_juliet_act5_scene3',251,255,'FRIAR LAURENCE','Was stay’d by accident, and yesternight'),
('romeo_and_juliet_act5_scene3',252,256,'FRIAR LAURENCE','Return’d my letter back. Then all alone'),
('romeo_and_juliet_act5_scene3',253,257,'FRIAR LAURENCE','At the prefixed hour of her waking,'),
('romeo_and_juliet_act5_scene3',254,258,'FRIAR LAURENCE','Came I to take her from her kindred’s vault;'),
('romeo_and_juliet_act5_scene3',255,259,'FRIAR LAURENCE','Meaning to keep her closely at my cell,'),
('romeo_and_juliet_act5_scene3',256,260,'FRIAR LAURENCE','Till I conveniently could send to Romeo:'),
('romeo_and_juliet_act5_scene3',257,261,'FRIAR LAURENCE','But when I came, some minute ere the time'),
('romeo_and_juliet_act5_scene3',258,262,'FRIAR LAURENCE','Of her awaking, here untimely lay'),
('romeo_and_juliet_act5_scene3',259,263,'FRIAR LAURENCE','The noble Paris and true Romeo dead.'),
('romeo_and_juliet_act5_scene3',260,264,'FRIAR LAURENCE','She wakes; and I entreated her come forth,'),
('romeo_and_juliet_act5_scene3',261,265,'FRIAR LAURENCE','And bear this work of heaven with patience:'),
('romeo_and_juliet_act5_scene3',262,266,'FRIAR LAURENCE','But then a noise did scare me from the tomb;'),
('romeo_and_juliet_act5_scene3',263,267,'FRIAR LAURENCE','And she, too desperate, would not go with me,'),
('romeo_and_juliet_act5_scene3',264,268,'FRIAR LAURENCE','But, as it seems, did violence on herself.'),
('romeo_and_juliet_act5_scene3',265,269,'FRIAR LAURENCE','All this I know; and to the marriage'),
('romeo_and_juliet_act5_scene3',266,270,'FRIAR LAURENCE','Her nurse is privy: and, if aught in this'),
('romeo_and_juliet_act5_scene3',267,271,'FRIAR LAURENCE','Miscarried by my fault, let my old life'),
('romeo_and_juliet_act5_scene3',268,272,'FRIAR LAURENCE','Be sacrificed, some hour before his time,'),
('romeo_and_juliet_act5_scene3',269,273,'FRIAR LAURENCE','Unto the rigour of severest law.'),
('romeo_and_juliet_act5_scene3',270,274,'PRINCE','We still have known thee for a holy man.'),
('romeo_and_juliet_act5_scene3',271,275,'PRINCE','Where’s Romeo’s man? what can he say in this?'),
('romeo_and_juliet_act5_scene3',272,276,'BALTHASAR','I brought my master news of Juliet’s death;'),
('romeo_and_juliet_act5_scene3',273,277,'BALTHASAR','And then in post he came from Mantua'),
('romeo_and_juliet_act5_scene3',274,278,'BALTHASAR','To this same place, to this same monument.'),
('romeo_and_juliet_act5_scene3',275,279,'BALTHASAR','This letter he early bid me give his father,'),
('romeo_and_juliet_act5_scene3',276,280,'BALTHASAR','And threaten’d me with death, going in the vault,'),
('romeo_and_juliet_act5_scene3',277,281,'BALTHASAR','If I departed not and left him there.'),
('romeo_and_juliet_act5_scene3',278,282,'PRINCE','Give me the letter; I will look on it.'),
('romeo_and_juliet_act5_scene3',279,283,'PRINCE','Where is the county’s page, that raised the watch?'),
('romeo_and_juliet_act5_scene3',280,284,'PRINCE','Sirrah, what made your master in this place?'),
('romeo_and_juliet_act5_scene3',281,285,'PAGE','He came with flowers to strew his lady’s grave;'),
('romeo_and_juliet_act5_scene3',282,286,'PAGE','And bid me stand aloof, and so I did:'),
('romeo_and_juliet_act5_scene3',283,287,'PAGE','Anon comes one with light to ope the tomb;'),
('romeo_and_juliet_act5_scene3',284,288,'PAGE','And by and by my master drew on him;'),
('romeo_and_juliet_act5_scene3',285,289,'PAGE','And then I ran away to call the watch.'),
('romeo_and_juliet_act5_scene3',286,290,'PRINCE','This letter doth make good the friar’s words,'),
('romeo_and_juliet_act5_scene3',287,291,'PRINCE','Their course of love, the tidings of her death:'),
('romeo_and_juliet_act5_scene3',288,292,'PRINCE','And here he writes that he did buy a poison'),
('romeo_and_juliet_act5_scene3',289,293,'PRINCE','Of a poor ’pothecary, and therewithal'),
('romeo_and_juliet_act5_scene3',290,294,'PRINCE','Came to this vault to die, and lie with Juliet.'),
('romeo_and_juliet_act5_scene3',291,295,'PRINCE','Where be these enemies? Capulet! Montague!'),
('romeo_and_juliet_act5_scene3',292,296,'PRINCE','See, what a scourge is laid upon your hate,'),
('romeo_and_juliet_act5_scene3',293,297,'PRINCE','That heaven finds means to kill your joys with love.'),
('romeo_and_juliet_act5_scene3',294,298,'PRINCE','And I for winking at your discords too'),
('romeo_and_juliet_act5_scene3',295,299,'PRINCE','Have lost a brace of kinsmen: all are punish’d.'),
('romeo_and_juliet_act5_scene3',296,300,'CAPULET','O brother Montague, give me thy hand:'),
('romeo_and_juliet_act5_scene3',297,301,'CAPULET','This is my daughter’s jointure, for no more'),
('romeo_and_juliet_act5_scene3',298,302,'CAPULET','Can I demand.'),
('romeo_and_juliet_act5_scene3',298,303,'MONTAGUE','But I can give thee more:'),
('romeo_and_juliet_act5_scene3',299,304,'MONTAGUE','For I will raise her statue in pure gold;'),
('romeo_and_juliet_act5_scene3',300,305,'MONTAGUE','That while Verona by that name is known,'),
('romeo_and_juliet_act5_scene3',301,306,'MONTAGUE','There shall no figure at such rate be set'),
('romeo_and_juliet_act5_scene3',302,307,'MONTAGUE','As that of true and faithful Juliet.'),
('romeo_and_juliet_act5_scene3',303,308,'CAPULET','As rich shall Romeo’s by his lady’s lie;'),
('romeo_and_juliet_act5_scene3',304,309,'CAPULET','Poor sacrifices of our enmity!'),
('romeo_and_juliet_act5_scene3',305,310,'PRINCE','A glooming peace this morning with it brings;'),
('romeo_and_juliet_act5_scene3',306,311,'PRINCE','The sun, for sorrow, will not show his head:'),
('romeo_and_juliet_act5_scene3',307,312,'PRINCE','Go hence, to have more talk of these sad things;'),
('romeo_and_juliet_act5_scene3',308,313,'PRINCE','Some shall be pardon’d, and some punished:'),
('romeo_and_juliet_act5_scene3',309,314,'PRINCE','For never was a story of more woe'),
('romeo_and_juliet_act5_scene3',310,315,'PRINCE','Than this of Juliet and her Romeo.'),
('romeo_and_juliet_prologue',1,0,'CHORUS','Two households, both alike in dignity,'),
('romeo_and_juliet_prologue',2,1,'CHORUS','In fair Verona, where we lay our scene,'),
('romeo_and_juliet_prologue',3,2,'CHORUS','From ancient grudge break to new mutiny,'),
('romeo_and_juliet_prologue',4,3,'CHORUS','Where civil blood makes civil hands unclean.'),
('romeo_and_juliet_prologue',5,4,'CHORUS','From forth the fatal loins of these two foes'),
('romeo_and_juliet_prologue',6,5,'CHORUS','A pair of star-cross’d lovers take their life;'),
('romeo_and_juliet_prologue',7,6,'CHORUS','Whose misadventured piteous overthrows'),
('romeo_and_juliet_prologue',8,7,'CHORUS','Do with their death bury their parents’ strife.'),
('romeo_and_juliet_prologue',9,8,'CHORUS','The fearful passage of their death-mark’d love,'),
('romeo_and_juliet_prologue',10,9,'CHORUS','And the continuance of their parents’ rage,'),
('romeo_and_juliet_prologue',11,10,'CHORUS','Which, but their children’s end, nought could remove,'),
('romeo_and_juliet_prologue',12,11,'CHORUS','Is now the two hours’ traffic of our stage;'),
('romeo_and_juliet_prologue',13,12,'CHORUS','The which if you with patient ears attend,'),
('romeo_and_juliet_prologue',14,13,'CHORUS','What here shall miss, our toil shall strive to mend.');
